﻿'use client'
import Link from 'next/link'
import { useState, useRef, useEffect, useMemo } from 'react'
import { usePostHog } from 'posthog-js/react'
import { getRelevantResources, getDefaultResources, type Resource } from '@/lib/resources'
import {
  PREP_PROVENANCE_VERSION,
  buildPrepClaimProvenance,
  type ClaimOriginClass,
} from '@/lib/prep-provenance'
import { scorePrepBriefConfidence } from '@/lib/prep-confidence'
import { PMF_EVENTS } from '@/lib/pmf-event-taxonomy'
import { type PrepRoleMode } from '@/lib/prep-role-modes'
import { BriefRating } from '@/components/BriefRating'
import type { InterviewStage } from '@/lib/prompts'
import {
  DEFAULT_INTERVIEW_STAGE,
  inferInitialRoleMode,
  ROLE_MODE_OPTIONS,
  STAGE_OPTIONS,
} from './prep-config'

function BoldText({ text }: { text: string }) {
  const parts = text.split(/\*\*(.+?)\*\*/g)
  return (
    <>
      {parts.map((part, i) => i % 2 === 1 ? <strong key={i}>{part}</strong> : part)}
    </>
  )
}

function normalizeClaimText(line: string) {
  return line
    .replace(/^[-*]\s+/, '')
    .replace(/^\d+[.)]\s+/, '')
    .replace(/\s+/g, ' ')
    .trim()
}

type TraceFilter = ClaimOriginClass | 'all'

type ClaimOriginCounts = Record<ClaimOriginClass, number>

function originClassLabel(originClass: ClaimOriginClass) {
  if (originClass === 'user_provided') return 'User Provided'
  if (originClass === 'system_detected') return 'System Detected'
  return 'Inferred'
}

function originClassClassName(originClass: ClaimOriginClass) {
  if (originClass === 'user_provided') return 'bg-emerald-50 text-emerald-700 border-emerald-200'
  if (originClass === 'system_detected') return 'bg-blue-50 text-blue-700 border-blue-200'
  return 'bg-amber-50 text-amber-700 border-amber-200'
}

function buildClaimOriginLookup(text: string): Record<string, ClaimOriginClass> {
  const lookup: Record<string, ClaimOriginClass> = {}
  const claims = buildPrepClaimProvenance(text)
  for (const claim of claims) {
    lookup[claim.claimText] = claim.originClass
  }
  return lookup
}

function buildClaimOriginCounts(text: string): ClaimOriginCounts {
  const counts: ClaimOriginCounts = {
    user_provided: 0,
    system_detected: 0,
    inferred: 0,
  }
  const claims = buildPrepClaimProvenance(text)
  for (const claim of claims) {
    counts[claim.originClass] += 1
  }
  return counts
}

function TraceLabel({
  originClass,
  onClick,
}: {
  originClass: ClaimOriginClass
  onClick?: () => void
}) {
  const className = `inline-flex items-center rounded border px-2 py-[1px] text-[10px] font-semibold tracking-[0.04em] uppercase ${originClassClassName(originClass)} ${onClick ? 'cursor-pointer hover:brightness-95 transition' : ''}`
  if (onClick) {
    return (
      <button
        type="button"
        onClick={onClick}
        className={className}
        title={`Trace source: ${originClassLabel(originClass)}. Click to filter.`}
        aria-label={`Trace source ${originClassLabel(originClass)}`}
      >
        {originClassLabel(originClass)}
      </button>
    )
  }
  return (
    <span
      className={className}
      title={`Trace source: ${originClassLabel(originClass)}`}
      aria-label={`Trace source ${originClassLabel(originClass)}`}
    >
      {originClassLabel(originClass)}
    </span>
  )
}

function SourceLegend({
  traceFilter,
  counts,
  onChangeFilter,
}: {
  traceFilter: TraceFilter
  counts: ClaimOriginCounts
  onChangeFilter: (next: TraceFilter) => void
}) {
  const totalClaims = counts.user_provided + counts.system_detected + counts.inferred
  const buttons: Array<{ key: TraceFilter; label: string; count: number }> = [
    { key: 'all', label: 'All Claims', count: totalClaims },
    { key: 'user_provided', label: 'User Provided', count: counts.user_provided },
    { key: 'system_detected', label: 'System Detected', count: counts.system_detected },
    { key: 'inferred', label: 'Inferred', count: counts.inferred },
  ]
  return (
    <div className="mb-5 rounded border border-slate-200 bg-slate-50 p-3">
      <p className="text-[10px] font-bold tracking-[0.12em] uppercase text-slate-500 mb-2">Source Legend</p>
      <div className="flex flex-wrap gap-2 mb-2">
        {buttons.map((button) => (
          <button
            key={button.key}
            type="button"
            onClick={() => onChangeFilter(button.key)}
            className={`inline-flex items-center gap-1 rounded border px-2 py-1 text-[10px] font-semibold tracking-[0.04em] uppercase transition-colors ${
              traceFilter === button.key
                ? 'bg-slate-900 text-white border-slate-900'
                : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
            }`}
          >
            <span>{button.label}</span>
            <span className={`rounded px-1.5 py-[1px] ${traceFilter === button.key ? 'bg-slate-700 text-slate-100' : 'bg-slate-100 text-slate-500'}`}>
              {button.count}
            </span>
          </button>
        ))}
      </div>
      <div className="flex flex-wrap gap-2">
        <TraceLabel originClass="user_provided" />
        <TraceLabel originClass="system_detected" />
        <TraceLabel originClass="inferred" />
      </div>
    </div>
  )
}

function renderBrief(
  text: string,
  traceFilter: TraceFilter,
  onTraceLabelClick: (originClass: ClaimOriginClass) => void,
) {
  const claimOriginLookup = buildClaimOriginLookup(text)
  return text.split('\n').map((line, i) => {
    if (line.startsWith('# ')) return null
    if (line.trim() === '---' || line.trim() === '***') return null
    if (line.startsWith('## ')) {
      return (
        <h2 key={i} className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-400 mt-10 mb-4 first:mt-0 pb-2 border-b border-slate-100">
          {line.slice(3)}
        </h2>
      )
    }
    if (line.startsWith('- ') || line.startsWith('* ')) {
      const claimText = normalizeClaimText(line)
      const originClass = claimOriginLookup[claimText] ?? 'inferred'
      if (traceFilter !== 'all' && originClass !== traceFilter) return null
      return (
        <div key={i} className="mb-3">
          <div className="mb-1.5">
            <TraceLabel originClass={originClass} onClick={() => onTraceLabelClick(originClass)} />
          </div>
          <div className="flex gap-2.5 text-[14px] text-slate-700 leading-relaxed">
          <span className="text-slate-300 shrink-0 select-none mt-0.5">-</span>
          <BoldText text={line.slice(2)} />
          </div>
        </div>
      )
    }
    if (line.trim() === '') return <div key={i} className="h-1.5" />
    const claimText = normalizeClaimText(line)
    const originClass = claimOriginLookup[claimText] ?? 'inferred'
    if (traceFilter !== 'all' && originClass !== traceFilter) return null
    return (
      <div key={i} className="mb-3">
        <div className="mb-1.5">
          <TraceLabel originClass={originClass} onClick={() => onTraceLabelClick(originClass)} />
        </div>
        <p className="text-[14px] text-slate-700 leading-relaxed mb-0">
          <BoldText text={line} />
        </p>
      </div>
    )
  })
}

function ResourcePanel({ brief }: { brief: string }) {
  const resources: Resource[] = brief.length > 0
    ? getRelevantResources(brief, 3)
    : getDefaultResources(2)

  if (resources.length === 0) return null

  return (
    <div className="bg-white border border-slate-200 rounded p-6 mb-4">
      <p className="text-[11px] font-bold tracking-[0.08em] uppercase text-slate-400 mb-4">
        Further Reading
      </p>
      <div className="flex flex-col gap-3">
        {resources.map(r => (
          <a
            key={r.url + r.title}
            href={r.url}
            target="_blank"
            rel="noopener noreferrer"
            className="group flex items-start gap-3 no-underline"
          >
            <div className="min-w-0">
              <div className="text-[13px] font-semibold text-slate-900 group-hover:text-slate-600 transition-colors">
                {r.title}
                <span className="ml-1.5 text-[11px] font-normal text-slate-400">{r.source} ↗</span>
              </div>
              <div className="text-[12px] text-slate-500 mt-0.5 leading-relaxed">{r.description}</div>
            </div>
          </a>
        ))}
      </div>
    </div>
  )
}

async function streamResponse(res: Response, onChunk: (text: string) => void) {
  if (!res.body) throw new Error('No body')
  const reader = res.body.getReader()
  const decoder = new TextDecoder()
  while (true) {
    const { done, value } = await reader.read()
    if (done) break
    onChunk(decoder.decode(value, { stream: true }))
  }
}

async function saveBrief(type: string, text: string, companyId?: string, sectionName?: string): Promise<string | null> {
  try {
    const isPrepType = type === 'prep' || type === 'prep_section'
    const claimProvenance = isPrepType ? buildPrepClaimProvenance(text) : undefined
    const res = await fetch('/api/briefs/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        type,
        text,
        company_id: companyId,
        section_name: sectionName,
        provenance_version: isPrepType ? PREP_PROVENANCE_VERSION : undefined,
        claim_provenance: claimProvenance,
      }),
    })
    if (!res.ok) return null
    const data = await res.json()
    return data.id ?? null
  } catch {
    return null
  }
}

function useOnDemand(url: string, companyId: string, sectionName: string) {
  const [content, setContent] = useState('')
  const [briefId, setBriefId] = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  async function generate() {
    setLoading(true)
    setContent('')
    setBriefId(null)
    setError('')
    try {
      const res = await fetch(url)
      if (!res.ok) {
        const body = await res.json().catch(() => ({}))
        setError(body?.error ?? `Request failed (${res.status})`)
        return
      }
      let fullText = ''
      await streamResponse(res, chunk => { fullText += chunk; setContent(fullText) })
      if (fullText.startsWith('__ERROR__')) {
        setError(fullText.slice(9))
        setContent('')
      } else {
        const id = await saveBrief('prep_section', fullText, companyId, sectionName)
        setBriefId(id)
      }
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Unknown error')
    } finally {
      setLoading(false)
    }
  }

  return { content, briefId, loading, error, generate }
}

function OnDemandPanel({
  title,
  description,
  content,
  briefId,
  loading,
  error,
  onGenerate,
  traceFilter,
  onTraceLabelClick,
  onLegendFilter,
}: {
  title: string
  description: string
  content: string
  briefId: string | null
  loading: boolean
  error: string
  onGenerate: () => void
  traceFilter: TraceFilter
  onTraceLabelClick: (originClass: ClaimOriginClass) => void
  onLegendFilter: (next: TraceFilter) => void
}) {
  const claimOriginCounts = useMemo(() => buildClaimOriginCounts(content), [content])
  return (
    <div className="bg-white border border-slate-200 rounded mb-4">
      <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100">
        <div>
          <p className="text-[11px] font-bold tracking-[0.08em] uppercase text-slate-400">{title}</p>
          {!content && !loading && (
            <p className="text-[12px] text-slate-400 mt-0.5">{description}</p>
          )}
        </div>
        <button
          type="button"
          onClick={onGenerate}
          disabled={loading}
          className="shrink-0 text-[12px] font-semibold text-slate-500 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 hover:text-slate-700 bg-transparent cursor-pointer disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
        >
          {loading ? 'Generating…' : content ? 'Regenerate' : 'Generate'}
        </button>
      </div>
      {loading && !content && (
        <div className="px-6 py-5">
          <div className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block" />
            <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block [animation-delay:150ms]" />
            <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block [animation-delay:300ms]" />
          </div>
        </div>
      )}
      {error && !content && (
        <div className="px-6 py-4 text-[13px] text-red-600">{error}</div>
      )}
      {(content || (loading && content)) && (
        <div className="px-6 py-5">
          <SourceLegend
            traceFilter={traceFilter}
            counts={claimOriginCounts}
            onChangeFilter={onLegendFilter}
          />
          {renderBrief(content, traceFilter, onTraceLabelClick)}
          {loading && (
            <span className="inline-block w-0.5 h-4 bg-slate-400 animate-pulse ml-0.5 align-middle" />
          )}
          {!loading && (
            <p className="mt-5 pt-3 border-t border-slate-100 text-[11px] text-slate-400">
              AI-generated — use as input, not advice. Verify facts before any conversation.
            </p>
          )}
        </div>
      )}
      {briefId && !loading && content && (
        <div className="px-6 pb-4 flex justify-end">
          <BriefRating briefId={briefId} />
        </div>
      )}
    </div>
  )
}

const NO_NOTES_MESSAGES: Record<string, string> = {
  coo:       'COO briefs require operational context. Add notes on the specific challenge this company is navigating - what phase, what broke, what the CEO cannot do alone.',
  ciso:      'CISO briefs improve significantly with sector and regulatory context. Add notes on recent events in their space, board security posture, or why the role opened.',
  cpo:       'CPO briefs improve with product context. Add notes on the current product situation - engagement vs acquisition problem, what created this opening.',
  cdo_data:  'CDO briefs need data mandate context. Add notes on the company data maturity and whether this is a governance or analytics mandate.',
  cdo_digital: 'Chief Digital Officer briefs improve with transformation context. Add notes on the digital agenda and internal dynamics.',
  cto:       'CTO briefs improve with engineering context. Add notes on tech debt posture, team maturity, and what triggered this search.',
  cio:       'CIO briefs improve with transformation context. Add notes on the agenda, the current CIO situation, and board technology appetite.',
}

export function PrepClient({
  companyId,
  companyName,
  companyStage,
  stageLabel,
  hasContacts,
  hasNotes,
  hasInterviewNotes,
  roleType,
  hasCareerHistory,
  hasPositioning,
  hasTargetTitles,
  profileScore,
  firstCompany = false,
  initialStage,
}: {
  companyId: string
  companyName: string
  companyStage: string
  stageLabel: string
  hasContacts: boolean
  hasNotes: boolean
  hasInterviewNotes: boolean
  roleType: string | null
  hasCareerHistory: boolean
  hasPositioning: boolean
  hasTargetTitles: boolean
  profileScore: number
  firstCompany?: boolean
  initialStage?: InterviewStage
}) {
  const [brief, setBrief] = useState('')
  const [briefId, setBriefId] = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [refineInput, setRefineInput] = useState('')
  const [refining, setRefining] = useState(false)
  const [postingUrl, setPostingUrl] = useState('')
  const [interviewStage, setInterviewStage] = useState<InterviewStage>(
    initialStage ?? DEFAULT_INTERVIEW_STAGE[companyStage] ?? 'executive_interview'
  )
  const [roleMode, setRoleMode] = useState<PrepRoleMode>(inferInitialRoleMode(roleType))
  const [outreachDraft, setOutreachDraft] = useState('')
  const [outreachLoading, setOutreachLoading] = useState(false)
  const [outreachError, setOutreachError] = useState('')
  const [outreachCopied, setOutreachCopied] = useState(false)
  const [outreachLogged, setOutreachLogged] = useState(false)
  const [outreachLogLoading, setOutreachLogLoading] = useState(false)
  const [lowConfidenceAcknowledged, setLowConfidenceAcknowledged] = useState(false)
  const [reviewedBriefId, setReviewedBriefId] = useState<string | null>(null)
  const [markingReviewed, setMarkingReviewed] = useState(false)
  const [traceFilter, setTraceFilter] = useState<TraceFilter>('all')
  const ph = usePostHog()
  // Chat state
  type ChatMessage = { role: 'user' | 'assistant'; content: string }
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([])
  const [chatInput, setChatInput] = useState('')
  const [chatLoading, setChatLoading] = useState(false)
  const [downloading, setDownloading] = useState(false)
  const refineRef = useRef<HTMLTextAreaElement>(null)
  const chatInputRef = useRef<HTMLTextAreaElement>(null)
  const autoStarted = useRef(false)
  const lowConfidenceSeenForBrief = useRef<string | null>(null)

  function captureTraceInteraction(interactionType: 'legend_filter' | 'label_click', nextFilter: TraceFilter) {
    try {
      ph?.capture('prep_trace_interaction', {
        company_id: companyId,
        interaction_type: interactionType,
        trace_filter: nextFilter,
        has_brief: !!brief,
      })
    } catch {
      // analytics must not block interactions
    }
  }

  async function emitPmfEvent(
    eventName: string,
    properties: Record<string, string | number | boolean | null>,
  ) {
    try {
      await fetch('/api/events/pmf', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ eventName, properties }),
      })
    } catch {
      // telemetry must not block product interactions
    }
  }

  function handleTraceLabelClick(originClass: ClaimOriginClass) {
    setTraceFilter(originClass)
    captureTraceInteraction('label_click', originClass)
  }

  function handleLegendFilter(next: TraceFilter) {
    setTraceFilter(next)
    captureTraceInteraction('legend_filter', next)
  }

  useEffect(() => {
    if (firstCompany && !autoStarted.current) {
      autoStarted.current = true
      handleGenerate()
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const background   = useOnDemand(`/api/prep/${companyId}/background`,  companyId, 'background')
  const leadership   = useOnDemand(`/api/prep/${companyId}/leadership`,  companyId, 'leadership')
  const priorities   = useOnDemand(`/api/prep/${companyId}/priorities`,  companyId, 'priorities')
  const challenges   = useOnDemand(`/api/prep/${companyId}/challenges`,  companyId, 'challenges')
  const competitive  = useOnDemand(`/api/prep/${companyId}/competitive`, companyId, 'competitive')
  const wins         = useOnDemand(`/api/prep/${companyId}/wins`,        companyId, 'wins')
  const techStack    = useOnDemand(`/api/prep/${companyId}/tech-stack`,  companyId, 'tech_stack')
  const whyHere      = useOnDemand(`/api/prep/${companyId}/why-here`,    companyId, 'why_here')
  const questions    = useOnDemand(`/api/prep/${companyId}/questions`,   companyId, 'questions')

  async function handleGenerate() {
    setLoading(true)
    setBrief('')
    setBriefId(null)
    setReviewedBriefId(null)
    setTraceFilter('all')
    setLowConfidenceAcknowledged(false)
    setError('')
    try {
      const url = new URL(`/api/prep/${companyId}`, window.location.origin)
      if (postingUrl.trim()) url.searchParams.set('posting_url', postingUrl.trim())
      url.searchParams.set('interview_stage', interviewStage)
      url.searchParams.set('role_mode', roleMode)
      const res = await fetch(url.toString())
      if (!res.ok) {
        const body = await res.json().catch(() => ({}))
        setError(body?.error ?? `Request failed (${res.status})`)
        return
      }
      let fullText = ''
      await streamResponse(res, chunk => { fullText += chunk; setBrief(fullText) })
      if (fullText.startsWith('__ERROR__')) {
        setError(fullText.slice(9))
        setBrief('')
      } else {
        const id = await saveBrief('prep', fullText, companyId)
        setBriefId(id)
        const confidence = scorePrepBriefConfidence(fullText)
        await emitPmfEvent(PMF_EVENTS.prep.prep_brief_generated, {
          company_id: companyId,
          type: 'prep',
          mode: roleMode,
          confidence_band: confidence.band,
          action_context: 'prep_generate',
          interview_stage: interviewStage,
        })
      }
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Unknown error')
    } finally {
      setLoading(false)
    }
  }

  async function handleRefine() {
    const request = refineInput.trim()
    if (!request || refining || loading) return
    setRefining(true)
    setBrief('')
    setBriefId(null)
    setReviewedBriefId(null)
    setTraceFilter('all')
    setLowConfidenceAcknowledged(false)
    setError('')
    try {
      const res = await fetch(`/api/prep/${companyId}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ brief, request }),
      })
      if (!res.ok) {
        const body = await res.json().catch(() => ({}))
        setError(body?.error ?? `Request failed (${res.status})`)
        return
      }
      let fullText = ''
      await streamResponse(res, chunk => { fullText += chunk; setBrief(fullText) })
      if (fullText.startsWith('__ERROR__')) {
        setError(fullText.slice(9))
        setBrief('')
      } else {
        setRefineInput('')
        const id = await saveBrief('prep', fullText, companyId)
        setBriefId(id)
        const confidence = scorePrepBriefConfidence(fullText)
        await emitPmfEvent(PMF_EVENTS.prep.prep_brief_refined, {
          company_id: companyId,
          mode: roleMode,
          confidence_band: confidence.band,
          action_context: 'prep_refine',
          interview_stage: interviewStage,
        })
      }
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Unknown error')
    } finally {
      setRefining(false)
    }
  }

  async function handleLogOutreach() {
    setOutreachLogLoading(true)
    try {
      await fetch(`/api/prep/${companyId}/outreach/log`, { method: 'POST' })
      setOutreachLogged(true)
    } catch {
      // non-critical - silently fail
    } finally {
      setOutreachLogLoading(false)
    }
  }

  async function handleGenerateOutreach() {
    setOutreachLoading(true)
    setOutreachDraft('')
    setOutreachError('')
    setOutreachCopied(false)
    setOutreachLogged(false)
    try {
      const res = await fetch(`/api/prep/${companyId}/outreach`, { method: 'POST' })
      if (!res.ok) {
        const body = await res.json().catch(() => ({}))
        setOutreachError(body?.error ?? `Request failed (${res.status})`)
        return
      }
      let fullText = ''
      await streamResponse(res, chunk => { fullText += chunk; setOutreachDraft(fullText) })
      if (fullText.startsWith('__ERROR__')) {
        setOutreachError(fullText.slice(9))
        setOutreachDraft('')
      }
    } catch (e) {
      setOutreachError(e instanceof Error ? e.message : 'Unknown error')
    } finally {
      setOutreachLoading(false)
    }
  }

  function handleCopyOutreach() {
    navigator.clipboard.writeText(outreachDraft).then(() => {
      setOutreachCopied(true)
      setTimeout(() => setOutreachCopied(false), 2000)
    }).catch(() => {})
  }

  async function handleChat() {
    const message = chatInput.trim()
    if (!message || chatLoading || loading) return
    const userMsg: ChatMessage = { role: 'user', content: message }
    setChatMessages(prev => [...prev, userMsg])
    setChatInput('')
    setChatLoading(true)
    try {
      const res = await fetch(`/api/prep/${companyId}/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message,
          brief: brief.slice(0, 6000),
          companyName,
          history: chatMessages.slice(-8).map(m => ({ role: m.role, content: m.content })),
        }),
      })
      let fullText = ''
      setChatMessages(prev => [...prev, { role: 'assistant', content: '' }])
      if (res.ok) {
        await streamResponse(res, chunk => {
          fullText += chunk
          setChatMessages(prev => {
            const updated = [...prev]
            updated[updated.length - 1] = { role: 'assistant', content: fullText }
            return updated
          })
        })
      } else {
        setChatMessages(prev => {
          const updated = [...prev]
          updated[updated.length - 1] = { role: 'assistant', content: 'Unable to answer right now.' }
          return updated
        })
      }
    } catch {
      setChatMessages(prev => {
        const updated = [...prev]
        updated[updated.length - 1] = { role: 'assistant', content: 'Unable to answer right now.' }
        return updated
      })
    } finally {
      setChatLoading(false)
    }
  }

  async function handleDownload() {
    if (downloading || !brief) return
    setDownloading(true)
    try {
      const title = `${companyName} - Prep Brief`
      const res = await fetch('/api/briefs/download', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: brief, title }),
      })
      if (!res.ok) return
      const blob = await res.blob()
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `${companyName.replace(/[^a-z0-9]+/gi, '-').toLowerCase()}-prep-brief.docx`
      document.body.appendChild(a)
      a.click()
      document.body.removeChild(a)
      URL.revokeObjectURL(url)
      await emitPmfEvent(PMF_EVENTS.prep.prep_export_word, {
        company_id: companyId,
        mode: roleMode,
        confidence_band: briefConfidence?.band ?? 'unknown',
        action_context: 'prep_export_word',
        interview_stage: interviewStage,
      })
    } catch {
      // silently fail - user can retry
    } finally {
      setDownloading(false)
    }
  }

  async function handlePdfExport() {
    if (exportBlockedByConfidence) return
    await emitPmfEvent(PMF_EVENTS.prep.prep_export_pdf, {
      company_id: companyId,
      mode: roleMode,
      confidence_band: briefConfidence?.band ?? 'unknown',
      action_context: 'prep_export_pdf',
      interview_stage: interviewStage,
    })
    window.print()
  }

  async function handleMarkReviewed() {
    if (!brief || markingReviewed) return
    if (briefId && reviewedBriefId === briefId) return

    setMarkingReviewed(true)
    try {
      await emitPmfEvent(PMF_EVENTS.prep.prep_brief_reviewed, {
        company_id: companyId,
        mode: roleMode,
        confidence_band: briefConfidence?.band ?? 'unknown',
        action_context: 'prep_brief_reviewed',
        interview_stage: interviewStage,
      })
      setReviewedBriefId(briefId ?? '__reviewed__')
    } finally {
      setMarkingReviewed(false)
    }
  }

  const busy = loading || refining
  const briefConfidence = useMemo(() => {
    if (!brief) return null
    return scorePrepBriefConfidence(brief)
  }, [brief])
  const isLowConfidence = briefConfidence?.band === 'low'
  const exportBlockedByConfidence = isLowConfidence && !lowConfidenceAcknowledged

  useEffect(() => {
    if (!brief || !isLowConfidence) return
    if (lowConfidenceSeenForBrief.current === brief) return
    lowConfidenceSeenForBrief.current = brief

    void emitPmfEvent(PMF_EVENTS.prep.prep_low_confidence_seen, {
      company_id: companyId,
      mode: roleMode,
      confidence_band: briefConfidence?.band ?? 'low',
      action_context: 'prep_low_confidence_banner',
      interview_stage: interviewStage,
    })
  }, [brief, isLowConfidence, companyId, roleMode, interviewStage, briefConfidence?.band])

  return (
    <div className="min-h-screen bg-slate-100 font-sans">

      <header className="bg-slate-900 no-print">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 h-14 flex items-center justify-between">
          <span className="text-[10px] font-bold tracking-[0.16em] uppercase text-slate-600">
            <span className="text-white">Starting </span><span className="text-orange-500">Monday</span>
          </span>
          <Link
            href={`/dashboard/companies/${companyId}`}
            className="text-[13px] text-slate-500 hover:text-slate-300 transition-colors"
          >
            ← {companyName}
          </Link>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 sm:px-6 py-8 sm:py-10">

        <div className="mb-6 sm:mb-8 no-print">
          <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-4 sm:gap-6 mb-5">
            <div>
              <h1 className="text-[26px] font-bold text-slate-900 leading-tight">Interview Prep</h1>
              <p className="text-[13px] text-slate-500 mt-1.5">{companyName} · {stageLabel}</p>
            </div>
            <div className="flex flex-col items-stretch sm:items-end gap-2 shrink-0">
              <input
                type="url"
                value={postingUrl}
                onChange={e => setPostingUrl(e.target.value)}
                placeholder="Paste job posting URL (optional)"
                disabled={busy}
                className="text-[12px] text-slate-700 placeholder-slate-400 border border-slate-200 rounded px-3 py-2 w-full sm:w-72 focus:outline-none focus:border-slate-400 disabled:opacity-50"
              />
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={handleGenerate}
                  disabled={busy}
                  className="flex-1 bg-slate-900 text-white text-[13px] font-semibold px-5 py-2.5 rounded cursor-pointer border-0 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {loading ? 'Generating…' : brief ? 'Regenerate' : 'Generate prep brief'}
                </button>
                {brief && !busy && (
                  <>
                    <button
                      type="button"
                      onClick={() => {
                        void handleMarkReviewed()
                      }}
                      disabled={markingReviewed || reviewedBriefId === (briefId ?? '__reviewed__')}
                      className="shrink-0 text-[13px] font-semibold text-slate-600 border border-slate-200 rounded px-4 py-2.5 hover:border-slate-400 hover:text-slate-800 bg-white cursor-pointer transition-colors disabled:opacity-40"
                      title="Mark this prep brief as reviewed"
                    >
                      {reviewedBriefId === (briefId ?? '__reviewed__') ? 'Reviewed' : markingReviewed ? 'Saving…' : 'Mark reviewed'}
                    </button>
                    <button
                      type="button"
                      onClick={handleDownload}
                      disabled={downloading || exportBlockedByConfidence}
                      className="shrink-0 text-[13px] font-semibold text-slate-600 border border-slate-200 rounded px-4 py-2.5 hover:border-slate-400 hover:text-slate-800 bg-white cursor-pointer transition-colors disabled:opacity-40"
                      title="Download as Word document"
                    >
                      {downloading ? '…' : 'Word'}
                    </button>
                    <button
                      type="button"
                      onClick={() => {
                        void handlePdfExport()
                      }}
                      disabled={exportBlockedByConfidence}
                      className="shrink-0 text-[13px] font-semibold text-slate-600 border border-slate-200 rounded px-4 py-2.5 hover:border-slate-400 hover:text-slate-800 bg-white cursor-pointer transition-colors"
                      title="Save as PDF"
                    >
                      PDF
                    </button>
                  </>
                )}
              </div>
            </div>
          </div>

          <div>
            <p className="text-[10px] font-bold tracking-[0.12em] uppercase text-slate-400 mb-2">Interview stage</p>
            <div className="flex flex-wrap gap-1.5">
              {STAGE_OPTIONS.map(opt => (
                <button
                  key={opt.value}
                  type="button"
                  onClick={() => setInterviewStage(opt.value)}
                  disabled={busy}
                  className={`text-[12px] font-medium px-3 py-1.5 rounded border transition-colors cursor-pointer disabled:cursor-not-allowed disabled:opacity-50 ${
                    interviewStage === opt.value
                      ? 'bg-slate-900 text-white border-slate-900'
                      : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400 hover:text-slate-800'
                  }`}
                >
                  {opt.label}
                </button>
              ))}
            </div>
          </div>

          <div className="mt-4">
            <p className="text-[10px] font-bold tracking-[0.12em] uppercase text-slate-400 mb-2">Role mode</p>
            <div className="flex flex-wrap gap-1.5">
              {ROLE_MODE_OPTIONS.map(opt => (
                <button
                  key={opt.value}
                  type="button"
                  onClick={() => setRoleMode(opt.value)}
                  disabled={busy}
                  className={`text-[12px] font-medium px-3 py-1.5 rounded border transition-colors cursor-pointer disabled:cursor-not-allowed disabled:opacity-50 ${
                    roleMode === opt.value
                      ? 'bg-slate-900 text-white border-slate-900'
                      : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400 hover:text-slate-800'
                  }`}
                >
                  {opt.label}
                </button>
              ))}
            </div>
          </div>
        </div>

        {firstCompany && !brief && (
          <div className="mb-6 bg-orange-50 border border-orange-200 rounded px-6 py-5">
            <p className="text-[10px] font-bold tracking-[0.14em] uppercase text-orange-500 mb-1">Your first intelligence brief</p>
            <p className="text-[14px] font-semibold text-slate-900 mb-1">
              {loading ? `Building your brief on ${companyName}...` : `Ready to brief you on ${companyName}.`}
            </p>
            <p className="text-[13px] text-slate-600 leading-relaxed">
              {loading
                ? 'Scanning public signals, leadership context, strategic priorities, and likely objections. This takes about 20 seconds.'
                : 'We scanned public signals, leadership context, and strategic priorities. Your brief is ready.'}
            </p>
          </div>
        )}

        {error && (
          <div className="mb-6 px-4 py-3 bg-red-50 border border-red-200 rounded text-[13px] text-red-700">
            {error}
          </div>
        )}

        {!brief && !busy && (() => {
          const warnings: { key: string; label: string; message: string; href: string; cta: string }[] = []
          if (!hasCareerHistory) warnings.push({
            key: 'career',
            label: 'No career history',
            message: 'The brief cannot personalize your background. Add verified career history on your profile.',
            href: '/dashboard/profile',
            cta: 'Add career history',
          })
          if (!hasPositioning) warnings.push({
            key: 'positioning',
            label: 'No positioning summary',
            message: 'Win Thesis will be less differentiated without a positioning statement.',
            href: '/dashboard/profile',
            cta: 'Add positioning',
          })
          if (!hasTargetTitles) warnings.push({
            key: 'targets',
            label: 'No target roles set',
            message: 'The brief cannot calibrate to your targets without at least one target title.',
            href: '/dashboard/profile',
            cta: 'Set targets',
          })
          if (!hasNotes) warnings.push({
            key: 'notes',
            label: 'No company notes',
            message: (roleType && NO_NOTES_MESSAGES[roleType]) ?? 'Company notes are the single biggest lever for brief quality.',
            href: `/dashboard/companies/${companyId}`,
            cta: 'Add notes',
          })
          if (warnings.length === 0) return null
          return (
            <div className="mb-4 flex flex-col gap-2">
              {warnings.map(w => (
                <div key={w.key} className="px-4 py-3 bg-amber-50 border border-amber-200 rounded flex items-start justify-between gap-4">
                  <div>
                    <p className="text-[12px] font-semibold text-amber-700 mb-0.5">{w.label}</p>
                    <p className="text-[12px] text-amber-600">{w.message}</p>
                  </div>
                  <Link href={w.href} className="shrink-0 text-[11px] font-semibold text-amber-700 border border-amber-300 rounded px-2.5 py-1 hover:bg-amber-100 transition-colors whitespace-nowrap">
                    {w.cta}
                  </Link>
                </div>
              ))}
            </div>
          )
        })()}

        {!brief && !busy && !error && (
          <div className="bg-white border border-slate-200 rounded p-8 sm:p-10 text-center">
            <p className="text-[14px] text-slate-400">
              Generates an elite brief using your pipeline data, company notes, scan results, and known contacts.
            </p>
          </div>
        )}

        {!brief && !busy && error && (
          <div className="bg-white border border-slate-200 rounded p-8 sm:p-10 text-center">
            <p className="text-[14px] text-slate-400">
              Click Generate to try again.
            </p>
          </div>
        )}

        {busy && !brief && (
          <div className="bg-white border border-slate-200 rounded p-5 sm:p-8">
            <div className="flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block" />
              <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block [animation-delay:150ms]" />
              <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block [animation-delay:300ms]" />
            </div>
          </div>
        )}

        {brief && profileScore < 50 && !busy && (
          <div className="mb-4 px-5 py-4 bg-amber-50 border border-amber-200 rounded flex items-start gap-4">
            <div className="flex-1 min-w-0">
              <p className="text-[13px] font-semibold text-amber-900">
                This brief used limited profile data.
              </p>
              <p className="text-[12px] text-amber-700 mt-1 leading-relaxed">
                Adding your resume unlocks significantly more specific talking points, win thesis, and pushback prep. The brief you just generated is a starting point.
              </p>
            </div>
            <Link
              href="/dashboard/profile#section-resume"
              className="shrink-0 text-[12px] font-semibold text-amber-900 border border-amber-300 hover:border-amber-500 px-3 py-1.5 rounded transition-colors"
            >
              Add resume →
            </Link>
          </div>
        )}

        {brief && briefConfidence && !busy && (
          <div className={`mb-4 rounded border px-5 py-4 ${isLowConfidence ? 'bg-amber-50 border-amber-200' : 'bg-slate-50 border-slate-200'}`}>
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
              <div>
                <p className="text-[10px] font-bold tracking-[0.12em] uppercase text-slate-500">Brief confidence</p>
                <p className="text-[14px] font-semibold text-slate-900 mt-1">
                  Score: {briefConfidence.score}/100 ({briefConfidence.band})
                </p>
              </div>
              <div className="text-[12px] text-slate-600">
                Sections: {briefConfidence.factors.structuredSections}/5 · Inferred penalty: -{briefConfidence.factors.inferredSharePenalty}
              </div>
            </div>
            {isLowConfidence && (
              <div className="mt-3 pt-3 border-t border-amber-200">
                <p className="text-[12px] font-semibold text-amber-800 mb-1.5">Low confidence remediation required before export</p>
                <ul className="text-[12px] text-amber-700 space-y-1.5">
                  {briefConfidence.remediation.map((item) => (
                    <li key={item}>- {item}</li>
                  ))}
                </ul>
                <button
                  type="button"
                  onClick={() => {
                    setLowConfidenceAcknowledged(true)
                    void emitPmfEvent(PMF_EVENTS.prep.prep_low_confidence_seen, {
                      company_id: companyId,
                      mode: roleMode,
                      confidence_band: briefConfidence?.band ?? 'low',
                      action_context: 'prep_low_confidence_acknowledged',
                      interview_stage: interviewStage,
                    })
                  }}
                  className="mt-3 text-[12px] font-semibold text-amber-900 border border-amber-300 rounded px-3 py-1.5 hover:bg-amber-100 transition-colors"
                >
                  Acknowledge and allow export
                </button>
              </div>
            )}
          </div>
        )}

        {brief && (
          <div className="bg-white border border-slate-200 rounded p-5 sm:p-8 mb-4">
            <SourceLegend
              traceFilter={traceFilter}
              counts={buildClaimOriginCounts(brief)}
              onChangeFilter={handleLegendFilter}
            />
            {renderBrief(brief, traceFilter, handleTraceLabelClick)}
            {busy && (
              <span className="inline-block w-0.5 h-4 bg-slate-400 animate-pulse ml-0.5 align-middle" />
            )}
            {!busy && (
              <p className="mt-6 pt-4 border-t border-slate-100 text-[11px] text-slate-400">
                AI-generated — use as input, not advice. Verify facts before any conversation.
              </p>
            )}
          </div>
        )}

        {briefId && !busy && (
          <div className="mb-4 flex justify-end no-print">
            <BriefRating briefId={briefId} />
          </div>
        )}

        {brief && !busy && (() => {
          const nudges: { href: string; cta: string; message: string }[] = []
          if (!hasInterviewNotes && (companyStage === 'interviewing' || companyStage === 'offer')) nudges.push({
            message: 'Add post-interview notes to sharpen the next brief based on what was actually asked.',
            href: `/dashboard/companies/${companyId}`,
            cta: 'Add interview notes',
          })
          if (!hasCareerHistory) nudges.push({
            message: 'Verified career history would make the Win Thesis and Talking Points significantly more specific.',
            href: '/dashboard/profile',
            cta: 'Add career history',
          })
          if (!hasPositioning) nudges.push({
            message: 'A positioning summary sharpens the Win Thesis and Bottom Line.',
            href: '/dashboard/profile',
            cta: 'Add positioning',
          })
          if (!hasNotes) nudges.push({
            message: 'Company notes are the single biggest lever. Add intel before the next regenerate.',
            href: `/dashboard/companies/${companyId}`,
            cta: 'Add notes',
          })
          const top = nudges.slice(0, 2)
          if (top.length === 0) return null
          return (
            <div className="mb-4 bg-white border border-slate-200 rounded p-5 no-print">
              <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-3">What would sharpen the next brief</p>
              <div className="flex flex-col gap-2.5">
                {top.map((n, i) => (
                  <div key={i} className="flex items-start justify-between gap-4">
                    <p className="text-[13px] text-slate-600">{n.message}</p>
                    <Link href={n.href} className="shrink-0 text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-2.5 py-1 hover:border-slate-400 transition-colors whitespace-nowrap">
                      {n.cta}
                    </Link>
                  </div>
                ))}
              </div>
            </div>
          )
        })()}

        {brief && !loading && (
          <div className="no-print">
            <OnDemandPanel
              title="Your Background Match"
              description="How your specific experience connects to this company's challenges. Generate this before you walk in."
              content={background.content}
              briefId={background.briefId}
              loading={background.loading}
              error={background.error}
              onGenerate={background.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
            <OnDemandPanel
              title="Leadership Team"
              description="Who is in the room, what they care about, and how to win with each of them."
              content={leadership.content}
              briefId={leadership.briefId}
              loading={leadership.loading}
              error={leadership.error}
              onGenerate={leadership.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
            <OnDemandPanel
              title="Strategic Priorities"
              description="What this company is actually focused on right now - and how to align your narrative."
              content={priorities.content}
              briefId={priorities.briefId}
              loading={priorities.loading}
              error={priorities.error}
              onGenerate={priorities.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
            <OnDemandPanel
              title="Pain Points"
              description="The real challenges they are dealing with - and how to demonstrate you understand them."
              content={challenges.content}
              briefId={challenges.briefId}
              loading={challenges.loading}
              error={challenges.error}
              onGenerate={challenges.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
            <OnDemandPanel
              title="Competitive Landscape"
              description="Who they compete with, how they position, and how to use it in the room."
              content={competitive.content}
              briefId={competitive.briefId}
              loading={competitive.loading}
              error={competitive.error}
              onGenerate={competitive.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
            <OnDemandPanel
              title="Recent Wins"
              description="What to acknowledge and reference to show you did the homework."
              content={wins.content}
              briefId={wins.briefId}
              loading={wins.loading}
              error={wins.error}
              onGenerate={wins.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
            <OnDemandPanel
              title="Tech Stack"
              description="What systems they are likely running and what to know before you walk in."
              content={techStack.content}
              briefId={techStack.briefId}
              loading={techStack.loading}
              error={techStack.error}
              onGenerate={techStack.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
            <OnDemandPanel
              title="Why Here"
              description="A personalized statement for when they ask why you want this role."
              content={whyHere.content}
              briefId={whyHere.briefId}
              loading={whyHere.loading}
              error={whyHere.error}
              onGenerate={whyHere.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
            <OnDemandPanel
              title="Likely Interview Questions"
              description="The questions they will ask you - with coaching on how to answer each."
              content={questions.content}
              briefId={questions.briefId}
              loading={questions.loading}
              error={questions.error}
              onGenerate={questions.generate}
              traceFilter={traceFilter}
              onTraceLabelClick={handleTraceLabelClick}
              onLegendFilter={handleLegendFilter}
            />
          </div>
        )}

        {brief && !loading && <div className="no-print"><ResourcePanel brief={brief} /></div>}

        {brief && !loading && (
          <div className="bg-white border border-slate-200 rounded p-6 mb-4 no-print">
            <p className="text-[11px] font-bold tracking-[0.08em] uppercase text-slate-400 mb-3">
              Ask about this brief
            </p>
            {chatMessages.length > 0 && (
              <div className="flex flex-col gap-3 mb-4 max-h-80 overflow-y-auto">
                {chatMessages.map((msg, i) => (
                  <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] rounded-lg px-4 py-2.5 text-[13px] leading-relaxed whitespace-pre-wrap ${
                      msg.role === 'user'
                        ? 'bg-slate-900 text-white'
                        : 'bg-slate-50 border border-slate-200 text-slate-800'
                    }`}>
                      {msg.content}
                      {msg.role === 'assistant' && msg.content === '' && chatLoading && (
                        <span className="inline-flex gap-1 ml-1">
                          <span className="w-1 h-1 rounded-full bg-slate-400 animate-pulse inline-block" />
                          <span className="w-1 h-1 rounded-full bg-slate-400 animate-pulse inline-block [animation-delay:150ms]" />
                          <span className="w-1 h-1 rounded-full bg-slate-400 animate-pulse inline-block [animation-delay:300ms]" />
                        </span>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
            <div className="flex gap-2 items-end">
              <textarea
                ref={chatInputRef}
                value={chatInput}
                onChange={e => setChatInput(e.target.value)}
                onKeyDown={e => {
                  if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleChat() }
                }}
                placeholder={chatMessages.length === 0
                  ? 'Ask anything — "What should I ask about their CFO transition?" or "Role-play their opening question"'
                  : 'Ask a follow-up...'}
                rows={2}
                disabled={chatLoading || loading}
                className="flex-1 border border-slate-200 rounded-lg px-3 py-2.5 text-[13px] text-slate-900 placeholder:text-slate-300 focus:outline-none focus:border-slate-400 resize-none disabled:opacity-50"
              />
              <button
                type="button"
                onClick={handleChat}
                disabled={chatLoading || loading || !chatInput.trim()}
                className="shrink-0 bg-slate-900 text-white text-[13px] font-semibold px-4 py-2.5 rounded-lg cursor-pointer border-0 disabled:opacity-40 disabled:cursor-not-allowed"
              >
                {chatLoading ? '…' : 'Ask'}
              </button>
            </div>
            <p className="mt-2 text-[11px] text-slate-300">Enter to send · Shift+Enter for new line</p>
          </div>
        )}

        {brief && !loading && (
          <div className="bg-white border border-slate-200 rounded p-6 no-print">
            <p className="text-[11px] font-bold tracking-[0.08em] uppercase text-slate-400 mb-3">
              Refine this brief
            </p>
            <div className="flex flex-wrap gap-2 mb-3">
              {[
                'Make the pushback counters more aggressive',
                'Add a first 30/60/90 day plan',
                "Assume they'll challenge my industry experience",
              ].map(chip => (
                <button
                  key={chip}
                  type="button"
                  onClick={() => { setRefineInput(chip); refineRef.current?.focus() }}
                  className="text-[12px] text-slate-500 border border-slate-200 rounded-full px-3 py-1 hover:border-slate-400 hover:text-slate-700 bg-transparent cursor-pointer transition-colors"
                >
                  {chip}
                </button>
              ))}
            </div>
            <div className="flex gap-3 items-end">
              <textarea
                ref={refineRef}
                value={refineInput}
                onChange={e => setRefineInput(e.target.value)}
                onKeyDown={e => {
                  if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleRefine() }
                }}
                placeholder="Or type your own refinement request..."
                rows={2}
                disabled={refining}
                className="flex-1 border border-slate-200 rounded-lg px-3 py-2.5 text-[13px] text-slate-900 placeholder:text-slate-300 focus:outline-none focus:border-slate-400 resize-none disabled:opacity-50"
              />
              <button
                type="button"
                onClick={handleRefine}
                disabled={refining || !refineInput.trim()}
                className="shrink-0 bg-slate-900 text-white text-[13px] font-semibold px-5 py-2.5 rounded-lg cursor-pointer border-0 disabled:opacity-40 disabled:cursor-not-allowed"
              >
                {refining ? 'Refining…' : 'Refine'}
              </button>
            </div>
            <p className="mt-2 text-[11px] text-slate-300">Enter to submit · Shift+Enter for new line</p>
          </div>
        )}

        {brief && (
          <div className="mt-6 bg-slate-900 rounded px-6 py-5 no-print">
            <div className="flex items-center justify-between gap-4 mb-3">
              <p className="text-[13px] text-slate-300 font-semibold">
                Draft outreach from this brief
              </p>
              {!outreachDraft && !outreachLoading && (
                <button
                  type="button"
                  onClick={handleGenerateOutreach}
                  disabled={outreachLoading}
                  className="shrink-0 text-[12px] font-semibold text-white border border-slate-600 hover:border-slate-400 px-3 py-1.5 rounded transition-colors cursor-pointer bg-transparent disabled:opacity-50"
                >
                  Generate →
                </button>
              )}
            </div>

            {outreachLoading && !outreachDraft && (
              <p className="text-[13px] text-slate-400 italic">Drafting outreach…</p>
            )}

            {outreachError && (
              <p className="text-[13px] text-red-400">{outreachError}</p>
            )}

            {outreachDraft && (
              <div>
                <p className="text-[14px] text-slate-200 leading-relaxed whitespace-pre-wrap mb-4">
                  {outreachDraft}
                </p>
                <div className="flex items-center gap-3 flex-wrap">
                  <button
                    type="button"
                    onClick={handleCopyOutreach}
                    className="text-[12px] font-semibold text-white border border-slate-600 hover:border-slate-400 px-3 py-1.5 rounded transition-colors cursor-pointer bg-transparent"
                  >
                    {outreachCopied ? 'Copied!' : 'Copy'}
                  </button>
                  {hasContacts && !outreachLogged && (
                    <button
                      type="button"
                      onClick={handleLogOutreach}
                      disabled={outreachLogLoading}
                      className="text-[12px] font-semibold text-slate-400 hover:text-slate-200 border border-slate-600 hover:border-slate-400 px-3 py-1.5 rounded transition-colors cursor-pointer bg-transparent disabled:opacity-50"
                    >
                      {outreachLogLoading ? 'Logging…' : 'Log as sent'}
                    </button>
                  )}
                  {outreachLogged && (
                    <span className="text-[12px] font-semibold text-green-400">Logged</span>
                  )}
                  <button
                    type="button"
                    onClick={handleGenerateOutreach}
                    disabled={outreachLoading}
                    className="text-[12px] font-semibold text-slate-400 hover:text-slate-200 px-3 py-1.5 rounded transition-colors cursor-pointer bg-transparent border-0 disabled:opacity-50"
                  >
                    Regenerate
                  </button>
                  {!hasContacts && (
                    <Link
                      href={`/dashboard/companies/${companyId}`}
                      className="text-[12px] text-slate-400 hover:text-slate-200 transition-colors"
                    >
                      Add a contact to log this →
                    </Link>
                  )}
                </div>
              </div>
            )}

            {!outreachDraft && !outreachLoading && !outreachError && (
              <p className="text-[12px] text-slate-500">
                Generates a 3-sentence message grounded in this company&apos;s signals and your prep brief.
                {!hasContacts && ' Add a contact at ' + companyName + ' to log the outreach after.'}
              </p>
            )}
          </div>
        )}

      </main>
    </div>
  )
}

'use client'
import Link from 'next/link'
import { useState, useRef, useEffect } from 'react'
import { completeOnboarding, skipOnboarding } from './actions'
import { HelpQuickButton } from '@/components/HelpQuickButton'
import { type SearchPersona, seededCompaniesFor, suggestionsForPersona } from './onboarding-helpers'
import {
  type OnboardingChannel,
  computeElapsedSeconds,
  estimateManualFieldReduction,
  isTransitionFirstCohort,
} from '@/lib/onboarding-speed'

type ImportResult = {
  full_name?: string | null
  current_title?: string | null
  current_company?: string | null
  positioning_summary?: string | null
  resume_text?: string | null
  beyond_resume?: string | null
  target_titles?: string | null
}

const PERSONA_OPTIONS: { value: SearchPersona; label: string; sub: string }[] = [
  { value: 'csuite',   label: 'C-Suite',         sub: 'CEO, CFO, CTO, COO, CIO, CHRO' },
  { value: 'vp',       label: 'VP / SVP',         sub: 'Targeting C-suite or a larger VP role' },
  { value: 'director', label: 'Director',          sub: 'Targeting VP or above' },
  { value: 'board',    label: 'Board / Advisor',  sub: 'Board seat or advisory role' },
]

const STEP_COUNT = 7
const QUICK_PATH_STEP_COUNT = 5


function Dots({ current, total = STEP_COUNT }: { current: number; total?: number }) {
  return (
    <div className="flex items-center gap-2">
      {Array.from({ length: total }).map((_, i) => (
        <div
          key={i}
          className={[
            'rounded-full transition-all duration-300',
            i === current ? 'w-5 h-1.5 bg-slate-900' : i < current ? 'w-1.5 h-1.5 bg-slate-400' : 'w-1.5 h-1.5 bg-slate-200',
          ].join(' ')}
        />
      ))}
    </div>
  )
}

export function OnboardingForm({ profile }: { profile: { full_name?: string | null; current_title?: string | null; current_company?: string | null } | null }) {
  const [step, setStep] = useState(0)
  const [direction, setDirection] = useState<'forward' | 'back'>('forward')
  const [animating, setAnimating] = useState(false)
  const [advancedSetup, setAdvancedSetup] = useState(false)
  const [onboardingChannel, setOnboardingChannel] = useState<OnboardingChannel>('executives')
  const [lowEnergyMode, setLowEnergyMode] = useState(false)
  const [elapsedSeconds, setElapsedSeconds] = useState(0)
  const [onboardingStartedAt] = useState(() => new Date().toISOString())

  const [fullName, setFullName]               = useState(profile?.full_name ?? '')
  const [searchPersona, setSearchPersona]     = useState<SearchPersona | ''>('')
  const [employmentStatus, setEmploymentStatus] = useState('')
  const [searchTimeline, setSearchTimeline]   = useState('')
  const [searchDriver, setSearchDriver]       = useState('')
  const [currentTitle, setCurrentTitle]       = useState(profile?.current_title ?? '')
  const [currentCompany, setCurrentCompany]   = useState(profile?.current_company ?? '')
  const [resumeText, setResumeText]           = useState('')
  const [positioningSummary, setPositioningSummary] = useState('')
  const [beyondResume, setBeyondResume]       = useState('')
  const [targetTitles, setTargetTitles]       = useState('')
  const [linkedinUrl, setLinkedinUrl]         = useState('')

  const [companyNames, setCompanyNames] = useState<string[]>(['', '', ''])
  const [briefingTime, setBriefingTime] = useState('07:00')
  const [briefingFrequency, setBriefingFrequency] = useState<'daily' | 'weekly'>('daily')

  const [intelContent, setIntelContent] = useState('')
  const [intelLoading, setIntelLoading] = useState(false)

  const firstName = fullName.trim().split(' ')[0] || 'there'

  const isPassive = employmentStatus === 'employed_exploring' && searchTimeline === 'opportunistic'

  const [pasteText, setPasteText]     = useState('')
  const [importing, setImporting]     = useState(false)
  const [importDone, setImportDone]   = useState(false)
  const [importThin, setImportThin]   = useState(false)
  const [importError, setImportError] = useState('')
  const [extracting, setExtracting]   = useState(false)
  const [manualMode, setManualMode]   = useState(false)

  const linkedinPdfRef = useRef<HTMLInputElement>(null)
  const nameRef = useRef<HTMLInputElement>(null)
  const step6FetchStarted = useRef(false)
  const nudgeLogged = useRef(false)
  const startLogged = useRef(false)
  const firstValueLogged = useRef(false)

  const transitionFirst = isTransitionFirstCohort(employmentStatus, searchTimeline)

  const manualFieldReduction = estimateManualFieldReduction({
    fullName,
    currentTitle,
    currentCompany,
    searchPersona,
    companyCount: companyNames.filter((name) => name.trim()).length,
    importedProfile: importDone,
    lowEnergyMode,
  })

  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const ch = params.get('channel') as OnboardingChannel | null
    if (ch && ['executives', 'coaches', 'outplacement', 'search_firms'].includes(ch)) {
      setOnboardingChannel(ch)
    }
    const mode = params.get('mode')
    const from = params.get('from')
    if (mode === 'low_energy' || from === 'low-energy') {
      setLowEnergyMode(true)
      setAdvancedSetup(false)
    }
  }, [])

  useEffect(() => {
    if (step === 0) nameRef.current?.focus()
  }, [step])

  useEffect(() => {
    const timer = window.setInterval(() => {
      setElapsedSeconds(computeElapsedSeconds(onboardingStartedAt))
    }, 1000)
    return () => window.clearInterval(timer)
  }, [onboardingStartedAt])

  useEffect(() => {
    if (startLogged.current) return
    startLogged.current = true
    fetch('/api/onboarding/events', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        eventName: 'onboarding_started',
        properties: {
          started_at: onboardingStartedAt,
          channel: onboardingChannel,
          mode: lowEnergyMode ? 'low_energy' : 'standard',
          confidence_band: null,
          action_context: 'onboarding_started',
        },
      }),
    }).catch(() => {})
  }, [onboardingStartedAt, onboardingChannel, lowEnergyMode])

  useEffect(() => {
    if (step === 3 && isPassive && !manualMode) {
      const timeoutId = window.setTimeout(() => setManualMode(true), 0)
      return () => window.clearTimeout(timeoutId)
    }
  }, [step, isPassive, manualMode])

  useEffect(() => {
    if (step !== 4 || advancedSetup) return
    if (companyNames.some(n => n.trim())) return
    const seeded = seededCompaniesFor(searchPersona)
    if (seeded.length === 0) return
    const timeoutId = window.setTimeout(() => setCompanyNames([...seeded, '']), 0)
    return () => window.clearTimeout(timeoutId)
  }, [step, advancedSetup, companyNames, searchPersona])

  useEffect(() => {
    if (step < 6 || firstValueLogged.current) return
    firstValueLogged.current = true
    fetch('/api/onboarding/events', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        eventName: 'onboarding_first_value_ready',
        properties: {
          elapsed_seconds: elapsedSeconds,
          under_ten_minutes: elapsedSeconds <= 600,
          transition_first: transitionFirst,
          low_energy_mode: lowEnergyMode,
          mode: lowEnergyMode ? 'low_energy' : 'standard',
          confidence_band: null,
          action_context: 'onboarding_first_value_ready',
        },
      }),
    }).catch(() => {})
  }, [step, elapsedSeconds, transitionFirst, lowEnergyMode])

  useEffect(() => {
    if (step >= 6 || elapsedSeconds < 480 || nudgeLogged.current) return
    nudgeLogged.current = true
    fetch('/api/onboarding/events', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        eventName: 'onboarding_nudge_shown',
        properties: {
          elapsed_seconds: elapsedSeconds,
          step,
          transition_first: transitionFirst,
          mode: lowEnergyMode ? 'low_energy' : 'standard',
          confidence_band: null,
          action_context: 'onboarding_nudge_shown',
        },
      }),
    }).catch(() => {})
  }, [step, elapsedSeconds, transitionFirst, lowEnergyMode])

  useEffect(() => {
    const currentElapsedSeconds = computeElapsedSeconds(onboardingStartedAt)
    fetch('/api/onboarding/events', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        eventName: 'onboarding_step_completed',
        properties: {
          step,
          elapsed_seconds: currentElapsedSeconds,
          low_energy_mode: lowEnergyMode,
          channel: onboardingChannel,
          mode: lowEnergyMode ? 'low_energy' : 'standard',
          confidence_band: null,
          action_context: 'onboarding_step_completed',
        },
      }),
    }).catch(() => {})
  }, [step, lowEnergyMode, onboardingChannel, onboardingStartedAt])

  useEffect(() => {
    if (step !== 6) return
    const firstCompany = companyNames.find(n => n.trim())
    if (!firstCompany || intelContent || intelLoading || step6FetchStarted.current) return
    step6FetchStarted.current = true
    setIntelLoading(true)
    fetch('/api/onboarding/intel', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ companyName: firstCompany.trim(), persona: searchPersona }),
    }).then(async res => {
      if (!res.body) return
      const reader = res.body.getReader()
      const decoder = new TextDecoder()
      let text = ''
      while (true) {
        const { done, value } = await reader.read()
        if (done) break
        text += decoder.decode(value, { stream: true })
        setIntelContent(text)
      }
    }).catch(() => {}).finally(() => setIntelLoading(false))
  }, [step, companyNames, intelContent, intelLoading, searchPersona])

  function goTo(next: number) {
    if (animating) return
    setDirection(next > step ? 'forward' : 'back')
    setAnimating(true)
    setTimeout(() => {
      setStep(next)
      setAnimating(false)
    }, 180)
  }

  function advance() {
    if (lowEnergyMode && step === 1) { goTo(4); return }
    if (lowEnergyMode && step === 4) {
      if (isPassive) setBriefingFrequency('weekly')
      goTo(6)
      return
    }
    if (!advancedSetup && step === 1) { goTo(4); return }
    if (!advancedSetup && step === 4) {
      if (isPassive) setBriefingFrequency('weekly')
      goTo(6)
      return
    }
    if (isPassive && step === 2) { goTo(4); return }
    if (isPassive && step === 4) { setBriefingFrequency('weekly'); goTo(6); return }
    if (step < STEP_COUNT - 1) goTo(step + 1)
  }

  function prevStep() {
    if (!advancedSetup && step === 4) return 1
    if (isPassive && step === 4) return 2
    if (isPassive && step === 6) return 4
    return step - 1
  }

  function quickStart() {
    if (!searchPersona) setSearchPersona('csuite')
    if (!companyNames.some(n => n.trim())) {
      const seeded = seededCompaniesFor(searchPersona || 'csuite')
      setCompanyNames([...seeded, ''])
    }
    goTo(4)
  }

  function progressIndex() {
    if (advancedSetup) return step
    if (step <= 1) return step
    if (step <= 4) return 2
    if (step === 5) return 3
    return 4
  }

  function applyImport(data: ImportResult) {
    if (data.full_name)            setFullName(data.full_name)
    if (data.current_title)        setCurrentTitle(data.current_title)
    if (data.current_company)      setCurrentCompany(data.current_company)
    if (data.positioning_summary)  setPositioningSummary(data.positioning_summary)
    if (data.resume_text)          setResumeText(data.resume_text)
    if (data.beyond_resume)        setBeyondResume(data.beyond_resume)
    if (data.target_titles)        setTargetTitles(data.target_titles)
    // Thin: only raw text was saved - structured fields (title, company) weren't extracted
    setImportThin(!data.current_title && !data.current_company)
    setImportDone(true)
  }

  async function handlePasteImport() {
    if (!pasteText.trim() || importing) return
    setImporting(true)
    setImportError('')
    const text = pasteText
    try {
      const res = await fetch('/api/linkedin-import', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text }),
      })
      const data = res.ok ? await res.json() : {}
      applyImport(data)
      if (!data.resume_text) setResumeText(text.slice(0, 20000))
      setPasteText('')
    } catch {
      setResumeText(text.slice(0, 20000))
      setImportDone(true)
    } finally {
      setImporting(false)
    }
  }

  async function handleLinkedInPdf(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return
    setExtracting(true)
    setImportError('')
    try {
      const fd = new FormData()
      fd.append('file', file)
      const extractRes = await fetch('/api/linkedin-import/extract', { method: 'POST', body: fd })
      const extractData = await extractRes.json().catch(() => ({}))
      if (!extractRes.ok || !extractData.text) {
        setImportError('Could not read the PDF. Try pasting your profile text instead.')
        return
      }
      setImporting(true)
      try {
        const importRes = await fetch('/api/linkedin-import', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ text: extractData.text }),
        })
        const data = importRes.ok ? await importRes.json() : {}
        applyImport(data)
        if (!data.resume_text) setResumeText(extractData.text.slice(0, 20000))
      } catch {
        setResumeText(extractData.text.slice(0, 20000))
        setImportDone(true)
      } finally {
        setImporting(false)
      }
    } finally {
      setExtracting(false)
      if (linkedinPdfRef.current) linkedinPdfRef.current.value = ''
    }
  }

  const slideClass = animating
    ? direction === 'forward'
      ? 'opacity-0 translate-x-4'
      : 'opacity-0 -translate-x-4'
    : 'opacity-100 translate-x-0'

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center px-4 py-12">
      <form id="onboarding-form" action={completeOnboarding} className="hidden">
        <input type="hidden" name="full_name"           value={fullName} />
        <input type="hidden" name="search_persona"      value={searchPersona} />
        <input type="hidden" name="onboarding_channel"  value={onboardingChannel} />
        <input type="hidden" name="onboarding_low_energy" value={lowEnergyMode ? 'true' : 'false'} />
        <input type="hidden" name="onboarding_started_at" value={onboardingStartedAt} />
        <input type="hidden" name="onboarding_elapsed_seconds" value={String(elapsedSeconds)} />
        <input type="hidden" name="manual_fields_baseline" value={String(manualFieldReduction.baselineManualFields)} />
        <input type="hidden" name="manual_fields_required" value={String(manualFieldReduction.requiredManualFields)} />
        <input type="hidden" name="manual_fields_reduction_rate" value={String(manualFieldReduction.reductionRate)} />
        <input type="hidden" name="employment_status"   value={employmentStatus} />
        <input type="hidden" name="search_timeline"     value={searchTimeline} />
        <input type="hidden" name="search_driver"       value={searchDriver} />
        <input type="hidden" name="current_title"       value={currentTitle} />
        <input type="hidden" name="current_company"     value={currentCompany} />
        <input type="hidden" name="resume_text"         value={resumeText} />
        <input type="hidden" name="positioning_summary" value={positioningSummary} />
        <input type="hidden" name="beyond_resume"       value={beyondResume} />
        <input type="hidden" name="target_titles"       value={targetTitles} />
        <input type="hidden" name="linkedin_url"        value={linkedinUrl} />
        <input type="hidden" name="company_names"        value={JSON.stringify(companyNames.filter(n => n.trim()))} />
        <input type="hidden" name="briefing_time"        value={briefingTime} />
        <input type="hidden" name="briefing_frequency"   value={briefingFrequency} />
      </form>

      <div className="w-full max-w-lg">
        {/* Wordmark */}
        <div className="text-center mb-10">
          <span className="text-[11px] font-bold tracking-[0.18em] uppercase text-slate-400">Starting Monday</span>
        </div>

        {/* Step content */}
        <div
          className={[
            'transition-all duration-200 ease-out',
            slideClass,
          ].join(' ')}
        >
          {step === 0 && (
            <StepName
              value={fullName}
              onChange={setFullName}
              inputRef={nameRef}
                onNext={() => advance()}
            />
          )}

          {step === 1 && (
            <StepLevel
              value={searchPersona}
              onSelect={v => { setSearchPersona(v); setTimeout(advance, 220) }}
            />
          )}

          {step === 2 && (
            <StepSituation
              status={employmentStatus}
              timeline={searchTimeline}
              driver={searchDriver}
              onStatus={setEmploymentStatus}
              onTimeline={setSearchTimeline}
              onDriver={setSearchDriver}
            />
          )}

          {step === 3 && (
            <StepImport
              importDone={importDone}
              importThin={importThin}
              importing={importing}
              extracting={extracting}
              importError={importError}
              manualMode={manualMode}
              pasteText={pasteText}
              currentTitle={currentTitle}
              currentCompany={currentCompany}
              linkedinUrl={linkedinUrl}
              onPasteText={setPasteText}
              onImport={handlePasteImport}
              onPdfClick={() => linkedinPdfRef.current?.click()}
              onManual={() => setManualMode(true)}
              onTitle={setCurrentTitle}
              onCompany={setCurrentCompany}
              onLinkedinUrl={setLinkedinUrl}
            />
          )}

          {step === 4 && (
            <StepCompanies
              names={companyNames}
              onChange={setCompanyNames}
              persona={searchPersona}
              currentTitle={currentTitle}
              isPassive={isPassive}
              onTitle={setCurrentTitle}
            />
          )}

          {step === 5 && (
            <StepBriefingTime
              value={briefingTime}
              onChange={setBriefingTime}
            />
          )}

          {step === 6 && (
            <StepDone
              firstName={firstName}
              companies={companyNames.filter(n => n.trim())}
              briefingTime={briefingTime}
              isPassive={isPassive}
              intelContent={intelContent}
              intelLoading={intelLoading}
            />
          )}
        </div>

        {/* Nav row */}
        <div className="mt-10 flex items-center justify-between">
          {/* Back / skip */}
          <div className="flex items-center gap-4">
            {step > 0 && (
              <button
                type="button"
                onClick={() => goTo(prevStep())}
                className="text-[13px] text-slate-400 hover:text-slate-600 bg-transparent border-0 cursor-pointer p-0"
              >
                Back
              </button>
            )}
            <button
              type="submit"
              form="onboarding-form"
              formAction={skipOnboarding}
              className="text-[12px] text-slate-300 hover:text-slate-500 bg-transparent border-0 cursor-pointer p-0"
            >
              Skip setup
            </button>
            {step === 0 && (
              <button
                type="button"
                onClick={quickStart}
                className="text-[12px] text-slate-300 hover:text-slate-500 bg-transparent border-0 cursor-pointer p-0"
              >
                Quick start
              </button>
            )}
          </div>

          {/* Dots */}
          <div className="flex flex-col items-center gap-2">
            <Dots current={progressIndex()} total={advancedSetup ? STEP_COUNT : QUICK_PATH_STEP_COUNT} />
            <p className="text-[11px] text-slate-400">
              {step <= 1
                ? 'Fast path: launch your first watchlist in about a minute.'
                : step <= 4
                ? 'You are one step away from first value.'
                : 'Next: first briefing preview, then dashboard.'}
            </p>
          </div>

          {/* Next */}
          <div>
            {step === 0 && (
              <button
                type="button"
                onClick={() => { setAdvancedSetup(false); goTo(1) }}
                className="bg-orange-500 hover:bg-orange-600 text-white text-[14px] font-semibold px-6 py-2.5 rounded transition-colors cursor-pointer border-0"
              >
                Guided setup (under 10 minutes)
              </button>
            )}
            {step === 1 && (
              <div className="flex flex-col items-end gap-2">
                <button
                  type="button"
                  onClick={() => { setAdvancedSetup(false); advance() }}
                  disabled={!searchPersona}
                  className="bg-orange-500 hover:bg-orange-600 disabled:opacity-30 text-white text-[14px] font-semibold px-6 py-2.5 rounded transition-colors cursor-pointer border-0 disabled:cursor-not-allowed"
                >
                  Continue to watchlist
                </button>
                <button
                  type="button"
                  onClick={() => { setAdvancedSetup(true); goTo(2) }}
                  disabled={lowEnergyMode}
                  className="text-[12px] text-slate-400 hover:text-slate-600 bg-transparent border-0 cursor-pointer p-0"
                >
                  {lowEnergyMode ? 'Context optional in low-energy mode' : 'Add search context first'}
                </button>
              </div>
            )}
            {step === 2 && (
              <button
                type="button"
                onClick={advance}
                className="bg-orange-500 hover:bg-orange-600 text-white text-[14px] font-semibold px-6 py-2.5 rounded transition-colors cursor-pointer border-0"
              >
                Continue
              </button>
            )}
            {step === 3 && (
              <button
                type="button"
                onClick={advance}
                className="bg-orange-500 hover:bg-orange-600 text-white text-[14px] font-semibold px-6 py-2.5 rounded transition-colors cursor-pointer border-0"
              >
                Continue
              </button>
            )}
            {step === 4 && (
              <button
                type="button"
                onClick={advance}
                disabled={!companyNames.some(n => n.trim())}
                className="bg-orange-500 hover:bg-orange-600 disabled:opacity-30 text-white text-[14px] font-semibold px-6 py-2.5 rounded transition-colors cursor-pointer border-0 disabled:cursor-not-allowed"
              >
                Continue
              </button>
            )}
            {step === 5 && (
              <button
                type="button"
                onClick={advance}
                className="bg-orange-500 hover:bg-orange-600 text-white text-[14px] font-semibold px-6 py-2.5 rounded transition-colors cursor-pointer border-0"
              >
                Continue
              </button>
            )}
            {step === 6 && (
              <button
                type="submit"
                form="onboarding-form"
                className="bg-orange-500 hover:bg-orange-600 text-white text-[14px] font-semibold px-6 py-2.5 rounded transition-colors cursor-pointer border-0"
              >
                {isPassive ? 'Start monitoring' : 'Start my search'}
              </button>
            )}
          </div>
        </div>
      </div>

      <input
        ref={linkedinPdfRef}
        type="file"
        accept=".pdf"
        onChange={handleLinkedInPdf}
        aria-label="Upload LinkedIn PDF"
        className="hidden"
      />
      <HelpQuickButton source="onboarding" href="/dashboard/help" />
    </div>
  )
}

function StepCompanies({
  names,
  onChange,
  persona,
  currentTitle,
  isPassive,
  onTitle,
}: {
  names: string[]
  onChange: (v: string[]) => void
  persona: SearchPersona | ''
  currentTitle: string
  isPassive?: boolean
  onTitle?: (v: string) => void
}) {
  const suggestions = suggestionsForPersona(persona)
  const inputCls = 'w-full border border-slate-200 rounded-lg px-4 py-3 text-[15px] text-slate-900 placeholder:text-slate-300 focus:outline-none focus:border-slate-400 bg-white'
  const filled = names.filter(n => n.trim()).length

  const [discovering, setDiscovering] = useState(false)
  const [discovered, setDiscovered] = useState<{ name: string; sector: string; fit: number }[] | null>(null)
  const [discoverError, setDiscoverError] = useState(false)

  async function discover() {
    setDiscovering(true)
    setDiscoverError(false)
    try {
      const res = await fetch('/api/discover', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          context: {
            currentTitle: currentTitle || undefined,
            persona: persona || undefined,
          },
        }),
      })
      if (!res.ok) throw new Error()
      const data = await res.json()
      setDiscovered(Array.isArray(data) ? data.slice(0, 9) : [])
    } catch {
      setDiscoverError(true)
    } finally {
      setDiscovering(false)
    }
  }

  function update(i: number, val: string) {
    const next = [...names]
    next[i] = val
    if (i === names.length - 1 && val.trim() && names.length < 8) next.push('')
    onChange(next)
  }

  function addName(name: string) {
    if (names.some(n => n.trim().toLowerCase() === name.toLowerCase())) return
    const emptyIdx = names.findIndex(n => !n.trim())
    if (emptyIdx >= 0) {
      const next = [...names]
      next[emptyIdx] = name
      onChange(next)
    } else {
      onChange([...names, name])
    }
  }

  function removeName(name: string) {
    const next = names.filter(n => n.trim().toLowerCase() !== name.toLowerCase())
    if (!next.some(n => !n.trim())) next.push('')
    onChange(next)
  }

  return (
    <div className="flex flex-col gap-6">
      <div>
        <h1 className="text-[28px] font-bold text-slate-900 leading-tight mb-2">
          {isPassive ? 'Which companies do you want to monitor?' : 'Which companies are you targeting?'}
        </h1>
        <p className="text-[15px] text-slate-500">
          {isPassive
            ? 'We scan their career pages and alert you when something worth knowing appears.'
            : 'Add at least one. We scan their career pages and alert you when a matching role appears.'}
        </p>
      </div>

      {isPassive && onTitle && (
        <div>
          <label className="block text-[11px] font-bold tracking-[0.08em] uppercase text-slate-400 mb-1.5">
            Your current title
          </label>
          <input
            type="text"
            value={currentTitle}
            onChange={e => onTitle(e.target.value)}
            placeholder="Chief Information Officer"
            className={inputCls}
          />
        </div>
      )}

      <div className="flex flex-col gap-2.5">
        {names.map((name, i) => (
          <input
            key={i}
            type="text"
            value={name}
            onChange={e => update(i, e.target.value)}
            placeholder={i === 0 ? 'Company name' : i < 3 ? 'Add another' : 'Add more'}
            className={inputCls}
          />
        ))}
      </div>

      {suggestions.length > 0 && !discovered && (
        <div>
          <p className="text-[11px] font-bold tracking-[0.08em] uppercase text-slate-400 mb-2">Quick add</p>
          <div className="flex flex-wrap gap-2">
            {suggestions.map(s => {
              const added = names.some(n => n.trim().toLowerCase() === s.toLowerCase())
              return (
                <button
                  key={s}
                  type="button"
                  onClick={() => added ? removeName(s) : addName(s)}
                  className={`text-[13px] px-3 py-1.5 rounded border transition-colors cursor-pointer ${
                    added
                      ? 'border-slate-900 bg-slate-900 text-white hover:bg-slate-700 hover:border-slate-700'
                      : 'border-slate-200 bg-white text-slate-700 hover:border-slate-400'
                  }`}
                >
                  {added ? '✓ ' : '+ '}{s}
                </button>
              )
            })}
          </div>
        </div>
      )}

      {/* AI Discovery */}
      {!discovered && !discovering && (
        <button
          type="button"
          onClick={discover}
          className="text-[13px] text-slate-400 hover:text-slate-700 bg-transparent border-0 cursor-pointer p-0 text-left transition-colors"
        >
          {discoverError ? 'Could not load suggestions - try again →' : 'Not sure where to start? Discover companies with AI →'}
        </button>
      )}

      {discovering && (
        <p className="text-[13px] text-slate-400">Finding companies for you...</p>
      )}

      {discovered && discovered.length > 0 && (
        <div>
          <div className="flex items-center justify-between mb-2">
            <p className="text-[11px] font-bold tracking-[0.08em] uppercase text-slate-400">AI-suggested companies</p>
            <button
              type="button"
              onClick={() => { setDiscovered(null); setDiscoverError(false) }}
              className="text-[11px] text-slate-400 hover:text-slate-600 bg-transparent border-0 cursor-pointer p-0 transition-colors"
            >
              Clear
            </button>
          </div>
          <div className="flex flex-wrap gap-2">
            {discovered.map(co => {
              const added = names.some(n => n.trim().toLowerCase() === co.name.toLowerCase())
              return (
                <button
                  key={co.name}
                  type="button"
                  onClick={() => added ? removeName(co.name) : addName(co.name)}
                  className={`text-[13px] px-3 py-1.5 rounded border transition-colors cursor-pointer ${
                    added
                      ? 'border-slate-900 bg-slate-900 text-white hover:bg-slate-700 hover:border-slate-700'
                      : 'border-slate-200 bg-white text-slate-700 hover:border-slate-400'
                  }`}
                >
                  {added ? '✓ ' : '+ '}{co.name}
                </button>
              )
            })}
          </div>
        </div>
      )}

      <p className="text-[12px] text-slate-400">
        {filled === 0
          ? 'Add at least one company to continue.'
          : filled === 1
          ? 'Good start. Add 2 more for the best coverage.'
          : filled >= 3
          ? `${filled} companies added. You can add more after setup.`
          : `${filled} added. One more recommended.`}
      </p>
    </div>
  )
}

function StepBriefingTime({
  value,
  onChange,
}: {
  value: string
  onChange: (v: string) => void
}) {
  const TIMES = [
    { label: '6:00 AM', value: '06:00' },
    { label: '6:30 AM', value: '06:30' },
    { label: '7:00 AM', value: '07:00' },
    { label: '7:30 AM', value: '07:30' },
    { label: '8:00 AM', value: '08:00' },
    { label: '8:30 AM', value: '08:30' },
    { label: '9:00 AM', value: '09:00' },
  ]

  const tz = typeof window !== 'undefined'
    ? Intl.DateTimeFormat().resolvedOptions().timeZone
