                </button>
              </div>

              {analysisTab === 'notes' && (
                <>
                  <h3 className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-2">Meeting Notes Analyzer</h3>
                  <textarea
                    value={meetingNotes}
                    onChange={event => setMeetingNotes(event.target.value)}
                    rows={7}
                    className="w-full rounded border border-slate-300 px-3 py-2 text-[13px] text-slate-900 mb-3"
                    placeholder="Paste notes. Example: interviewer asked about scaling risk, board pressure on timeline, asked for 90-day plan..."
                  />
                  <button
                    type="button"
                    onClick={() => setMeetingAnalysis(analyzeMeetingNotes(meetingNotes))}
                    className="inline-flex min-h-[40px] items-center rounded border border-slate-900 bg-slate-900 px-3 py-2 text-[12px] font-semibold text-white"
                  >
                    Analyze notes
                  </button>

                  {meetingAnalysis && (
                    <div className="mt-4 space-y-3">
                      <article className="rounded border border-slate-200 bg-white p-3">
                        <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-1">Key Signals</p>
                        <ul className="space-y-1">
                          {meetingAnalysis.keySignals.map(item => <li key={item} className="text-[12px] text-slate-700">- {item}</li>)}
                        </ul>
                      </article>
                      <article className="rounded border border-slate-200 bg-white p-3">
                        <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-1">Likely Risks</p>
                        <ul className="space-y-1">
                          {meetingAnalysis.likelyRisks.map(item => <li key={item} className="text-[12px] text-slate-700">- {item}</li>)}
                        </ul>
                      </article>
                      <article className="rounded border border-slate-200 bg-white p-3">
                        <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-1">Follow-Ups</p>
                        <ul className="space-y-1">
                          {meetingAnalysis.followUps.map(item => <li key={item} className="text-[12px] text-slate-700">- {item}</li>)}
                        </ul>
                      </article>
                    </div>
                  )}
                </>
              )}

              {analysisTab === 'transcript' && (
                <>
                  <h3 className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-2">Transcription Consent and Integration</h3>
                  <p className="text-[12px] text-slate-600 mb-3">Choose a transcription service or paste transcripts directly. Consent is required before transcript analysis.</p>

                  <button
                    type="button"
                    onClick={() => setShowTranscriptionPanel(current => !current)}
                    className="mb-3 inline-flex min-h-[38px] items-center rounded border border-slate-300 bg-white px-3 py-2 text-[12px] font-semibold text-slate-700 hover:border-slate-400"
                  >
                    {showTranscriptionPanel ? 'Hide transcription setup' : 'Show transcription setup'}
                  </button>

                  {showTranscriptionPanel && (
                    <>
                      <div className="rounded border border-slate-200 bg-white p-3 mb-3">
                <label className="block text-[11px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-1.5">Jurisdiction</label>
                <input
                  value={jurisdiction}
                  onChange={event => setJurisdiction(event.target.value)}
                  className="w-full rounded border border-slate-300 px-3 py-2 text-[13px] text-slate-900 mb-2"
                  placeholder="State/Country where recording laws apply"
                />
                <label className="flex items-start gap-2 text-[12px] text-slate-700 mb-2">
                  <input type="checkbox" checked={consentChecked} onChange={event => setConsentChecked(event.target.checked)} className="mt-0.5" />
                  <span>I confirm I have lawful consent from relevant participants to transcribe and analyze this meeting content.</span>
                </label>
                <button
                  type="button"
                  onClick={() => {
                    void saveTranscriptionConsent()
                  }}
                  disabled={transcriptLoading}
                  className="inline-flex min-h-[40px] items-center rounded border border-slate-300 px-3 py-2 text-[12px] font-semibold text-slate-700 hover:border-slate-400 disabled:opacity-60"
                >
                  {transcriptLoading ? 'Saving...' : (consentSaved ? 'Consent saved' : 'Save consent')}
                </button>
              </div>

              <div className="rounded border border-slate-200 bg-white p-3 mb-3">
                <label className="block text-[11px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-1.5">Transcription provider</label>
                <select
                  value={provider}
                  onChange={event => setProvider(event.target.value as TranscriptionProvider)}
                  aria-label="Transcription provider"
                  title="Transcription provider"
                  className="w-full rounded border border-slate-300 px-3 py-2 text-[13px] text-slate-900 mb-2"
                >
                  <option value="otter">Otter</option>
                  <option value="fireflies">Fireflies</option>
                  <option value="fathom">Fathom</option>
                  <option value="grain">Grain</option>
                  <option value="gong">Gong</option>
                  <option value="other">Other</option>
                </select>
                <input
                  value={connectionLabel}
                  onChange={event => setConnectionLabel(event.target.value)}
                  className="w-full rounded border border-slate-300 px-3 py-2 text-[13px] text-slate-900 mb-2"
                  placeholder="Connection label (optional)"
                />
                <button
                  type="button"
                  onClick={() => {
                    void connectProvider()
                  }}
                  disabled={providerLoading}
                  className="inline-flex min-h-[40px] items-center rounded border border-slate-300 px-3 py-2 text-[12px] font-semibold text-slate-700 hover:border-slate-400 disabled:opacity-60"
                >
                  {providerLoading ? 'Connecting...' : 'Connect provider (placeholder)'}
                </button>
                {providerMessage && <p className="text-[11px] text-emerald-700 mt-2">{providerMessage}</p>}
                {providerConnections.length > 0 && (
                  <div className="mt-3 space-y-1">
                    {providerConnections.slice(0, 5).map(connection => (
                      <p key={connection.id} className="text-[11px] text-slate-600">{connection.provider} · {connection.connection_label ?? 'No label'} · {connection.status}</p>
                    ))}
                  </div>
                )}

                <div className="mt-3 rounded border border-slate-200 bg-white p-3">
                  <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-2">Verified next steps ({provider})</p>
                  <ul className="space-y-1.5">
                    {providerSteps.map(step => (
                      <li key={step} className="text-[11px] text-slate-700">- {step}</li>
                    ))}
                  </ul>
                </div>
              </div>

              <div className="rounded border border-slate-200 bg-white p-3">
                <label className="block text-[11px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-1.5">Transcript title (optional)</label>
                <input
                  value={transcriptTitle}
                  onChange={event => setTranscriptTitle(event.target.value)}
                  className="w-full rounded border border-slate-300 px-3 py-2 text-[13px] text-slate-900 mb-2"
                  placeholder="Hiring manager interview - round 2"
                />
                <label className="block text-[11px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-1.5">Paste transcript</label>
                <textarea
                  value={transcriptText}
                  onChange={event => setTranscriptText(event.target.value)}
                  rows={6}
                  className="w-full rounded border border-slate-300 px-3 py-2 text-[13px] text-slate-900 mb-2"
                  placeholder="Paste raw transcript text here."
                />
                <label className="block text-[11px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-1.5">Notes (optional)</label>
                <textarea
                  value={transcriptNotes}
                  onChange={event => setTranscriptNotes(event.target.value)}
                  rows={3}
                  className="w-full rounded border border-slate-300 px-3 py-2 text-[13px] text-slate-900 mb-2"
                  placeholder="Paste additional notes or context."
                />
                <button
                  type="button"
                  onClick={() => {
                    void ingestTranscript()
                  }}
                  disabled={transcriptLoading}
                  className="inline-flex min-h-[40px] items-center rounded border border-slate-900 bg-slate-900 px-3 py-2 text-[12px] font-semibold text-white disabled:opacity-60"
                >
                  {transcriptLoading ? 'Saving...' : 'Save and analyze transcript'}
                </button>
                {transcriptError && <p className="text-[11px] text-red-600 mt-2">{transcriptError}</p>}

                {transcriptAnalysis && (
                  <div className="mt-3 space-y-2 rounded border border-slate-200 bg-white p-3">
                    <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-500">Transcript Analysis</p>
                    <p className="text-[11px] text-slate-600">Signals: {transcriptAnalysis.keySignals.length} · Follow-ups: {transcriptAnalysis.followUps.length} · Questions: {transcriptAnalysis.potentialQuestions.length}</p>
                    <p className="text-[11px] text-slate-700">Risk language: {transcriptAnalysis.summary.hasRiskLanguage ? 'yes' : 'no'} · Decision language: {transcriptAnalysis.summary.hasDecisionLanguage ? 'yes' : 'no'} · Timeline language: {transcriptAnalysis.summary.hasTimelineLanguage ? 'yes' : 'no'}</p>
                  </div>
                )}
              </div>
                    </>
                  )}
                </>
              )}
            </div>
          </div>
        </section>

        {protocolSessions.length > 0 && (
          <section className="bg-white border border-slate-200 rounded-xl p-5 sm:p-6">
            <h2 className="text-[12px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-3">Saved Grill Me Sessions</h2>
            <div className="space-y-2">
              {protocolSessions.slice(0, 8).map(session => (
                <button
                  key={session.id}
                  type="button"
                  onClick={() => {
                    setProtocolSession(session)
                    setLastConfirmation(session.last_confirmation ?? '')
                  }}
                  className="w-full rounded border border-slate-200 bg-slate-50 px-3 py-2 text-left hover:border-slate-300"
                >
                  <p className="text-[12px] font-semibold text-slate-900">{session.topic}</p>
                  <p className="text-[11px] text-slate-600">{session.current_question_id} · entries {session.entries_count} · open flags {session.open_flags_count}</p>
                </button>
              ))}
            </div>
          </section>
        )}

        <footer className="mt-6 rounded-xl border border-slate-800 bg-slate-900 px-6 py-6 text-slate-300">
          <div className="flex flex-wrap items-center justify-between gap-4 mb-4">
            <p className="text-[11px] font-bold tracking-[0.16em] uppercase">
              <span className="text-white">Starting </span><span className="text-orange-400">Monday</span>
            </p>
            <div className="flex flex-wrap gap-4 text-[12px]">
              <Link href="/privacy" className="text-slate-400 hover:text-white">Privacy policy</Link>
              <Link href="/method-and-evidence" className="text-slate-400 hover:text-white">Method and evidence</Link>
              <Link href="/evidence-room" className="text-slate-400 hover:text-white">Evidence room</Link>
              <Link href="/dashboard" className="text-slate-400 hover:text-white">Dashboard</Link>
              <Link href="/login" className="text-slate-400 hover:text-white">Sign in</Link>
            </div>
          </div>
          <p className="text-[12px] text-slate-400">Private by default. Built for disciplined executive search execution with early signal and low-noise workflows.</p>
          <p className="text-[12px] text-slate-500 mt-2">© 2026 Starting Monday. All rights reserved.</p>
        </footer>
      </main>
    </div>
  )
}

'use client'
import { useEffect, useRef, useState, useTransition, type KeyboardEvent as ReactKeyboardEvent } from 'react'
import Link from 'next/link'
import { rateTrace } from './actions'
import { buildFailureSummaryPayload } from './copy-summary'
import { resolveNextActiveRowId } from './active-row'
import {
  buildUrl,
  composeEvalNotes,
  FEATURE_LABELS,
  FEATURES,
  FAILURE_CATEGORIES,
  parseEvalNotes,
  type BulkApplyUndoChange,
  type LastActionState,
  type ToastState,
  type Trace,
} from './trace-shared'

function TraceRow({
  trace,
  enableShortcuts,
  shortcutsBlocked,
  denseMode,
  rowRef,
  onActivate,
  onRated,
}: {
  trace: Trace
  enableShortcuts: boolean
  shortcutsBlocked?: boolean
  denseMode: boolean
  rowRef?: (element: HTMLDivElement | null) => void
  onActivate?: (traceId: string) => void
  onRated?: (traceId: string, prevPass: boolean | null, nextPass: boolean | null, categories: string[]) => void
}) {
  const parsedNotes = parseEvalNotes(trace.eval_notes)
  const [evalPass, setEvalPass]   = useState(trace.eval_pass)
  const [evalNotesBody, setEvalNotesBody] = useState(parsedNotes.body)
  const [categories, setCategories] = useState(parsedNotes.categories)
  const [expanded, setExpanded]   = useState(false)
  const [, startTransition]       = useTransition()

  function persist(nextPass: boolean | null, nextNotesBody: string, nextCategories: string[]) {
    const nextNotes = composeEvalNotes(nextNotesBody, nextCategories)
    startTransition(async () => { await rateTrace(trace.id, nextPass, nextNotes) })
  }

  function setRating(nextPass: boolean | null) {
    const prevPass = evalPass
    setEvalPass(nextPass)
    persist(nextPass, evalNotesBody, categories)
    onRated?.(trace.id, prevPass, nextPass, categories)
  }

  function toggleCategory(category: string) {
    const nextCategories = categories.includes(category)
      ? categories.filter((item) => item !== category)
      : [...categories, category]

    setCategories(nextCategories)
    persist(evalPass, evalNotesBody, nextCategories)
    if (evalPass === false) {
      onRated?.(trace.id, false, false, nextCategories)
    }
  }

  function saveNotes() {
    persist(evalPass, evalNotesBody, categories)
  }

  useEffect(() => {
    if (!enableShortcuts || shortcutsBlocked) return

    function onKeyDown(event: KeyboardEvent) {
      const target = event.target as HTMLElement | null
      if (target) {
        const tagName = target.tagName.toLowerCase()
        if (tagName === 'textarea' || tagName === 'input' || tagName === 'select' || target.isContentEditable) return
      }

      if (event.key.toLowerCase() === 'p') {
        event.preventDefault()
        setRating(true)
      } else if (event.key.toLowerCase() === 'f') {
        event.preventDefault()
        setRating(false)
      } else if (event.key.toLowerCase() === 'u') {
        event.preventDefault()
        setRating(null)
      } else if (event.key.toLowerCase() === 'o') {
        event.preventDefault()
        setExpanded((value) => !value)
      } else if (/^[1-8]$/.test(event.key) && evalPass === false) {
        event.preventDefault()
        const idx = Number(event.key) - 1
        const category = FAILURE_CATEGORIES[idx]
        if (category) {
          toggleCategory(category)
        }
      }
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
  }, [enableShortcuts, shortcutsBlocked, evalNotesBody, categories, evalPass])

  const tokens = (trace.prompt_tokens ?? 0) + (trace.completion_tokens ?? 0)
  const dateStr = new Date(trace.created_at).toLocaleString('en-US', {
    month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit',
  })

  const featureLabel = FEATURE_LABELS[trace.feature] ?? trace.feature.replace(/_/g, ' ')

  return (
    <div
      ref={rowRef}
      className={`border-b border-slate-100 ${evalPass === true ? 'bg-emerald-50/30' : evalPass === false ? 'bg-red-50/30' : ''} ${enableShortcuts ? 'ring-1 ring-slate-300 ring-inset' : ''}`}
      onMouseDown={() => onActivate?.(trace.id)}
    >
      <div className="px-5 py-4 flex items-start gap-4">

        {/* Pass / Fail column */}
        <div className="flex flex-col gap-1.5 shrink-0 pt-0.5">
          <button
            type="button"
            onClick={() => setRating(evalPass === true ? null : true)}
            aria-keyshortcuts="P"
            className={`px-3 py-1.5 rounded text-[12px] font-bold cursor-pointer border-0 transition-colors w-14 ${
              evalPass === true
                ? 'bg-emerald-500 text-white'
                : 'bg-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-700'
            }`}
          >
            Pass
          </button>
          <button
            type="button"
            onClick={() => setRating(evalPass === false ? null : false)}
            aria-keyshortcuts="F"
            className={`px-3 py-1.5 rounded text-[12px] font-bold cursor-pointer border-0 transition-colors w-14 ${
              evalPass === false
                ? 'bg-red-500 text-white'
                : 'bg-slate-100 text-slate-400 hover:bg-red-50 hover:text-red-700'
            }`}
          >
            Fail
          </button>
        </div>

        {/* Content column */}
        <div className="flex-1 min-w-0">

          {/* Metadata row */}
          <div className="flex items-center gap-3 flex-wrap mb-2.5">
            <span className="text-[11px] font-bold tracking-[0.08em] uppercase text-slate-600">
              {featureLabel}
            </span>
            {enableShortcuts && (
              <span className="text-[10px] font-bold tracking-[0.08em] uppercase text-slate-700 bg-slate-200 px-2 py-0.5 rounded">
                Active
              </span>
            )}
            <span className="text-[11px] text-slate-400">{dateStr}</span>
            {trace.latency_ms != null && (
              <span className="text-[11px] text-slate-300">{(trace.latency_ms / 1000).toFixed(1)}s</span>
            )}
            {tokens > 0 && (
              <span className="text-[11px] text-slate-300">{tokens.toLocaleString()} tok</span>
            )}
            {trace.user_id && (
              <span className="text-[11px] font-mono text-slate-200">{trace.user_id.slice(0, 8)}</span>
            )}
          </div>

          {/* Input snapshot */}
          {!denseMode && trace.input_snapshot && Object.keys(trace.input_snapshot).length > 0 && (
            <div className="mb-2 flex flex-wrap gap-x-4 gap-y-0.5">
              {Object.entries(trace.input_snapshot).map(([k, v]) => (
                <span key={k} className="text-[11px] font-mono text-slate-300">
                  {k}: <span className="text-slate-400">{String(v)}</span>
                </span>
              ))}
            </div>
          )}

          {/* Output snapshot */}
          {trace.output_snapshot && (
            <div className="mb-3">
          const [focusMode, setFocusMode] = useState(false)
              <button
                type="button"
                onClick={() => setExpanded(v => !v)}
                aria-keyshortcuts="O"
                className="text-[11px] text-slate-400 hover:text-slate-600 bg-transparent border-0 cursor-pointer p-0 mb-1.5"
              >
                Output {expanded ? '▲' : '▼'}
              </button>
              {expanded ? (
                <pre className="text-[12px] text-slate-700 whitespace-pre-wrap leading-relaxed bg-white border border-slate-100 rounded p-3 max-h-[500px] overflow-y-auto">
                  {trace.output_snapshot}
                </pre>
              ) : !denseMode ? (
                <p className="text-[12px] text-slate-600 leading-relaxed">
                  {trace.output_snapshot.slice(0, 220)}{trace.output_snapshot.length > 220 ? '…' : ''}
                </p>
              ) : (
                <p className="text-[11px] text-slate-400">Collapsed in dense mode. Expand output when needed.</p>
              )}
            </div>
          )}

          {/* Notes */}
          <div className="mb-2 flex flex-wrap items-center gap-1.5">
            {FAILURE_CATEGORIES.map((category, idx) => {
              const active = categories.includes(category)
              return (
                <button
                  key={category}
                  type="button"
                  onClick={() => toggleCategory(category)}
                  aria-keyshortcuts={String(idx + 1)}
                  className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                    active
                      ? 'bg-slate-900 text-white border-slate-900'
                      : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
                  }`}
                >
                  <span className="mr-1 font-semibold">{idx + 1}</span>{category}
                </button>
              )
            })}
          </div>

          <textarea
            value={evalNotesBody}
            onChange={e => setEvalNotesBody(e.target.value)}
            onBlur={saveNotes}
            placeholder="Open coding: what is wrong (or strong) about this output?"
            rows={denseMode ? 1 : 2}
            className="w-full text-[12px] text-slate-700 border border-slate-200 rounded px-3 py-2 placeholder:text-slate-300 focus:outline-none focus:border-slate-400 resize-none bg-white"
          />
          <p className="mt-1.5 text-[10px] text-slate-400">Shortcuts: P = pass, F = fail, U = unrated, O = output, J/K = active row, 1-8 = fail tags.</p>
        </div>
      </div>
    </div>
  )
}

export function TraceViewer({
  traces,
  currentFeature,
  unratedOnly,
  page,
  totalPages,
  totalCount,
}: {
  traces: Trace[]
  currentFeature: string
  unratedOnly: boolean
  page: number
  totalPages: number
  totalCount: number
}) {
  const [visibleTraces, setVisibleTraces] = useState(traces)
  const [sessionLabeled, setSessionLabeled] = useState<Record<string, boolean>>({})
  const [sessionFailureTagsByTrace, setSessionFailureTagsByTrace] = useState<Record<string, string[]>>({})
  const [failureSummaryMode, setFailureSummaryMode] = useState<'page' | 'session'>('page')
  const [isApplyingTopTag, setIsApplyingTopTag] = useState(false)
  const [isUndoingTopTag, setIsUndoingTopTag] = useState(false)
  const [lastBulkApply, setLastBulkApply] = useState<{ tag: string; changes: BulkApplyUndoChange[] } | null>(null)
  const [toast, setToast] = useState<ToastState | null>(null)
  const [lastAction, setLastAction] = useState<LastActionState | null>(null)
  const [includeZeroCountsInCopy, setIncludeZeroCountsInCopy] = useState(false)
  const [copyFormat, setCopyFormat] = useState<'list' | 'table'>('list')
  const [showCopyPreview, setShowCopyPreview] = useState(false)
  const [trimForSlack, setTrimForSlack] = useState(false)
  const [showCopyActions, setShowCopyActions] = useState(false)
  const [copyMenuAnnouncement, setCopyMenuAnnouncement] = useState('')
  const [activeRowId, setActiveRowId] = useState<string | null>(traces[0]?.id ?? null)
  const copyActionsRef = useRef<HTMLDivElement | null>(null)
  const rowRefs = useRef<Record<string, HTMLDivElement | null>>({})
  const copyActionsToggleRef = useRef<HTMLButtonElement | null>(null)
  const copyActionItemRefs = useRef<Array<HTMLButtonElement | null>>([])
  const focusMode = unratedOnly && currentFeature === 'prep_brief'
  const [denseMode, setDenseMode] = useState(focusMode)

  useEffect(() => {
    setVisibleTraces(traces)
    setActiveRowId(traces[0]?.id ?? null)
  }, [traces])

  useEffect(() => {
    if (visibleTraces.length === 0) {
      setActiveRowId(null)
      return
    }

    if (activeRowId && visibleTraces.some((trace) => trace.id === activeRowId)) {
      return
    }

    setActiveRowId(visibleTraces[0]?.id ?? null)
  }, [visibleTraces, activeRowId])

  useEffect(() => {
    setSessionLabeled({})
    setSessionFailureTagsByTrace({})
    setFailureSummaryMode('page')
    setIncludeZeroCountsInCopy(false)
    setCopyFormat('list')
    setShowCopyPreview(false)
    setShowCopyActions(false)
    setTrimForSlack(false)
    setLastBulkApply(null)
    setLastAction(null)
  }, [currentFeature, unratedOnly, page])

  useEffect(() => {
    setDenseMode(focusMode)
  }, [focusMode])

  useEffect(() => {
    if (!focusMode || !activeRowId) return
    const rowElement = rowRefs.current[activeRowId]
    if (!rowElement) return
    rowElement.scrollIntoView({ block: 'nearest', behavior: 'smooth' })
  }, [focusMode, activeRowId])

  useEffect(() => {
    if (visibleTraces.length === 0) return

    function onKeyDown(event: KeyboardEvent) {
      if (showCopyActions) return

      const target = event.target as HTMLElement | null
      if (target) {
        const tagName = target.tagName.toLowerCase()
        if (tagName === 'textarea' || tagName === 'input' || tagName === 'select' || target.isContentEditable) return
      }

      if (event.metaKey || event.ctrlKey || event.altKey) return

      const key = event.key.toLowerCase()
      if (key === 'a' && !isApplyingTopTag) {
        event.preventDefault()
        void applyTopTagToUntaggedFails()
        return
      }
      if (key === 'z' && lastBulkApply && !isUndoingTopTag) {
        event.preventDefault()
        void undoLastBulkApplyTopTag()
        return
      }
      if (key === 'd' && focusMode) {
        event.preventDefault()
        setDenseMode((value) => !value)
        return
      }
      if (key === 'g') {
        event.preventDefault()
        const nextIndex = event.shiftKey ? visibleTraces.length - 1 : 0
        setActiveRowId(visibleTraces[nextIndex]?.id ?? null)
        return
      }
      if (key !== 'j' && key !== 'k') return

      event.preventDefault()
      const currentIndex = activeRowId
        ? visibleTraces.findIndex((trace) => trace.id === activeRowId)
        : -1
      const safeIndex = currentIndex >= 0 ? currentIndex : 0
      const delta = key === 'j' ? 1 : -1
      const nextIndex = Math.max(0, Math.min(visibleTraces.length - 1, safeIndex + delta))
      setActiveRowId(visibleTraces[nextIndex]?.id ?? null)
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
  }, [
    visibleTraces,
    activeRowId,
    showCopyActions,
    isApplyingTopTag,
    lastBulkApply,
    isUndoingTopTag,
    focusMode,
  ])

  useEffect(() => {
    if (!showCopyActions) return

    const focusTimeout = window.setTimeout(() => {
      copyActionItemRefs.current[0]?.focus()
    }, 0)

    function onDocumentMouseDown(event: MouseEvent) {
      const target = event.target as Node | null
      if (!target) return
      if (copyActionsRef.current?.contains(target)) return
      setShowCopyActions(false)
    }

    function onDocumentKeyDown(event: KeyboardEvent) {
      if (event.key === 'Escape') {
        setShowCopyActions(false)
      }
    }

    document.addEventListener('mousedown', onDocumentMouseDown)
    document.addEventListener('keydown', onDocumentKeyDown)

    return () => {
      window.clearTimeout(focusTimeout)
      document.removeEventListener('mousedown', onDocumentMouseDown)
      document.removeEventListener('keydown', onDocumentKeyDown)
    }
  }, [showCopyActions])

  useEffect(() => {
    if (showCopyActions) {
      setCopyMenuAnnouncement('Copy actions menu opened. Use arrow keys or tab to navigate, enter to select, and escape to close.')
    } else {
      setCopyMenuAnnouncement('Copy actions menu closed.')
    }
  }, [showCopyActions])

  function focusCopyActionByIndex(index: number) {
    const buttons = copyActionItemRefs.current.filter(Boolean)
    if (buttons.length === 0) return
    const next = ((index % buttons.length) + buttons.length) % buttons.length
    buttons[next]?.focus()
  }

  function onCopyActionKeyDown(event: ReactKeyboardEvent<HTMLButtonElement>, index: number) {
    const key = event.key.toLowerCase()
    if (key === 's' || key === '1') {
      event.preventDefault()
      setShowCopyActions(false)
      void copyFailureSummary()
      return
    }
    if (key === 'c' || key === '2') {
      event.preventDefault()
      setShowCopyActions(false)
      void copyCompactSummary()
      return
    }
    if (key === 't' || key === '3') {
      event.preventDefault()
      setShowCopyActions(false)
      void copyCompactSummaryTable()
      return
    }

    if (event.key === 'ArrowDown') {
      event.preventDefault()
      focusCopyActionByIndex(index + 1)
    } else if (event.key === 'ArrowUp') {
      event.preventDefault()
      focusCopyActionByIndex(index - 1)
    } else if (event.key === 'Tab') {
      event.preventDefault()
      focusCopyActionByIndex(event.shiftKey ? index - 1 : index + 1)
    } else if (event.key === 'Home') {
      event.preventDefault()
      focusCopyActionByIndex(0)
    } else if (event.key === 'End') {
      event.preventDefault()
      focusCopyActionByIndex(copyActionItemRefs.current.length - 1)
    } else if (event.key === 'Escape') {
      event.preventDefault()
      setShowCopyActions(false)
      copyActionsToggleRef.current?.focus()
    }
  }

  function onCopyActionsTriggerKeyDown(event: ReactKeyboardEvent<HTMLButtonElement>) {
    if (event.key === 'ArrowDown') {
      event.preventDefault()
      setShowCopyActions(true)
      window.setTimeout(() => focusCopyActionByIndex(0), 0)
    } else if (event.key === 'ArrowUp') {
      event.preventDefault()
      setShowCopyActions(true)
      window.setTimeout(() => focusCopyActionByIndex(copyActionItemRefs.current.length - 1), 0)
    } else if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault()
      setShowCopyActions((value) => !value)
    } else if (event.key === 'Escape') {
      if (showCopyActions) {
        event.preventDefault()
        setShowCopyActions(false)
      }
    }
  }

  useEffect(() => {
    if (!toast) return
    const timeout = window.setTimeout(() => setToast(null), 1800)
    return () => window.clearTimeout(timeout)
  }, [toast])

  function handleRated(traceId: string, prevPass: boolean | null, nextPass: boolean | null, categories: string[]) {
    setSessionLabeled((prev) => {
      const next = { ...prev }
      const wasCounted = Object.prototype.hasOwnProperty.call(next, traceId)

      if (prevPass === null && nextPass !== null) {
        next[traceId] = nextPass
      } else if (nextPass === null && wasCounted) {
        delete next[traceId]
      } else if (nextPass !== null && wasCounted) {
        next[traceId] = nextPass
      }

      return next
    })

    setSessionFailureTagsByTrace((prev) => {
      const next = { ...prev }
      if (nextPass === false) {
        next[traceId] = [...new Set(categories)]
      } else {
        delete next[traceId]
      }
      return next
    })

    if (!unratedOnly || nextPass === null) return

    const nextActiveRowId = resolveNextActiveRowId(visibleTraces, traceId, activeRowId)
    const nextVisible = visibleTraces.filter((trace) => trace.id !== traceId)
    setVisibleTraces(nextVisible)
    setActiveRowId(nextActiveRowId)
  }

  const sessionTotal = Object.keys(sessionLabeled).length
  const sessionPass = Object.values(sessionLabeled).filter(Boolean).length
  const sessionFail = sessionTotal - sessionPass
  const pageFailureCategoryCounts = visibleTraces.reduce<Record<string, number>>((acc, trace) => {
    if (trace.eval_pass !== false) return acc
    const { categories } = parseEvalNotes(trace.eval_notes)
    for (const category of categories) {
      acc[category] = (acc[category] ?? 0) + 1
    }
    return acc
  }, {})
  const pageFailureCategoryRows = Object.entries(pageFailureCategoryCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 8)
  const sessionFailureCategoryCounts = Object.values(sessionFailureTagsByTrace).reduce<Record<string, number>>((acc, tags) => {
    for (const tag of tags) {
      acc[tag] = (acc[tag] ?? 0) + 1
    }
    return acc
  }, {})
  const sessionFailureCategoryRows = Object.entries(sessionFailureCategoryCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 8)
  const summaryRows = failureSummaryMode === 'session' ? sessionFailureCategoryRows : pageFailureCategoryRows
  const topFailureTheme = summaryRows[0] ?? null
  const modeLabel = failureSummaryMode === 'session' ? 'session' : 'current page'
  const sourceCounts = failureSummaryMode === 'session' ? sessionFailureCategoryCounts : pageFailureCategoryCounts
  const allKnownTags = [...new Set([...FAILURE_CATEGORIES, ...Object.keys(sourceCounts)])]
  const rowsForCopy = includeZeroCountsInCopy
    ? allKnownTags
        .map((tag) => [tag, sourceCounts[tag] ?? 0] as const)
        .sort((a, b) => b[1] - a[1])
    : summaryRows
  const rowsForCopySlack = trimForSlack ? rowsForCopy.slice(0, 6) : rowsForCopy
  const rowsOmittedForSlack = Math.max(0, rowsForCopy.length - rowsForCopySlack.length)
  const untaggedFailedTraces = visibleTraces.filter((trace) => {
    if (trace.eval_pass !== false) return false
    return parseEvalNotes(trace.eval_notes).categories.length === 0
  })
  const activeRowIndex = activeRowId
    ? visibleTraces.findIndex((trace) => trace.id === activeRowId)
    : -1

  const copyPreviewPayload = summaryRows.length > 0
    ? buildFailureSummaryPayload(rowsForCopy, {
      modeLabel,
      includeZeroCounts: includeZeroCountsInCopy,
      trimForSlack,
      copyFormat,
      topFailureTheme,
    })
    : ''
  const copyPreviewChars = copyPreviewPayload.length
  const copyPreviewLines = copyPreviewPayload.length > 0 ? copyPreviewPayload.split('\n').length : 0
  const slackCharLimit = 4000
  const githubCommentCharLimit = 65000
  const fitsSlack = copyPreviewChars <= slackCharLimit
  const fitsGithubComment = copyPreviewChars <= githubCommentCharLimit
  const shouldSuggestTrimForSlack = !fitsSlack && !trimForSlack

  async function applyTopTagToUntaggedFails() {
    if (!topFailureTheme || untaggedFailedTraces.length === 0 || isApplyingTopTag) return

    const topTag = topFailureTheme[0]
    const snapshotById = Object.fromEntries(visibleTraces.map((trace) => [trace.id, trace]))
    const changes: BulkApplyUndoChange[] = untaggedFailedTraces.map((trace) => ({
      traceId: trace.id,
      prevNotes: snapshotById[trace.id]?.eval_notes ?? null,
      prevSessionTags: sessionFailureTagsByTrace[trace.id],
    }))

    setIsApplyingTopTag(true)
    try {
      for (const trace of untaggedFailedTraces) {
        const parsed = parseEvalNotes(trace.eval_notes)
        const nextCategories = [...new Set([...parsed.categories, topTag])]
        const nextNotes = composeEvalNotes(parsed.body, nextCategories)

        const result = await rateTrace(trace.id, false, nextNotes)
        if (!result.ok) throw new Error('save failed')

        setVisibleTraces((prev) => prev.map((row) => (
          row.id === trace.id
            ? { ...row, eval_notes: nextNotes }
            : row
        )))

        setSessionFailureTagsByTrace((prev) => ({
          ...prev,
          [trace.id]: nextCategories,
        }))
      }

      if (changes.length > 0) {
        setLastBulkApply({ tag: topTag, changes })
        setToast({ kind: 'success', message: `Applied ${topTag} to ${changes.length} trace${changes.length === 1 ? '' : 's'}.` })
        setLastAction({
          message: `Applied ${topTag} to ${changes.length} trace${changes.length === 1 ? '' : 's'}`,
          at: new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }),
        })
      }
    } catch {
      setToast({ kind: 'error', message: 'Could not apply top tag. Try again.' })
    } finally {
      setIsApplyingTopTag(false)
    }
  }

  async function undoLastBulkApplyTopTag() {
    if (!lastBulkApply || isUndoingTopTag) return

    const undoCount = lastBulkApply.changes.length
    setIsUndoingTopTag(true)
    try {
      for (const change of lastBulkApply.changes) {
        const restoredNotes = change.prevNotes ?? ''
        const result = await rateTrace(change.traceId, false, restoredNotes)
        if (!result.ok) throw new Error('undo failed')

        setVisibleTraces((prev) => prev.map((row) => (
          row.id === change.traceId
            ? { ...row, eval_notes: change.prevNotes }
            : row
        )))

        setSessionFailureTagsByTrace((prev) => {
          const next = { ...prev }
          if (change.prevSessionTags === undefined) {
            delete next[change.traceId]
          } else {
            next[change.traceId] = change.prevSessionTags
          }
          return next
        })
      }

      setLastBulkApply(null)
      setToast({ kind: 'success', message: `Undid bulk tag on ${undoCount} trace${undoCount === 1 ? '' : 's'}.` })
      setLastAction({
        message: `Undid bulk tag on ${undoCount} trace${undoCount === 1 ? '' : 's'}`,
        at: new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }),
      })
    } catch {
      setToast({ kind: 'error', message: 'Could not undo bulk tag. Try again.' })
    } finally {
      setIsUndoingTopTag(false)
    }
  }

  async function copyTopTheme() {
    if (!topFailureTheme) return
    try {
      await navigator.clipboard.writeText(topFailureTheme[0])
      setToast({ kind: 'success', message: `Copied top theme: ${topFailureTheme[0]}` })
      setLastAction({
        message: `Copied top theme ${topFailureTheme[0]}`,
        at: new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }),
      })
    } catch {
      setToast({ kind: 'error', message: 'Could not copy top theme.' })
    }
  }

  async function copyFailureSummary() {
    if (summaryRows.length === 0) return
    const payload = copyPreviewPayload

    try {
      await navigator.clipboard.writeText(payload)
      setToast({ kind: 'success', message: `Copied ${modeLabel} failure summary.` })
      setLastAction({
        message: `Copied ${modeLabel} failure summary (${copyFormat})`,
        at: new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }),
      })
    } catch {
      setToast({ kind: 'error', message: 'Could not copy failure summary.' })
    }
  }

  async function copyCompactSummary() {
    if (summaryRows.length === 0) return

    const compactRows = summaryRows.slice(0, 6)
    const omitted = Math.max(0, summaryRows.length - compactRows.length)
    const lines = [
      `Failure tags (${modeLabel}, compact)`,
      ...compactRows.map(([tag, count]) => `- ${tag}: ${count}`),
    ]

    if (omitted > 0) {
      lines.push(`(${omitted} additional tag${omitted === 1 ? '' : 's'} omitted)`)
    }

    if (topFailureTheme) {
      lines.push(`Top theme: ${topFailureTheme[0]} (${topFailureTheme[1]})`)
    }

    const payload = lines.join('\n')

    try {
      await navigator.clipboard.writeText(payload)
      setToast({ kind: 'success', message: `Copied compact ${modeLabel} summary.` })
      setLastAction({
        message: `Copied compact ${modeLabel} summary`,
        at: new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }),
      })
    } catch {
      setToast({ kind: 'error', message: 'Could not copy compact summary.' })
    }
  }

  async function copyCompactSummaryTable() {
    if (summaryRows.length === 0) return

    const compactRows = summaryRows.slice(0, 6)
    const omitted = Math.max(0, summaryRows.length - compactRows.length)
    const lines = [
      `Failure tags (${modeLabel}, compact table)`,
      '',
      '| Tag | Count |',
      '| --- | ---: |',
      ...compactRows.map(([tag, count]) => `| ${tag} | ${count} |`),
    ]

    if (omitted > 0) {
      lines.push('', `(${omitted} additional tag${omitted === 1 ? '' : 's'} omitted)`)
    }

    if (topFailureTheme) {
      lines.push('', `Top theme: **${topFailureTheme[0]}** (${topFailureTheme[1]})`)
    }

    const payload = lines.join('\n')

    try {
      await navigator.clipboard.writeText(payload)
      setToast({ kind: 'success', message: `Copied compact table ${modeLabel} summary.` })
      setLastAction({
        message: `Copied compact table ${modeLabel} summary`,
        at: new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }),
      })
    } catch {
      setToast({ kind: 'error', message: 'Could not copy compact table summary.' })
    }
  }

  return (
    <>
      <div aria-live="polite" className="sr-only">{copyMenuAnnouncement}</div>

      {toast && (
        <div className={`mb-4 rounded border px-3 py-2 text-[11px] ${toast.kind === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800' : 'bg-red-50 border-red-200 text-red-700'}`}>
          {toast.message}
        </div>
      )}

      {/* Filter bar */}
      <div className="flex flex-wrap items-center gap-3 mb-5">
        {FEATURES.map(f => (
          <Link
            key={f}
            href={buildUrl({ feature: f || undefined, unrated: unratedOnly ? '1' : undefined })}
            className={`text-[12px] font-semibold px-3 py-1.5 rounded transition-colors ${
              currentFeature === f
                ? 'bg-slate-900 text-white'
                : 'bg-white border border-slate-200 text-slate-600 hover:border-slate-400'
            }`}
          >
            {FEATURE_LABELS[f]}
          </Link>
        ))}
        <div className="ml-auto">
          <Link
            href={buildUrl({ feature: currentFeature || undefined, unrated: unratedOnly ? undefined : '1' })}
            className={`text-[12px] font-semibold px-3 py-1.5 rounded transition-colors ${
              unratedOnly
                ? 'bg-amber-500 text-white'
                : 'bg-white border border-slate-200 text-slate-600 hover:border-slate-400'
            }`}
          >
            Unrated only
          </Link>
        </div>
      </div>

      <div className="mb-4 bg-white border border-slate-200 rounded px-3 py-2 flex flex-wrap items-center gap-x-4 gap-y-1 text-[11px] text-slate-500">
        <span className="font-semibold text-slate-700">Session labeled: {sessionTotal}</span>
        <span>Pass: {sessionPass}</span>
        <span>Fail: {sessionFail}</span>
        {focusMode && activeRowIndex >= 0 && (
          <span className="text-slate-600">Active row: {activeRowIndex + 1}/{visibleTraces.length}</span>
        )}
        {focusMode && (
          <button
            type="button"
            onClick={() => setDenseMode((v) => !v)}
            aria-keyshortcuts="D"
            className="ml-auto text-[11px] font-semibold border border-slate-200 bg-white text-slate-700 hover:border-slate-400 px-2 py-1 rounded transition-colors"
          >
            {denseMode ? 'Dense view: on' : 'Dense view: off'}
          </button>
        )}
      </div>

      <div className="mb-4 bg-white border border-slate-200 rounded px-3 py-2">
        <div className="flex items-center justify-between gap-2 mb-1.5">
          <div>
            <p className="text-[10px] font-bold tracking-[0.12em] uppercase text-slate-400">
              Failure tags ({failureSummaryMode === 'session' ? 'session' : 'current page'})
            </p>
            {lastAction && (
              <p className="text-[10px] text-slate-400 mt-1">
                Last action: <span className="text-slate-600">{lastAction.message}</span> <span className="text-slate-400">at {lastAction.at}</span>
              </p>
            )}
            {topFailureTheme && (
              <p className="text-[10px] text-slate-500 mt-1">
                Top theme: <span className="font-semibold text-slate-700">{topFailureTheme[0]}</span> ({topFailureTheme[1]})
              </p>
            )}
            <p className="text-[10px] text-slate-400 mt-1">Keyboard: A = apply top tag, Z = undo last bulk apply, D = toggle dense view.</p>
          </div>
          <div className="flex items-center gap-1">
            {topFailureTheme && untaggedFailedTraces.length > 0 && (
              <button
                type="button"
                onClick={applyTopTagToUntaggedFails}
                disabled={isApplyingTopTag}
                aria-keyshortcuts="A"
                className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                  isApplyingTopTag
                    ? 'bg-slate-100 text-slate-400 border-slate-200'
                    : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
                }`}
              >
                {isApplyingTopTag ? 'Applying…' : `Apply top tag to ${untaggedFailedTraces.length}`}
              </button>
            )}
            {topFailureTheme && (
              <button
                type="button"
                onClick={copyTopTheme}
                className="text-[10px] px-2 py-1 rounded border transition-colors bg-white text-slate-600 border-slate-200 hover:border-slate-400"
              >
                Copy top theme
              </button>
            )}
            {summaryRows.length > 0 && (
              <div className="relative" ref={copyActionsRef}>
                <button
                  type="button"
                  ref={copyActionsToggleRef}
                  onClick={() => setShowCopyActions((value) => !value)}
                  onKeyDown={onCopyActionsTriggerKeyDown}
                  className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                    showCopyActions
                      ? 'bg-slate-900 text-white border-slate-900'
                      : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
                  } focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-slate-400 focus-visible:ring-offset-1`}
                >
                  Copy actions
                </button>
                {showCopyActions && (
                  <div role="menu" className="absolute right-0 top-[calc(100%+4px)] z-10 min-w-[150px] bg-white border border-slate-200 rounded shadow-sm p-1 space-y-1">
                    <button
                      type="button"
                      role="menuitem"
                      ref={(el) => { copyActionItemRefs.current[0] = el }}
                      onKeyDown={(event) => onCopyActionKeyDown(event, 0)}
                      onClick={() => { setShowCopyActions(false); void copyFailureSummary() }}
                      className="w-full text-left text-[10px] px-2 py-1 rounded text-slate-600 hover:bg-slate-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-slate-400"
                    >
                      Copy summary
                    </button>
                    <button
                      type="button"
                      role="menuitem"
                      ref={(el) => { copyActionItemRefs.current[1] = el }}
                      onKeyDown={(event) => onCopyActionKeyDown(event, 1)}
                      onClick={() => { setShowCopyActions(false); void copyCompactSummary() }}
                      className="w-full text-left text-[10px] px-2 py-1 rounded text-slate-600 hover:bg-slate-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-slate-400"
                    >
                      Copy compact
                    </button>
                    <button
                      type="button"
                      role="menuitem"
                      ref={(el) => { copyActionItemRefs.current[2] = el }}
                      onKeyDown={(event) => onCopyActionKeyDown(event, 2)}
                      onClick={() => { setShowCopyActions(false); void copyCompactSummaryTable() }}
                      className="w-full text-left text-[10px] px-2 py-1 rounded text-slate-600 hover:bg-slate-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-slate-400"
                    >
                      Copy compact table
                    </button>
                    <div className="pt-1 mt-1 border-t border-slate-100 text-[9px] text-slate-400 px-1">
                      ↑/↓/Tab navigate · Enter select · Esc close · S/C/T or 1/2/3 quick keys
                    </div>
                  </div>
                )}
              </div>
            )}
            {summaryRows.length > 0 && (
              <button
                type="button"
                onClick={() => setShowCopyPreview((value) => !value)}
                className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                  showCopyPreview
                    ? 'bg-slate-900 text-white border-slate-900'
                    : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
                }`}
              >
                {showCopyPreview ? 'Hide preview' : 'Preview copy'}
              </button>
            )}
            <button
              type="button"
              onClick={() => setCopyFormat((value) => (value === 'list' ? 'table' : 'list'))}
              className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                copyFormat === 'table'
                  ? 'bg-slate-900 text-white border-slate-900'
                  : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
              }`}
            >
              Format: {copyFormat}
            </button>
            <button
              type="button"
              onClick={() => setIncludeZeroCountsInCopy((value) => !value)}
              className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                includeZeroCountsInCopy
                  ? 'bg-slate-900 text-white border-slate-900'
                  : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
              }`}
            >
              Include zeros: {includeZeroCountsInCopy ? 'on' : 'off'}
            </button>
            <button
              type="button"
              onClick={() => setTrimForSlack((value) => !value)}
              className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                trimForSlack
                  ? 'bg-slate-900 text-white border-slate-900'
                  : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
              }`}
            >
              Trim for Slack: {trimForSlack ? 'on' : 'off'}
            </button>
            {lastBulkApply && (
              <button
                type="button"
                onClick={undoLastBulkApplyTopTag}
                disabled={isUndoingTopTag}
                aria-keyshortcuts="Z"
                className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                  isUndoingTopTag
                    ? 'bg-slate-100 text-slate-400 border-slate-200'
                    : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
                }`}
              >
                {isUndoingTopTag ? 'Undoing…' : `Undo ${lastBulkApply.tag}`}
              </button>
            )}
            <button
              type="button"
              onClick={() => setFailureSummaryMode('page')}
              className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                failureSummaryMode === 'page'
                  ? 'bg-slate-900 text-white border-slate-900'
                  : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
              }`}
            >
              Page
            </button>
            <button
              type="button"
              onClick={() => setFailureSummaryMode('session')}
              className={`text-[10px] px-2 py-1 rounded border transition-colors ${
                failureSummaryMode === 'session'
                  ? 'bg-slate-900 text-white border-slate-900'
                  : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'
              }`}
            >
              Session
            </button>
          </div>
        </div>
        {summaryRows.length > 0 ? (
          <div className="flex flex-wrap items-center gap-1.5">
            {summaryRows.map(([category, count]) => (
              <span key={category} className="text-[10px] px-2 py-1 rounded border border-slate-200 bg-slate-50 text-slate-600">
                {category} <span className="font-semibold text-slate-800">{count}</span>
              </span>
            ))}
          </div>
        ) : (
          <p className="text-[11px] text-slate-400">
            {failureSummaryMode === 'session'
              ? 'No session failure tags yet.'
              : 'No failed traces with category tags on this page yet.'}
          </p>
        )}
        {showCopyPreview && summaryRows.length > 0 && (
          <div className="mt-2 border border-slate-200 rounded bg-slate-50 p-2">
            <div className="flex items-center justify-between gap-2 mb-1">
              <p className="text-[10px] font-semibold text-slate-500">Copy payload preview</p>
              <div className="flex items-center gap-2">
                <p className="text-[10px] text-slate-400">{copyPreviewChars} chars · {copyPreviewLines} lines</p>
                <span className={`text-[10px] px-1.5 py-0.5 rounded border ${fitsSlack ? 'text-emerald-700 bg-emerald-50 border-emerald-200' : 'text-amber-700 bg-amber-50 border-amber-200'}`}>
                  {fitsSlack ? 'Fits Slack' : 'Over 4k'}
                </span>
                <span className={`text-[10px] px-1.5 py-0.5 rounded border ${fitsGithubComment ? 'text-emerald-700 bg-emerald-50 border-emerald-200' : 'text-amber-700 bg-amber-50 border-amber-200'}`}>
                  {fitsGithubComment ? 'Fits GitHub comment' : 'Over 65k'}
                </span>
              </div>
            </div>
            {shouldSuggestTrimForSlack && (
              <div className="mb-2 flex items-center justify-between gap-2 rounded border border-amber-200 bg-amber-50 px-2 py-1.5">
                <p className="text-[10px] text-amber-800">Payload exceeds Slack-friendly length. Enable Trim for Slack?</p>
                <button
                  type="button"
                  onClick={() => setTrimForSlack(true)}
                  className="text-[10px] font-semibold rounded border border-amber-300 bg-white text-amber-800 hover:border-amber-500 px-2 py-1 transition-colors"
                >
                  Enable trim
                </button>
              </div>
            )}
            <pre className="text-[10px] text-slate-600 whitespace-pre-wrap leading-relaxed max-h-40 overflow-y-auto">
              {copyPreviewPayload}
            </pre>
          </div>
        )}
      </div>

      {unratedOnly && visibleTraces.length > 0 && (
        <p className="text-[11px] text-slate-500 mb-3">
          Focus mode: shortcuts apply to the active trace. Use J/K to change active row, G/Shift+G for first/last row, D for dense view, and 1-8 for fail tags. Rate and it auto-advances.
        </p>
      )}

      {/* Trace list */}
      {totalCount === 0 ? (
        <div className="bg-white border border-slate-200 rounded p-10 text-center">
          <p className="text-[14px] text-slate-400">
            No traces yet. Traces are written on every Claude API call once migration 040 is applied.
          </p>
        </div>
      ) : visibleTraces.length === 0 ? (
        <div className="bg-white border border-slate-200 rounded p-10 text-center">
          <p className="text-[14px] text-slate-500">This page of unrated traces is complete.</p>
          {unratedOnly && page < totalPages - 1 ? (
            <>
              <p className="text-[12px] text-slate-400 mt-1">Move to the next unrated page to continue labeling.</p>
              <Link
                href={buildUrl({ feature: currentFeature || undefined, unrated: '1', page: String(page + 1) })}
                className="inline-block mt-3 text-[12px] font-semibold px-3 py-1.5 rounded border border-slate-200 bg-white text-slate-700 hover:border-slate-400 transition-colors"
              >
                Next unrated page
              </Link>
            </>
          ) : (
            <p className="text-[12px] text-slate-400 mt-1">No more unrated traces on remaining pages for this filter.</p>
          )}
        </div>
      ) : (
        <div className="bg-white border border-slate-200 rounded overflow-hidden mb-5">
          {visibleTraces.map((t, idx) => (
            <TraceRow
              key={t.id}
              trace={t}
              enableShortcuts={t.id === activeRowId || (activeRowId == null && idx === 0)}
              shortcutsBlocked={showCopyActions}
              denseMode={denseMode}
              rowRef={(element) => {
                if (element) {
                  rowRefs.current[t.id] = element
                } else {
                  delete rowRefs.current[t.id]
                }
              }}
              onActivate={setActiveRowId}
              onRated={handleRated}
            />
          ))}
        </div>
      )}

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between">
          <Link
            href={page > 0 ? buildUrl({ feature: currentFeature || undefined, unrated: unratedOnly ? '1' : undefined, page: String(page - 1) }) : '#'}
            className={`text-[13px] font-semibold px-4 py-2 rounded border border-slate-200 bg-white hover:bg-slate-50 ${page === 0 ? 'opacity-40 pointer-events-none' : ''}`}
          >
            Previous
          </Link>
          <span className="text-[12px] text-slate-400">
            Page {page + 1} of {totalPages} &middot; {totalCount} total
          </span>
          <Link
            href={page < totalPages - 1 ? buildUrl({ feature: currentFeature || undefined, unrated: unratedOnly ? '1' : undefined, page: String(page + 1) }) : '#'}
            className={`text-[13px] font-semibold px-4 py-2 rounded border border-slate-200 bg-white hover:bg-slate-50 ${page >= totalPages - 1 ? 'opacity-40 pointer-events-none' : ''}`}
          >
            Next
          </Link>
        </div>
      )}
    </>
  )
}

import Link from 'next/link'
import { redirect, notFound } from 'next/navigation'
import { readFile } from 'node:fs/promises'
import path from 'node:path'
import { createClient } from '@/lib/supabase/server'
import { createAdminClient } from '@/lib/supabase/admin'
import { getStaffMember, getAllStaff } from '@/lib/staff'
import { getStripe } from '@/lib/stripe'
import { getRolePathPriorityDebugRows } from '@/lib/role-path-priority'
import { FunnelChart, EventVolumeChart } from './admin-charts'
import { INTERNAL_APIS, PAGE_GROUPS, STEP_LABELS } from './admin-page-config'

type EmailCouncilLogEntry = {
  ts: string
  to?: string
  channel?: string
  subject?: string
  blocked?: boolean
  blockers?: string[]
  warnings?: string[]
  scores?: {
    ejes?: number
    open?: number
    understand?: number
    reply?: number
    productLift?: number
  }
}

export default async function AdminPage() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) redirect('/login')

  const staff = await getStaffMember(user.email ?? '')
  if (!staff) notFound()

  const rolePathPriorityDebugPromise = getRolePathPriorityDebugRows()

  const adminClient = createAdminClient()
  const since24h = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString()
  const since7d  = new Date(Date.now() - 7  * 24 * 60 * 60 * 1000).toISOString()
  const since30d = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString()

  const [
    { data: activeUsers },
    { data: profiles },
    { data: events7d },
    { data: events30d },
    { count: totalUsers },
    { count: paidUsers },
    { count: trialingUsers },
    teamMembers,
    { data: partnerRows },
    { data: users24h },
    { data: companies24h },
    { data: contacts24h },
    { data: followUps24h },
    { data: briefingViews24h },
    { count: openAutomationAlerts },
  ] = await Promise.all([
    adminClient.from('users').select('id').in('subscription_status', ['trialing', 'active']),
    adminClient.from('user_profiles').select('user_id, positioning_summary, briefing_time, last_briefing_sent_at, placed_at, placement_company, full_name'),
    adminClient.from('user_events').select('event_name, created_at').gte('created_at', since7d).limit(5000),
    adminClient.from('user_events').select('event_name').gte('created_at', since30d).limit(5000),
    adminClient.from('users').select('id', { count: 'exact', head: true }),
    adminClient.from('users').select('id', { count: 'exact', head: true }).eq('subscription_status', 'active'),
    adminClient.from('users').select('id', { count: 'exact', head: true }).eq('subscription_status', 'trialing'),
    getAllStaff(),
    adminClient.from('partners').select('id, name, email, referral_code, commission_pct, is_active, created_at').order('created_at', { ascending: false }),
    adminClient.from('users').select('id').gte('created_at', since24h).limit(5000),
    adminClient.from('companies').select('user_id').gte('created_at', since24h).is('archived_at', null).limit(5000),
    adminClient.from('contacts').select('user_id').gte('created_at', since24h).limit(5000),
    adminClient.from('follow_ups').select('user_id').gte('created_at', since24h).limit(5000),
    adminClient.from('user_events').select('user_id').eq('event_name', 'briefing_viewed').gte('created_at', since24h).limit(5000),
    adminClient.from('automation_alerts').select('id', { count: 'exact', head: true }).eq('status', 'open'),
  ])

  const usersWithCompany24h = new Set((companies24h ?? []).map(r => r.user_id)).size
  const usersWithContact24h = new Set((contacts24h ?? []).map(r => r.user_id)).size
  const usersWithFollowUp24h = new Set((followUps24h ?? []).map(r => r.user_id)).size
  const usersWithBriefingView24h = new Set((briefingViews24h ?? []).map(r => r.user_id)).size

  const activeUserIds = new Set((activeUsers ?? []).map(u => u.id))
  const profileMap = Object.fromEntries((profiles ?? []).map(p => [p.user_id, p]))

  let a1 = 0, a5 = 0
  for (const uid of activeUserIds) {
    const p = profileMap[uid]
    if (!p) continue
    if ((p.positioning_summary?.length ?? 0) >= 100) a1++
    if (p.briefing_time) a5++
  }

  // Briefing health
  const briefingConfiguredProfiles = (profiles ?? []).filter(p => activeUserIds.has(p.user_id) && p.briefing_time)
  const lastBriefingSentAt = briefingConfiguredProfiles
    .map(p => p.last_briefing_sent_at)
    .filter(Boolean)
    .sort()
    .at(-1) ?? null
  const briefingHoursAgo = lastBriefingSentAt
    ? Math.round((Date.now() - new Date(lastBriefingSentAt).getTime()) / 3_600_000)
    : null
  const briefingStale = briefingConfiguredProfiles.length > 0 && (briefingHoursAgo === null || briefingHoursAgo >= 36)

  const adminAny = adminClient as any
  const [{ data: latestExecutiveResearchRun }, { count: executiveResearchSourceCount }, { count: executiveResearchFailureCount }] = await Promise.all([
    adminAny
      .from('executive_research_refresh_runs')
      .select('run_started_at, run_finished_at, checked_count, changed_count, failed_count')
      .order('run_started_at', { ascending: false })
      .limit(1)
      .maybeSingle(),
    adminAny.from('executive_research_library').select('id', { count: 'exact', head: true }),
    adminAny.from('executive_research_library').select('id', { count: 'exact', head: true }).not('fetch_error', 'is', null),
  ])

  const executiveResearchHoursAgo = latestExecutiveResearchRun?.run_started_at
    ? Math.round((Date.now() - new Date(latestExecutiveResearchRun.run_started_at).getTime()) / 3_600_000)
    : null
  const executiveResearchStatus: 'healthy' | 'degraded' | 'stale' | 'missing' = !latestExecutiveResearchRun
    ? 'missing'
    : (latestExecutiveResearchRun.failed_count ?? 0) > 0
      ? 'degraded'
      : executiveResearchHoursAgo !== null && executiveResearchHoursAgo > 8 * 24
        ? 'stale'
        : 'healthy'

  // Placements
  const placements = (profiles ?? [])
    .filter(p => p.placed_at != null)
    .sort((a, b) => new Date(b.placed_at!).getTime() - new Date(a.placed_at!).getTime())

  const userIdList = [...activeUserIds]
  const [
    { count: a2Count }, { count: a3Count }, { count: a4Count }, { count: a6Count },
    { data: endedTrials },
    { data: allSignals },
    { data: signalActions },
    { data: qualityLogs },
    { data: activeTrials },
  ] = await Promise.all([
    adminClient.from('companies').select('user_id', { count: 'exact', head: true }).in('user_id', userIdList).is('archived_at', null),
    adminClient.from('briefs').select('user_id', { count: 'exact', head: true }).in('user_id', userIdList).eq('type', 'prep'),
    adminClient.from('contacts').select('user_id', { count: 'exact', head: true }).in('user_id', userIdList),
    adminClient.from('follow_ups').select('user_id', { count: 'exact', head: true }).in('user_id', userIdList),
    adminClient.from('users').select('subscription_status, plan_at_trial_end, signup_source').not('trial_ends_at', 'is', null).lt('trial_ends_at', new Date().toISOString()),
    adminClient.from('company_signals').select('id, signal_type').limit(2000),
    adminClient.from('signal_action_events').select('signal_id, action_type').limit(2000),
    adminClient.from('brief_quality_log').select('context_score, has_resume, has_scan_result, has_contacts, word_count').gte('created_at', since30d).limit(500),
    adminClient.from('users').select('id, email, created_at, trial_ends_at, signup_source').eq('subscription_status', 'trialing').gt('trial_ends_at', new Date().toISOString()).order('created_at', { ascending: false }).limit(50),
  ])

  const denominator = activeUserIds.size || 1
  const funnelData = [
    { step: 'a1_resume',    label: 'Resume',    count: a1 },
    { step: 'a2_company',   label: 'Company',   count: a2Count ?? 0 },
    { step: 'a3_prep',      label: 'Brief',     count: a3Count ?? 0 },
    { step: 'a4_contact',   label: 'Contact',   count: a4Count ?? 0 },
    { step: 'a5_briefing',  label: 'Briefing',  count: a5 },
    { step: 'a6_follow_up', label: 'Follow-up', count: a6Count ?? 0 },
  ]

  const eventCounts7d  = (events7d  ?? []).reduce<Record<string, number>>((acc, e) => { acc[e.event_name] = (acc[e.event_name] ?? 0) + 1; return acc }, {})
  const eventCounts30d = (events30d ?? []).reduce<Record<string, number>>((acc, e) => { acc[e.event_name] = (acc[e.event_name] ?? 0) + 1; return acc }, {})
  const eventVolumeData = Object.entries(eventCounts30d).sort((a, b) => b[1] - a[1]).map(([event_name, count]) => ({ event_name, count }))
  const rolePathPriorityDebug = await rolePathPriorityDebugPromise
  const searchPaused7d = eventCounts7d.search_paused ?? 0
  const searchResumed7d = eventCounts7d.search_resumed ?? 0
  const netPaused7d = searchPaused7d - searchResumed7d
  const pauseResumeRatio7d = searchResumed7d > 0 ? (searchPaused7d / searchResumed7d).toFixed(2) : null
  const trendByDay: Record<string, { paused: number; resumed: number }> = {}
  for (const event of events7d ?? []) {
    const dayKey = event.created_at?.slice(0, 10)
    if (!dayKey) continue
    if (!trendByDay[dayKey]) trendByDay[dayKey] = { paused: 0, resumed: 0 }
    if (event.event_name === 'search_paused') trendByDay[dayKey].paused += 1
    if (event.event_name === 'search_resumed') trendByDay[dayKey].resumed += 1
  }
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  const pauseResumeTrend7d = Array.from({ length: 7 }, (_, idx) => {
    const date = new Date(today)
    date.setDate(today.getDate() - (6 - idx))
    const dayKey = date.toISOString().slice(0, 10)
    const stats = trendByDay[dayKey] ?? { paused: 0, resumed: 0 }
    const label = date.toLocaleDateString('en-US', { weekday: 'short', month: 'numeric', day: 'numeric' })
    return { dayKey, label, paused: stats.paused, resumed: stats.resumed, net: stats.paused - stats.resumed }
  })
  const trendPeak = pauseResumeTrend7d.reduce((peak, row) => Math.max(peak, row.paused, row.resumed), 1)
  const recent3d = pauseResumeTrend7d.slice(-3)
  const netPausedLast3d = recent3d.reduce((sum, row) => sum + row.net, 0)
  const positiveNetDaysLast3d = recent3d.filter((row) => row.net > 0).length
  const telemetryAlertLevel: 'normal' | 'watch' | 'risk' =
    netPausedLast3d >= 6 || positiveNetDaysLast3d === 3
      ? 'risk'
      : netPausedLast3d >= 3 || positiveNetDaysLast3d >= 2
        ? 'watch'
        : 'normal'

  // Go/no-go scorecard metrics (best-effort with explicit tracking gaps)
  const since14d = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000).toISOString()
  const since60d = new Date(Date.now() - 60 * 24 * 60 * 60 * 1000).toISOString()
  const [
    { data: users7d },
    { data: users60d },
    { data: companies7d },
    { data: contacts7d },
    { data: followUps7d },
    { data: briefingViews7d },
    { data: briefingViews14d },
    { data: actionEvents14d },
  ] = await Promise.all([
    adminClient.from('users').select('id, created_at').gte('created_at', since7d).limit(5000),
    adminClient.from('users').select('id, created_at, subscription_tier, subscription_status').gte('created_at', since60d).limit(5000),
    adminClient.from('companies').select('user_id').gte('created_at', since7d).is('archived_at', null).limit(5000),
    adminClient.from('contacts').select('user_id').gte('created_at', since7d).limit(5000),
    adminClient.from('follow_ups').select('user_id').gte('created_at', since7d).limit(5000),
    adminClient.from('user_events').select('user_id').eq('event_name', 'briefing_viewed').gte('created_at', since7d).limit(5000),
    adminClient.from('user_events').select('user_id').eq('event_name', 'briefing_viewed').gte('created_at', since14d).limit(5000),
    adminClient.from('user_events').select('user_id, event_name').in('event_name', ['follow_up_set', 'contact_added', 'company_added', 'outreach_draft_generated', 'briefing_action_clicked']).gte('created_at', since14d).limit(5000),
  ])

  const cohort7 = users7d ?? []
  const cohort7UserIds = new Set(cohort7.map(u => u.id))
  const usersWithCompany7d = new Set((companies7d ?? []).map(r => r.user_id))
  const usersWithContact7d = new Set((contacts7d ?? []).map(r => r.user_id))
  const usersWithFollowUp7d = new Set((followUps7d ?? []).map(r => r.user_id))
  const usersWithBriefing7d = new Set((briefingViews7d ?? []).map(r => r.user_id))

  let activated7dCount = 0
  for (const uid of cohort7UserIds) {
    if (usersWithCompany7d.has(uid) && usersWithContact7d.has(uid) && usersWithFollowUp7d.has(uid) && usersWithBriefing7d.has(uid)) {
      activated7dCount++
    }
  }
  const activationRate7d = cohort7.length > 0 ? Math.round((activated7dCount / cohort7.length) * 100) : null

  const briefingViewers14d = new Set((briefingViews14d ?? []).map(r => r.user_id))
  const actionUsers14d = new Set((actionEvents14d ?? []).map(r => r.user_id))
  const convertedUsers14d = [...briefingViewers14d].filter(uid => actionUsers14d.has(uid)).length
  const briefingToActionRate14d = briefingViewers14d.size > 0 ? Math.round((convertedUsers14d / briefingViewers14d.size) * 100) : null

  const monitorCohort = (users60d ?? []).filter(u => {
    const created = new Date(u.created_at).getTime()
    const min = Date.now() - 60 * 24 * 60 * 60 * 1000
    const max = Date.now() - 30 * 24 * 60 * 60 * 1000
    return created >= min && created <= max && u.subscription_tier === 'passive'
  })
  const monitorRetained = monitorCohort.filter(u => u.subscription_status === 'active').length
  const monitorRetention30d = monitorCohort.length > 0 ? Math.round((monitorRetained / monitorCohort.length) * 100) : null

  type ScoreStatus = 'green' | 'yellow' | 'red' | 'gray'
  function statusClass(status: ScoreStatus): string {
    if (status === 'green') return 'text-green-700 bg-green-50 border-green-200'
    if (status === 'yellow') return 'text-amber-700 bg-amber-50 border-amber-200'
    if (status === 'red') return 'text-red-700 bg-red-50 border-red-200'
    return 'text-slate-500 bg-slate-50 border-slate-200'
  }

  const scoreRows: { label: string; threshold: string; value: string; status: ScoreStatus; note?: string }[] = [
    {
      label: 'Activation completion (7d)',
      threshold: '>= 45%',
      value: activationRate7d === null ? 'N/A' : `${activationRate7d}%`,
      status: activationRate7d === null ? 'gray' : activationRate7d >= 45 ? 'green' : activationRate7d >= 35 ? 'yellow' : 'red',
      note: cohort7.length > 0 ? `Cohort n=${cohort7.length}` : 'Need more 7-day signups',
    },
    {
      label: 'Briefing to action (14d)',
      threshold: '>= 35%',
      value: briefingToActionRate14d === null ? 'N/A' : `${briefingToActionRate14d}%`,
      status: briefingToActionRate14d === null ? 'gray' : briefingToActionRate14d >= 35 ? 'green' : briefingToActionRate14d >= 25 ? 'yellow' : 'red',
      note: briefingViewers14d.size > 0 ? `Viewers n=${briefingViewers14d.size}` : 'No briefing viewers in window',
    },
    {
      label: 'Intelligence retention (30d)',
      threshold: '>= 70%',
      value: monitorRetention30d === null ? 'N/A' : `${monitorRetention30d}%`,
      status: monitorRetention30d === null ? 'gray' : monitorRetention30d >= 70 ? 'green' : monitorRetention30d >= 60 ? 'yellow' : 'red',
      note: monitorCohort.length > 0 ? `Cohort n=${monitorCohort.length}` : 'No matured Intelligence cohort yet',
    },
    {
      label: 'Upgrade pull (30d)',
      threshold: '>= 12%',
      value: 'Tracking gap',
      status: 'gray',
      note: 'Need tier-change event history for monitor_to_paid_upgrade.',
    },
    {
      label: 'Reliability floor',
      threshold: 'briefing fresh + no stale worker',
      value: briefingConfiguredProfiles.length === 0 ? 'N/A' : briefingStale ? 'Stale' : 'Healthy',
      status: briefingConfiguredProfiles.length === 0 ? 'gray' : briefingStale ? 'red' : 'green',
      note: briefingConfiguredProfiles.length === 0 ? 'No briefing configs yet' : `Last briefing ${briefingHoursAgo ?? '-'}h ago`,
    },
  ]

  const hardRedCount = scoreRows.filter(r => r.status === 'red').length
  const measurableCount = scoreRows.filter(r => r.status !== 'gray').length
  const measurableGreen = scoreRows.filter(r => r.status === 'green').length
  const decision: { label: 'GO' | 'CONDITIONAL GO' | 'NO-GO'; status: ScoreStatus; reason: string } =
    hardRedCount > 0
      ? { label: 'NO-GO', status: 'red', reason: 'One or more hard thresholds are below floor.' }
      : measurableCount > 0 && measurableGreen === measurableCount
        ? { label: 'GO', status: 'green', reason: 'All measurable thresholds are on target.' }
        : { label: 'CONDITIONAL GO', status: 'yellow', reason: 'No hard failures, but missing data or near-threshold metrics remain.' }

  // Active trial users: enrich with company status
  const trialUsers = activeTrials ?? []
  const trialUserIds = trialUsers.map(u => u.id)
  let trialCompanySet = new Set<string>()
  if (trialUserIds.length > 0) {
    const { data: trialCompanyRows } = await adminClient.from('companies').select('user_id').in('user_id', trialUserIds).is('archived_at', null)
    trialCompanySet = new Set((trialCompanyRows ?? []).map(r => r.user_id))
  }

  // Partners: attribution counts
  const partners = (partnerRows ?? []) as { id: string; name: string; email: string; referral_code: string; commission_pct: number; is_active: boolean; created_at: string }[]
  const partnerIds = partners.map(p => p.id)
  let attributionsByPartner: Record<string, { total: number; active: number; mrr: number }> = {}
  if (partnerIds.length > 0) {
    const { data: attrRows } = await adminClient
      .from('referral_attributions')
      .select('partner_id, signup_user_id')
      .in('partner_id', partnerIds)
    const attrUserIds = (attrRows ?? []).map(a => a.signup_user_id)
    let userStatusMap: Record<string, { status: string; tier: string }> = {}
    if (attrUserIds.length > 0) {
      const { data: attrUsers } = await adminClient
        .from('users')
        .select('id, subscription_status, subscription_tier')
        .in('id', attrUserIds)
      userStatusMap = Object.fromEntries((attrUsers ?? []).map(u => [u.id, { status: u.subscription_status, tier: u.subscription_tier ?? '' }]))
    }
    const TIER_MRR: Record<string, number> = { passive: 49, active: 129, executive: 249 }
    for (const attr of (attrRows ?? [])) {
      if (!attributionsByPartner[attr.partner_id]) attributionsByPartner[attr.partner_id] = { total: 0, active: 0, mrr: 0 }
      attributionsByPartner[attr.partner_id].total++
      const u = userStatusMap[attr.signup_user_id]
      if (u?.status === 'active') {
        attributionsByPartner[attr.partner_id].active++
        attributionsByPartner[attr.partner_id].mrr += TIER_MRR[u.tier] ?? 0
      }
    }
  }

  // B2B accounts: seat owners and their member counts
  const { data: allSeatsRows } = await adminClient
    .from('team_seats')
    .select('owner_id, status')
  const seatsByOwner: Record<string, { total: number; accepted: number }> = {}
  for (const s of (allSeatsRows ?? [])) {
    if (!seatsByOwner[s.owner_id]) seatsByOwner[s.owner_id] = { total: 0, accepted: 0 }
    seatsByOwner[s.owner_id].total++
    if (s.status === 'accepted') seatsByOwner[s.owner_id].accepted++
  }
  const seatOwnerIds = Object.keys(seatsByOwner)
  let b2bAccounts: { id: string; email: string; tier: string; total: number; accepted: number }[] = []
  if (seatOwnerIds.length > 0) {
    const { data: ownerData } = await adminClient
      .from('users')
      .select('id, email, subscription_tier')
      .in('id', seatOwnerIds)
    b2bAccounts = (ownerData ?? []).map((u: { id: string; email: string | null; subscription_tier: string | null }) => ({
      id: u.id,
      email: u.email ?? '',
      tier: u.subscription_tier ?? 'free',
      total: seatsByOwner[u.id]?.total ?? 0,
      accepted: seatsByOwner[u.id]?.accepted ?? 0,
    })).sort((a, b) => b.total - a.total)
  }

  // Trial conversion
  const trialsEnded = endedTrials ?? []
  const totalEnded = trialsEnded.length
  const totalConverted = trialsEnded.filter(u => u.subscription_status === 'active').length
  const conversionRate = totalEnded > 0 ? Math.round((totalConverted / totalEnded) * 100) : null
  const linkedInAdsThreshold = 35
  const linkedInAdsGatePass = conversionRate !== null && conversionRate >= linkedInAdsThreshold
  const linkedInAdsDecision = linkedInAdsGatePass ? 'GO' : 'DEFER'

  // Conversion by signup_source channel
  const channelMap: Record<string, { ended: number; converted: number }> = {}
  for (const u of trialsEnded) {
    const ch = u.signup_source ?? 'direct'
    if (!channelMap[ch]) channelMap[ch] = { ended: 0, converted: 0 }
    channelMap[ch].ended++
    if (u.subscription_status === 'active') channelMap[ch].converted++
  }
  const channelRows = Object.entries(channelMap)
    .sort((a, b) => b[1].ended - a[1].ended)
    .map(([ch, { ended, converted }]) => ({
      channel: ch,
      ended,
      converted,
      rate: ended > 0 ? Math.round((converted / ended) * 100) : 0,
    }))

  // Signal to action rate by signal type
  const actedSignalIds = new Set((signalActions ?? []).map(a => a.signal_id).filter((id): id is string => id !== null))
  const signalTypeCounts: Record<string, { total: number; acted: number }> = {}
  for (const s of (allSignals ?? []) as { id: string; signal_type: string }[]) {
    if (!signalTypeCounts[s.signal_type]) signalTypeCounts[s.signal_type] = { total: 0, acted: 0 }
    signalTypeCounts[s.signal_type].total++
    if (actedSignalIds.has(s.id)) signalTypeCounts[s.signal_type].acted++
  }
  const signalRows = Object.entries(signalTypeCounts)
    .sort((a, b) => b[1].total - a[1].total)
    .map(([type, counts]) => ({
      type,
      label: type.replace(/_/g, ' ').replace(/\b\w/g, (c: string) => c.toUpperCase()),
      total: counts.total,
      acted: counts.acted,
      rate: counts.total > 0 ? Math.round((counts.acted / counts.total) * 100) : 0,
    }))

  // Brief quality
  const logs = qualityLogs ?? []
  const avgContextScore = logs.length > 0
    ? Math.round(logs.reduce((sum: number, l: { context_score: number | null }) => sum + (l.context_score ?? 0), 0) / logs.length)
    : null
  const pctResume   = logs.length > 0 ? Math.round(logs.filter((l: { has_resume: boolean }) => l.has_resume).length / logs.length * 100) : null
  const pctScan     = logs.length > 0 ? Math.round(logs.filter((l: { has_scan_result: boolean }) => l.has_scan_result).length / logs.length * 100) : null
  const pctContacts = logs.length > 0 ? Math.round(logs.filter((l: { has_contacts: boolean }) => l.has_contacts).length / logs.length * 100) : null
  const wordCountLogs = logs.filter((l: { word_count: number | null }) => l.word_count)
  const avgWords = wordCountLogs.length > 0
    ? Math.round(wordCountLogs.reduce((sum: number, l: { word_count: number | null }) => sum + (l.word_count ?? 0), 0) / wordCountLogs.length)
    : null

  const roleBadge = (role: string) =>
    role === 'owner' ? 'bg-amber-50 text-amber-700' :
    role === 'admin' ? 'bg-blue-50 text-blue-700' :
    'bg-slate-100 text-slate-500'

  // Email council quality telemetry from local score log
  const emailCouncilLogPath = path.join(process.cwd(), '.logs', 'email-council-scores.jsonl')
  let emailCouncilEntries: EmailCouncilLogEntry[] = []
  try {
    const raw = await readFile(emailCouncilLogPath, 'utf8')
    emailCouncilEntries = raw
      .split(/\r?\n/)
      .filter(Boolean)
      .map((line) => {
        try {
          return JSON.parse(line) as EmailCouncilLogEntry
        } catch {
          return null
        }
      })
      .filter((entry): entry is EmailCouncilLogEntry => entry !== null)
  } catch {
    emailCouncilEntries = []
  }

  const nowMs = Date.now()
  const oneDayMs = 24 * 60 * 60 * 1000
  const sevenDayMs = 7 * oneDayMs

  const councilLast24h = emailCouncilEntries.filter((entry) => {
    const ts = Date.parse(entry.ts)
    return Number.isFinite(ts) && nowMs - ts <= oneDayMs
  })

  const councilLast7d = emailCouncilEntries.filter((entry) => {
    const ts = Date.parse(entry.ts)
    return Number.isFinite(ts) && nowMs - ts <= sevenDayMs
  })

  const blockedSends24h = councilLast24h.filter((entry) => entry.blocked).length
  const evaluated24h = councilLast24h.length
  const passed24h = evaluated24h - blockedSends24h
  const avgEjes24h = evaluated24h > 0
    ? Math.round(councilLast24h.reduce((sum, entry) => sum + (entry.scores?.ejes ?? 0), 0) / evaluated24h)
    : null

  const blockerCounts = new Map<string, number>()
  for (const entry of councilLast24h) {
    for (const blocker of entry.blockers ?? []) {
      blockerCounts.set(blocker, (blockerCounts.get(blocker) ?? 0) + 1)
    }
  }
  const topBlockers = Array.from(blockerCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3)

  const councilChannelMap = new Map<string, { count: number; blocked: number; ejesSum: number }>()
  for (const entry of councilLast7d) {
    const key = entry.channel ?? 'general'
    const current = councilChannelMap.get(key) ?? { count: 0, blocked: 0, ejesSum: 0 }
    current.count += 1
    current.blocked += entry.blocked ? 1 : 0
    current.ejesSum += entry.scores?.ejes ?? 0
    councilChannelMap.set(key, current)
  }
  const channelEjesTrend = Array.from(councilChannelMap.entries())
    .map(([channel, stats]) => ({
      channel,
      evaluations: stats.count,
      blockedRate: stats.count > 0 ? Math.round((stats.blocked / stats.count) * 100) : 0,
      avgEjes: stats.count > 0 ? Math.round(stats.ejesSum / stats.count) : 0,
    }))
    .sort((a, b) => b.evaluations - a.evaluations)

  const signups7d = cohort7.length

  // MRR from Stripe (best-effort — falls back to null on error)
  let stripeMrr: number | null = null
  try {
    const stripe = getStripe()
    const subs = await stripe.subscriptions.list({ status: 'active', limit: 100 })
    let totalCents = 0
    for (const sub of subs.data) {
      for (const item of sub.items.data) {
        const cents = (item.price.unit_amount ?? 0) * (item.quantity ?? 1)
        totalCents += item.price.recurring?.interval === 'year'
          ? Math.round(cents / 12)
          : cents
      }
    }
    stripeMrr = Math.round(totalCents / 100)
  } catch {
    // Stripe unavailable — show null
  }

  return (
    <div className="min-h-screen bg-slate-100 font-sans">
      <header className="bg-slate-900">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 h-14 flex items-center justify-between">
          <span className="text-[13px] font-bold tracking-[0.16em] uppercase text-slate-400"><span className="text-white">Starting </span><span className="text-orange-500">Monday</span></span>
          <div className="flex items-center gap-4">
            <Link href="/dashboard/admin/sales-enablement" className="text-[13px] font-semibold text-orange-300 hover:text-orange-200 transition-colors">Sales enablement</Link>
            <Link href="/dashboard/admin/revenue" className="text-[13px] font-semibold text-slate-400 hover:text-slate-200 transition-colors">Revenue</Link>
            <Link href="/dashboard/admin/product" className="text-[13px] font-semibold text-slate-400 hover:text-slate-200 transition-colors">Product</Link>
            <Link href="/dashboard/admin/operations" className="text-[13px] font-semibold text-slate-400 hover:text-slate-200 transition-colors">Operations</Link>
            <Link href="/dashboard/admin/guide" className="text-[13px] font-semibold text-slate-400 hover:text-slate-200 transition-colors">Guide</Link>
            <Link href="/dashboard/admin/internal-guide" className="text-[13px] font-semibold text-slate-400 hover:text-slate-200 transition-colors">Internal guide</Link>
            <Link href="/dashboard/admin/onboarding/video" className="text-[13px] font-semibold text-slate-400 hover:text-slate-200 transition-colors">Onboarding video</Link>
            <Link href="/dashboard/admin/traces" className="text-[13px] font-semibold text-slate-400 hover:text-slate-200 transition-colors">Traces</Link>
            <Link href="/dashboard/admin/team" className="text-[13px] font-semibold text-slate-400 hover:text-slate-200 transition-colors">Team</Link>
            <Link href="/dashboard" className="text-[13px] text-slate-300 hover:text-white transition-colors">Back to Dashboard</Link>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 py-8 sm:py-10">
<div className="mb-8 flex items-start justify-between gap-4">
          <div>
            <h1 className="text-[26px] font-bold text-slate-900 leading-tight">Admin</h1>
            <p className="text-[13px] text-slate-500 mt-1.5">
              Signed in as <span className="font-semibold">{user.email}</span>
              <span className={`ml-2 text-[13px] font-bold px-2 py-0.5 rounded ${roleBadge(staff.role)}`}>{staff.role}</span>
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Link href="/dashboard/admin/sales-enablement" className="text-[13px] font-semibold text-white bg-slate-900 border border-slate-900 hover:bg-slate-800 px-4 py-2 rounded transition-colors shrink-0">
              Open sales enablement
            </Link>
            {staff.role === 'owner' && (
              <Link href="/dashboard/admin/team" className="text-[13px] font-semibold text-slate-900 bg-white border border-slate-200 hover:border-slate-400 px-4 py-2 rounded transition-colors shrink-0">
                Manage team
              </Link>
            )}
          </div>
        </div>

        <section className="mb-8 bg-slate-50 border border-slate-200 rounded p-4">
          <h2 className="text-[13px] font-bold tracking-[0.12em] uppercase text-slate-500 mb-2">Jump to section</h2>
          <div className="flex flex-wrap gap-x-4 gap-y-2 text-[13px]">
            <a href="#control-rooms" className="text-slate-700 hover:text-slate-900 underline underline-offset-2">Control rooms</a>
            <a href="#subscriber-summary" className="text-slate-700 hover:text-slate-900 underline underline-offset-2">Subscribers</a>
            <a href="#email-council-health" className="text-slate-700 hover:text-slate-900 underline underline-offset-2">Email council</a>
            <a href="#system-health" className="text-slate-700 hover:text-slate-900 underline underline-offset-2">System health</a>
            <a href="#role-path-ranking" className="text-slate-700 hover:text-slate-900 underline underline-offset-2">Role-path ranking</a>
            <a href="#internal-pages" className="text-slate-700 hover:text-slate-900 underline underline-offset-2">Internal pages</a>
            <a href="#partners" className="text-slate-700 hover:text-slate-900 underline underline-offset-2">Partners</a>
          </div>
        </section>

        <section id="control-rooms" className="bg-white border border-slate-200 rounded p-5 mb-6">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-3">Control rooms</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-3 text-[13px]">
            <Link href="/dashboard/admin/sales-enablement" className="border border-slate-200 rounded px-4 py-3 hover:border-slate-400 transition-colors">
              <p className="font-semibold text-slate-900">Sales enablement</p>
              <p className="text-[13px] text-slate-500 mt-1">Compare proposals, checkpoints, and weighted scorecards.</p>
            </Link>
            <Link href="/dashboard/admin/revenue" className="border border-slate-200 rounded px-4 py-3 hover:border-slate-400 transition-colors">
              <p className="font-semibold text-slate-900">Revenue</p>
              <p className="text-[13px] text-slate-500 mt-1">Conversion, trial health, and paid growth diagnostics.</p>
            </Link>
            <Link href="/dashboard/admin/operations" className="border border-slate-200 rounded px-4 py-3 hover:border-slate-400 transition-colors">
              <p className="font-semibold text-slate-900">Operations</p>
              <p className="text-[13px] text-slate-500 mt-1">Reliability, release quality, and monitoring alerts.</p>
            </Link>
          </div>
        </section>

        <section id="email-council-health" className="bg-white border border-slate-200 rounded p-6 mb-6">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-1">Email Council Health (Daily)</h2>
          <p className="text-[13px] text-slate-400 mb-5">Blocked sends, top blockers, and 7-day EJES trend.</p>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4 mb-5">
            {[{
              label: 'Evaluated (24h)',
              value: evaluated24h,
            }, {
              label: 'Blocked (24h)',
              value: blockedSends24h,
            }, {
              label: 'Passed (24h)',
              value: passed24h,
            }, {
              label: 'Avg EJES (24h)',
              value: avgEjes24h ?? 'N/A',
            }].map((card) => (
              <div key={card.label} className="bg-slate-50 border border-slate-200 rounded p-4">
                <div className="text-[24px] font-bold text-slate-900 leading-none">{card.value}</div>
                <div className="text-[13px] text-slate-400 mt-1.5 tracking-[0.07em] uppercase">{card.label}</div>
              </div>
            ))}
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <div className="border border-slate-200 rounded p-4">
              <p className="text-[13px] font-bold tracking-[0.12em] uppercase text-slate-400 mb-2">Top blockers (24h)</p>
              {topBlockers.length === 0 ? (
                <p className="text-[13px] text-slate-500">No blockers logged in the last 24 hours.</p>
              ) : (
                <ul className="space-y-2">
                  {topBlockers.map(([blocker, count]) => (
                    <li key={blocker} className="text-[13px] text-slate-700 flex items-start justify-between gap-3">
                      <span className="leading-relaxed">{blocker}</span>
                      <span className="text-[13px] font-bold text-slate-500">{count}</span>
                    </li>
                  ))}
                </ul>
              )}
            </div>

            <div className="border border-slate-200 rounded p-4">
              <p className="text-[13px] font-bold tracking-[0.12em] uppercase text-slate-400 mb-2">Channel EJES trend (7d)</p>
              {channelEjesTrend.length === 0 ? (
                <p className="text-[13px] text-slate-500">No channel score data yet.</p>
              ) : (
                <div className="space-y-2">
                  {channelEjesTrend.map((row) => (
                    <div key={row.channel} className="grid grid-cols-[1fr_auto_auto] items-center gap-3 text-[13px]">
                      <span className="text-slate-700">{row.channel}</span>
                      <span className="text-slate-500">EJES {row.avgEjes}</span>
                      <span className={`text-[13px] font-bold px-2 py-0.5 rounded ${row.blockedRate === 0 ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>
                        blocked {row.blockedRate}%
                      </span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </section>

        <div className="mb-8">
          <p className="text-[13px] font-bold tracking-[0.12em] uppercase text-slate-400 mb-3">Operating Areas</p>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {PAGE_GROUPS.map((group) => {
              const corePages = group.pages.filter((page) => page.priority === 'core')
              const advancedCount = group.pages.filter((page) => page.priority === 'advanced').length
              return (
                <div key={group.id} className="bg-white border border-slate-200 rounded p-4">
                  <p className="text-[14px] font-bold text-slate-900">{group.label}</p>
                  <p className="text-[13px] text-slate-500 mt-1 leading-relaxed">{group.purpose}</p>
                  <div className="mt-3 space-y-1.5">
                    {corePages.map((page) => (
                      <Link key={page.path} href={page.path} className="block text-[13px] font-semibold text-slate-700 hover:text-slate-900 hover:underline">
                        {page.label}
                      </Link>
                    ))}
                    {advancedCount > 0 && (
                      <p className="text-[13px] text-slate-400 mt-2">+ {advancedCount} advanced pages</p>
                    )}
                  </div>
                </div>
              )
            })}
          </div>
        </div>

        <div className="mb-8">
          <p className="text-[13px] font-bold tracking-[0.12em] uppercase text-slate-400 mb-3">Daily activation snapshot (24h)</p>
          <div className="grid grid-cols-2 sm:grid-cols-5 gap-3 sm:gap-4">
            {[
              { label: 'New users', value: users24h?.length ?? 0 },
              { label: 'Added company', value: usersWithCompany24h },
              { label: 'Added contact', value: usersWithContact24h },
              { label: 'Set follow-up', value: usersWithFollowUp24h },
              { label: 'Viewed briefing', value: usersWithBriefingView24h },
            ].map((card) => (
              <div key={card.label} className="bg-white border border-slate-200 rounded p-4">
                <div className="text-[24px] font-bold text-slate-900 leading-none">{card.value}</div>
                <div className="text-[13px] text-slate-400 mt-1.5 tracking-[0.07em] uppercase">{card.label}</div>
              </div>
            ))}
          </div>
          <div className="mt-3">
            <Link href="/guide" className="inline-flex items-center gap-2 text-[13px] font-semibold text-slate-600 hover:text-slate-900 transition-colors">
              Automation alerts: <span className="text-slate-900">{openAutomationAlerts ?? 0}</span> - view runbooks
            </Link>
          </div>
        </div>

        <div className="mb-8">
          <p className="text-[13px] font-bold tracking-[0.12em] uppercase text-slate-400 mb-3">Search control telemetry (7d)</p>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 sm:gap-4">
            {[
              { label: 'Paused events', value: searchPaused7d },
              { label: 'Resumed events', value: searchResumed7d },
              { label: 'Net paused', value: netPaused7d },
              { label: 'Pause/Resume ratio', value: pauseResumeRatio7d ?? 'N/A' },
            ].map((card) => (
              <div key={card.label} className="bg-white border border-slate-200 rounded p-4">
                <div className="text-[24px] font-bold text-slate-900 leading-none">{card.value}</div>
                <div className="text-[13px] text-slate-400 mt-1.5 tracking-[0.07em] uppercase">{card.label}</div>
              </div>
            ))}
          </div>
          <div className="mt-4 bg-white border border-slate-200 rounded p-4">
            <div className="flex items-center justify-between gap-3 mb-3">
              <p className="text-[13px] font-bold tracking-[0.12em] uppercase text-slate-400">Daily trend</p>
              <span
                className={`text-[13px] font-bold px-2 py-1 rounded border ${
                  telemetryAlertLevel === 'risk'
                    ? 'text-red-700 bg-red-50 border-red-200'
                    : telemetryAlertLevel === 'watch'
                      ? 'text-amber-700 bg-amber-50 border-amber-200'
                      : 'text-emerald-700 bg-emerald-50 border-emerald-200'
                }`}
              >
                {telemetryAlertLevel === 'risk' ? 'At risk' : telemetryAlertLevel === 'watch' ? 'Watch' : 'Healthy'}
              </span>
            </div>
            <p className="text-[13px] text-slate-500 mb-3">
              Last 3d net: <span className="font-semibold text-slate-700">{netPausedLast3d > 0 ? `+${netPausedLast3d}` : netPausedLast3d}</span>
              {' '}({positiveNetDaysLast3d}/3 days positive)
            </p>
            <div className="space-y-2">
              {pauseResumeTrend7d.map((row) => (
                <div key={row.dayKey} className="grid grid-cols-[84px_1fr_44px] items-center gap-3 text-[13px]">
                  <span className="text-slate-500">{row.label}</span>
                  <div className="grid grid-cols-2 gap-2">
                    <progress
                      max={trendPeak}
                      value={row.paused}
                      title={`Paused: ${row.paused}`}
                      className="w-full h-2 [&::-webkit-progress-bar]:bg-slate-100 [&::-webkit-progress-value]:bg-slate-900 [&::-moz-progress-bar]:bg-slate-900"
                    />
                    <progress
                      max={trendPeak}
                      value={row.resumed}
                      title={`Resumed: ${row.resumed}`}
                      className="w-full h-2 [&::-webkit-progress-bar]:bg-slate-100 [&::-webkit-progress-value]:bg-emerald-500 [&::-moz-progress-bar]:bg-emerald-500"
                    />
                  </div>
                  <span className={`text-right font-semibold ${row.net > 0 ? 'text-amber-700' : row.net < 0 ? 'text-emerald-700' : 'text-slate-500'}`}>
                    {row.net > 0 ? `+${row.net}` : row.net}
                  </span>
                </div>
              ))}
            </div>
            <div className="mt-3 flex items-center gap-4 text-[13px] text-slate-400">
              <span><span className="inline-block w-2 h-2 rounded bg-slate-900 mr-1" />Paused</span>
              <span><span className="inline-block w-2 h-2 rounded bg-emerald-500 mr-1" />Resumed</span>
              <span>Net shown at right</span>
            </div>
          </div>
        </div>

        <section id="role-path-ranking" className="bg-white border border-slate-200 rounded p-6 mb-6">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-1">Role Path Ranking Debug</h2>
          <p className="text-[13px] text-slate-400 mb-4">Live homepage order inputs from click volume and conversion behavior (90d window).</p>
          {rolePathPriorityDebug.length === 0 ? (
            <p className="text-[13px] text-slate-500">No role-path ranking data yet. Confirm footer click traffic and analytics credentials.</p>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-[13px] min-w-[760px]">
                <thead>
                  <tr className="text-left text-slate-400 border-b border-slate-100">
                    <th className="py-2 pr-3 font-semibold">Rank</th>
                    <th className="py-2 pr-3 font-semibold">CTA key</th>
                    <th className="py-2 pr-3 font-semibold text-right">Clicks</th>
                    <th className="py-2 pr-3 font-semibold text-right">Anon est.</th>
                    <th className="py-2 pr-3 font-semibold text-right">Conv users</th>
                    <th className="py-2 pr-3 font-semibold text-right">Conv rate</th>
                    <th className="py-2 font-semibold text-right">Score</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {rolePathPriorityDebug.map((row) => (
                    <tr key={row.ctaKey}>
                      <td className="py-2 pr-3 font-semibold text-slate-900">#{row.rank}</td>
                      <td className="py-2 pr-3 text-slate-700">{row.ctaKey}</td>
                      <td className="py-2 pr-3 text-right text-slate-800">{row.clicks}</td>
                      <td className="py-2 pr-3 text-right text-slate-500">{row.anonymousClickEstimate}</td>
                      <td className="py-2 pr-3 text-right text-slate-800">{row.conversionUsers}</td>
                      <td className="py-2 pr-3 text-right text-slate-800">{(row.conversionRate * 100).toFixed(1)}%</td>
                      <td className="py-2 text-right text-slate-900 font-semibold">{row.score.toFixed(4)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </section>

        <section id="go-no-go" className="bg-white border border-slate-200 rounded p-6 mb-6">
          <div className="flex items-center justify-between gap-3 mb-4">
            <div>
              <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400">Go/No-Go Scorecard</h2>
              <p className="text-[13px] text-slate-400 mt-1">Auto-evaluated from current measurable thresholds.</p>
            </div>
            <div className={`text-[13px] font-bold px-3 py-1.5 rounded border ${statusClass(decision.status)}`}>
              {decision.label}
            </div>
          </div>
          <p className="text-[13px] text-slate-600 mb-4">{decision.reason}</p>
          <div className="space-y-2">
            {scoreRows.map((row) => (
              <div key={row.label} className="border border-slate-200 rounded px-4 py-3">
                <div className="flex items-center justify-between gap-3">
                  <div className="min-w-0">
                    <p className="text-[13px] font-semibold text-slate-900 truncate">{row.label}</p>
                    <p className="text-[13px] text-slate-400">Threshold: {row.threshold}</p>
                  </div>
                  <span className={`text-[13px] font-bold px-2.5 py-1 rounded border shrink-0 ${statusClass(row.status)}`}>{row.value}</span>
                </div>
                {row.note && <p className="text-[13px] text-slate-500 mt-1.5">{row.note}</p>}
              </div>
            ))}
          </div>
        </section>

        {/* Subscriber summary */}
        <section id="subscriber-summary" className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-4 mb-6">
          {[
            { label: 'Total users',   value: String(totalUsers    ?? 0), highlight: false },
            { label: 'Active (paid)', value: String(paidUsers     ?? 0), highlight: false },
            { label: 'Trialing',      value: String(trialingUsers ?? 0), highlight: false },
            { label: 'Placed',        value: String(placements.length),  highlight: false },
            { label: 'New (7d)',       value: String(signups7d),          highlight: false },
            { label: 'Stripe MRR',    value: stripeMrr !== null ? `$${stripeMrr.toLocaleString()}` : '--', highlight: true },
          ].map(({ label, value, highlight }) => (
            <div key={label} className="bg-white border border-slate-200 rounded p-5">
              <div className={`text-[28px] font-bold ${highlight ? 'text-orange-500' : 'text-slate-900'}`}>{value}</div>
              <div className="text-[13px] text-slate-400 mt-1">{label}</div>
            </div>
          ))}
        </section>

        {/* System health */}
        <section id="system-health" className="bg-white border border-slate-200 rounded p-5 mb-6">
          <div className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-3">System Health</div>
          <div className="flex items-center gap-3 mb-3">
            <span className={`w-2 h-2 rounded-full flex-shrink-0 ${briefingStale ? 'bg-red-500' : briefingConfiguredProfiles.length === 0 ? 'bg-slate-300' : 'bg-green-500'}`} />
            <span className="text-[13px] text-slate-700">
              Briefing worker{' '}
              {briefingConfiguredProfiles.length === 0
                ? '-- no users configured'
                : briefingHoursAgo !== null
                  ? `-- last sent ${briefingHoursAgo}h ago`
                  : '-- never sent'}
            </span>
            {briefingStale && (
              <span className="text-[13px] font-bold text-red-600 bg-red-50 px-2 py-0.5 rounded">STALE</span>
            )}
          </div>
          <div className="flex items-center gap-3">
            <span className={`w-2 h-2 rounded-full flex-shrink-0 ${
              executiveResearchStatus === 'healthy'
                ? 'bg-green-500'
                : executiveResearchStatus === 'degraded'
                  ? 'bg-red-500'
                  : executiveResearchStatus === 'stale'
                    ? 'bg-amber-500'
                    : 'bg-slate-300'
            }`} />
            <span className="text-[13px] text-slate-700">
              Executive research refresh{' '}
              {latestExecutiveResearchRun
                ? `-- last run ${executiveResearchHoursAgo ?? '-'}h ago • checked ${latestExecutiveResearchRun.checked_count ?? 0} • changed ${latestExecutiveResearchRun.changed_count ?? 0}`
                : '-- no runs yet'}
            </span>
            <span className={`text-[13px] font-bold px-2 py-0.5 rounded ${
              executiveResearchStatus === 'healthy'
                ? 'text-green-700 bg-green-50'
                : executiveResearchStatus === 'degraded'
                  ? 'text-red-700 bg-red-50'
                  : executiveResearchStatus === 'stale'
                    ? 'text-amber-700 bg-amber-50'
                    : 'text-slate-500 bg-slate-100'
            }`}>
              {executiveResearchStatus.toUpperCase()}
            </span>
            <span className="text-[13px] text-slate-500">
              Sources: {executiveResearchSourceCount ?? 0} • Failures: {executiveResearchFailureCount ?? 0}
            </span>
          </div>
          <p className="text-[13px] text-slate-500 mt-2">
            API: <span className="font-mono">/api/admin/executive-research/health</span>
          </p>
        </section>

        {/* Team summary */}
        <section id="team-summary" className="bg-white border border-slate-200 rounded overflow-hidden mb-6">
          <div className="px-6 py-[18px] border-b border-slate-200 flex items-center justify-between">
            <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400">Team</h2>
            <Link href="/dashboard/admin/team" className="text-[13px] text-slate-500 hover:text-slate-700">Manage Team</Link>
          </div>
          <div className="divide-y divide-slate-50">
            {teamMembers.map(m => (
              <div key={m.id} className="px-6 py-3 flex items-center justify-between">
                <span className="text-[13px] text-slate-900">{m.email}</span>
                <span className={`text-[13px] font-bold px-2 py-0.5 rounded ${roleBadge(m.role)}`}>{m.role}</span>
              </div>
            ))}
          </div>
        </section>

        <section id="internal-pages" className="bg-white border border-slate-200 rounded p-5 mb-6">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-3">Internal navigation</h2>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 text-[13px]">
            <div className="border border-slate-200 rounded p-4">
              <p className="text-[13px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-2">Go to market</p>
              <div className="grid grid-cols-1 gap-2">
                <Link href="/dashboard/admin/sales-enablement" className="border border-slate-200 rounded px-3 py-2 hover:border-slate-400 transition-colors">Sales enablement control room</Link>
                <Link href="/dashboard/admin/revenue" className="border border-slate-200 rounded px-3 py-2 hover:border-slate-400 transition-colors">Revenue and conversion</Link>
                <Link href="/dashboard/admin/product" className="border border-slate-200 rounded px-3 py-2 hover:border-slate-400 transition-colors">Product ops</Link>
              </div>
            </div>
            <div className="border border-slate-200 rounded p-4">
              <p className="text-[13px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-2">Platform operations</p>
              <div className="grid grid-cols-1 gap-2">
                <Link href="/dashboard/admin/operations" className="border border-slate-200 rounded px-3 py-2 hover:border-slate-400 transition-colors">Operations</Link>
                <Link href="/dashboard/admin/onboarding/video" className="border border-slate-200 rounded px-3 py-2 hover:border-slate-400 transition-colors">Onboarding video timeline</Link>
                <Link href="/dashboard/admin/team" className="border border-slate-200 rounded px-3 py-2 hover:border-slate-400 transition-colors">Team and permissions</Link>
              </div>
            </div>
          </div>
        </section>

        {/* Six-actions funnel */}
        <section id="six-actions-funnel" className="bg-white border border-slate-200 rounded p-6 mb-6">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-1">Six-Actions Funnel</h2>
          <p className="text-[13px] text-slate-400 mb-6">Trialing + active users (n={activeUserIds.size})</p>
          <FunnelChart data={funnelData} />
          <table className="w-full mt-4 text-[13px]">
            <thead>
              <tr className="text-left text-slate-400">
                <th className="py-1 font-semibold">Step</th>
                <th className="py-1 font-semibold text-right">Users</th>
                <th className="py-1 font-semibold text-right">%</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {funnelData.map(row => (
                <tr key={row.step}>
                  <td className="py-2 text-slate-700">{STEP_LABELS[row.step] ?? row.step}</td>
                  <td className="py-2 text-right font-semibold text-slate-900">{row.count}</td>
                  <td className="py-2 text-right text-slate-400">{Math.round((row.count / denominator) * 100)}%</td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>

        {/* Event volume */}
        <section id="event-volume" className="bg-white border border-slate-200 rounded p-6 mb-6">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-1">Event Volume (30d)</h2>
          <p className="text-[13px] text-slate-400 mb-6">7d counts in right column</p>
          {eventVolumeData.length === 0 ? (
            <p className="text-[13px] text-slate-400">No events yet.</p>
          ) : (
            <>
              <EventVolumeChart data={eventVolumeData} />
              <table className="w-full mt-4 text-[13px]">
                <thead>
                  <tr className="text-left text-slate-400">
                    <th className="py-1 font-semibold">Event</th>
                    <th className="py-1 font-semibold text-right">30d</th>
                    <th className="py-1 font-semibold text-right">7d</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {eventVolumeData.map(row => (
                    <tr key={row.event_name}>
                      <td className="py-2 text-slate-700 font-mono text-[13px]">{row.event_name}</td>
                      <td className="py-2 text-right font-semibold text-slate-900">{row.count}</td>
                      <td className="py-2 text-right text-slate-400">{eventCounts7d[row.event_name] ?? 0}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </>
          )}
        </section>

        {/* Trial conversion */}
        <section id="trial-conversion" className="bg-white border border-slate-200 rounded p-6 mb-6">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-1">Trial Conversion</h2>
          <p className="text-[13px] text-slate-400 mb-5">Users whose 30-day trial window has closed</p>
          <div className={`mb-5 border rounded p-4 ${linkedInAdsGatePass ? 'border-green-200 bg-green-50' : 'border-amber-200 bg-amber-50'}`}>
            <div className="flex items-center justify-between gap-3 mb-1">
              <p className="text-[13px] font-bold tracking-[0.1em] uppercase text-slate-500">LinkedIn Ads Gate</p>
              <span className={`text-[13px] font-bold px-2 py-0.5 rounded ${linkedInAdsGatePass ? 'bg-green-600 text-white' : 'bg-amber-600 text-white'}`}>
                {linkedInAdsDecision}
              </span>
            </div>
            <p className="text-[13px] text-slate-600">
              Requires trial-to-paid conversion of at least {linkedInAdsThreshold}%. Current: {conversionRate !== null ? `${conversionRate}%` : 'N/A'}.
            </p>
            {!linkedInAdsGatePass && (
              <p className="text-[13px] text-slate-500 mt-1">
                Paid ads stay deferred until this threshold is reached.
              </p>
            )}
          </div>
          {totalEnded === 0 ? (
            <p className="text-[13px] text-slate-400">No ended trials yet.</p>
          ) : (
            <>
              <div className="grid grid-cols-3 gap-6 mb-6">
                {[
                  { label: 'Trials ended', value: String(totalEnded), highlight: false },
                  { label: 'Converted to paid', value: String(totalConverted), highlight: false },
                  { label: 'Conversion rate', value: conversionRate !== null ? `${conversionRate}%` : '-', highlight: true, rate: conversionRate },
                ].map(({ label, value, highlight, rate }) => (
                  <div key={label}>
                    <div className={`text-[28px] font-bold ${
                      highlight && rate !== null && rate !== undefined
                        ? rate >= 40 ? 'text-green-600' : rate >= 20 ? 'text-amber-600' : 'text-red-600'
                        : 'text-slate-900'
                    }`}>{value}</div>
                    <div className="text-[13px] text-slate-400 mt-1">{label}</div>
                  </div>
                ))}
              </div>
              {channelRows.length > 0 && (
                <div>
                  <p className="text-[13px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-3">By channel</p>
                  <table className="w-full text-[13px]">
                    <thead>
                      <tr className="text-left border-b border-slate-100">
                        <th className="pb-2 font-semibold text-slate-400">Source</th>
                        <th className="pb-2 font-semibold text-slate-400 text-right">Trials</th>
                        <th className="pb-2 font-semibold text-slate-400 text-right">Converted</th>
                        <th className="pb-2 font-semibold text-slate-400 text-right">Rate</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {channelRows.map(r => (
                        <tr key={r.channel}>
                          <td className="py-2 font-mono text-slate-600">{r.channel}</td>
                          <td className="py-2 text-right text-slate-500">{r.ended}</td>
                          <td className="py-2 text-right text-slate-500">{r.converted}</td>
                          <td className={`py-2 text-right font-semibold ${
                            r.rate >= 40 ? 'text-green-600' : r.rate >= 20 ? 'text-amber-600' : 'text-red-600'
                          }`}>{r.rate}%</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </>
          )}
        </section>

        <section id="active-trials" className="bg-white border border-slate-200 rounded p-5 mb-6">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-2">Trial watchlist</h2>
          <p className="text-[13px] text-slate-600">Active trials: {trialUsers.length}</p>
        </section>

        {/* Signal to action rate */}
        <details id="signal-action-rate" className="bg-white border border-slate-200 rounded p-6 mb-6">
          <summary className="cursor-pointer text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400">Signal &rarr; Action Rate</summary>
          <div className="pt-4">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-1">Signal Action Rate</h2>
          <p className="text-[13px] text-slate-400 mb-5">Signals that triggered outreach, brief gen, or contact add within 48h</p>
          {signalRows.length === 0 ? (
            <p className="text-[13px] text-slate-400">No signals yet.</p>
          ) : (
            <table className="w-full text-[13px]">
              <thead>
                <tr className="text-left text-slate-400 border-b border-slate-100">
                  <th className="py-2 font-semibold">Signal type</th>
                  <th className="py-2 font-semibold text-right">Total</th>
                  <th className="py-2 font-semibold text-right">Acted</th>
                  <th className="py-2 font-semibold text-right">Rate</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {signalRows.map(row => (
                  <tr key={row.type}>
                    <td className="py-2.5 text-slate-700">{row.label}</td>
                    <td className="py-2.5 text-right text-slate-400">{row.total}</td>
                    <td className="py-2.5 text-right font-semibold text-slate-900">{row.acted}</td>
                    <td className="py-2.5 text-right">
                      <span className={`font-bold ${row.rate >= 50 ? 'text-green-600' : row.rate >= 25 ? 'text-amber-600' : 'text-slate-400'}`}>
                        {row.rate}%
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
          </div>
        </details>

        <section id="partners" className="bg-white border border-slate-200 rounded p-5">
          <h2 className="text-[13px] font-bold tracking-[0.14em] uppercase text-slate-400 mb-2">Commercial snapshot</h2>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 text-[13px]">
            <div className="border border-slate-200 rounded px-3 py-2">Partners: <span className="font-semibold">{partners.length}</span></div>
            <div className="border border-slate-200 rounded px-3 py-2">B2B accounts: <span className="font-semibold">{b2bAccounts.length}</span></div>
            <div className="border border-slate-200 rounded px-3 py-2">Placements: <span className="font-semibold">{placements.length}</span></div>
            <div className="border border-slate-200 rounded px-3 py-2">Avg context: <span className="font-semibold">{avgContextScore ?? 'N/A'}</span></div>
          </div>
        </section>

      </main>
    </div>
  )
}

'use client'

import { useEffect, useMemo, useState } from 'react'
import { detectLegacyTemplateCopy } from '@/lib/outreach/legacy-copy-guard'

const STATUS_OPTIONS = [
  { value: 'all', label: 'All Statuses' },
  { value: 'prospect', label: 'Prospect' },
  { value: 'reached_out', label: 'Reached Out' },
  { value: 'in_conversation', label: 'In Conversation' },
  { value: 'meeting_scheduled', label: 'Meeting Set' },
  { value: 'closed', label: 'Closed' },
]

const CHANNEL_OPTIONS = [
  { value: 'executives', label: 'Executives' },
  { value: 'search_firms', label: 'Search Firms' },
  { value: 'coaches', label: 'Coaches' },
  { value: 'outplacement_firms', label: 'Outplacement Firms' },
] as const

const CONFIDENCE_OPTIONS = [
  { value: 'high', label: 'High Confidence' },
  { value: 'medium', label: 'Medium Confidence' },
  { value: 'low', label: 'Low Confidence' },
  { value: 'all', label: 'All Confidence' },
] as const

const FOLLOW_UP_BATCH_SIZE = 5
const FOLLOW_UP_BATCH_DELAY_MS = 1250
const FOLLOW_UP_RETRY_DELAY_MS = 1500
const COACH_WORKSHEET_URL = 'https://startingmonday.app/for-coaches/coach-prep-worksheet'
const FOLLOW_UP_MAX_ATTEMPTS = 2
const FOLLOW_UP_CAMPAIGN_STEP = 'followup_bulk_v1'
const FOLLOW_UP_POLL_INITIAL_DELAY_MS = 1500
const FOLLOW_UP_POLL_MAX_DELAY_MS = 10000
const FOLLOW_UP_POLL_TIMEOUT_MS = 180000

type ProspectRow = {
  fullName: string
  roleBucket: string
  company: string
  email: string
  emailConfidence: 'high' | 'medium' | 'low'
  status: string
  followUpSent: boolean
  hasLiveOutreach: boolean
  emailOpening: string
  emailBodyCore: string
  defaultSubject: string
  defaultBody: string
  outreachChannel: 'executives' | 'search_firms' | 'coaches' | 'outplacement_firms'
  fitTier: 'strong' | 'medium'
  personaFocus: string
  campaignTag?: 'coach_day1_60'
}

type Props = {
  rows: ProspectRow[]
  fromAddressLabel: string
  buildVersion: string
}

type ErrorDisplay = {
  title: string
  detail: string
  rawReason?: string
}

type BatchStatusSummary = {
  totalJobs: number
  queuedJobs: number
  sendingJobs: number
  acceptedJobs: number
  deliveredJobs: number
  bouncedJobs: number
  complainedJobs: number
  repliedJobs: number
  failedJobs: number
  completedJobs: number
  failedRecipients: Array<{ jobId: string; recipientEmail: string; code: string; message: string }>
}

export { detectLegacyTemplateCopy }

function legacyCopyBlockedError(hits: string[]): ErrorDisplay {
  return {
    title: 'Legacy draft blocked',
    detail: 'Legacy outreach copy markers were detected in this draft. Sending is blocked to prevent stale templates from going out.',
    rawReason: hits.join(', '),
  }
}

function parseJsonObject(value: string): Record<string, unknown> | null {
  try {
    const parsed = JSON.parse(value)
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return parsed as Record<string, unknown>
    }
    return null
  } catch {
    return null
  }
}

function toStringList(value: unknown): string[] {
  return Array.isArray(value) ? value.map(String) : []
}

async function readApiPayload(response: Response): Promise<{ payload: Record<string, unknown>; fallbackError: string }> {
  const fallbackError = `Request failed (${response.status})`
  const rawText = await response.text().catch(() => '')

  if (!rawText.trim()) {
    return { payload: {}, fallbackError }
  }

  const parsed = parseJsonObject(rawText)
  if (parsed) {
    return { payload: parsed, fallbackError }
  }

  return {
    payload: { error: `${fallbackError}: ${rawText.trim().slice(0, 220)}` },
    fallbackError,
  }
}

function isHtmlErrorPayload(value: string): boolean {
  const normalized = value.trim().toLowerCase()
  return normalized.includes('<!doctype html') || normalized.includes('<html')
}

function isTransientFollowUpError(value: string): boolean {
  const normalized = value.trim().toLowerCase()
  return normalized.includes('request failed (502)')
    || normalized.includes('request failed (503)')
    || normalized.includes('request failed (504)')
    || normalized.includes('internal server error')
    || isHtmlErrorPayload(normalized)
}

function normalizeFollowUpFailureReason(value: string): string {
  if (isHtmlErrorPayload(value)) {
    return 'Send route returned an HTML 502/503 page instead of JSON.'
  }

  return value
}

export function formatOutreachErrorMessage(error: string | null | undefined, sendMode: 'dry_run' | 'test_to_self' | 'live'): ErrorDisplay {
  const normalized = (error ?? '').trim()

  if (!normalized) {
    return {
      title: 'Email was not sent',
      detail: sendMode === 'test_to_self'
        ? 'The test email did not go out. Review the message and try again.'
        : 'The outreach message did not go out. Review the details below and try again.',
    }
  }

  if (normalized.toLowerCase().startsWith('blocked by email council gate:')) {
    return {
      title: 'Send blocked before delivery',
      detail: 'This draft did not meet the live email quality gate, so no email was sent. Tighten the copy and run a test to yourself before sending live.',
      rawReason: normalized,
    }
  }

  if (normalized === 'Recipient is suppressed. Remove suppression before sending.') {
    return {
      title: 'Recipient is suppressed',
      detail: 'This contact is currently blocked from outreach. Remove the suppression entry before trying again.',
    }
  }

  if (normalized === 'Could not resolve test recipient email.') {
    return {
      title: 'Test send could not start',
      detail: 'Your account email could not be resolved for Send Test To Me. Confirm your signed-in user has a valid email address.',
    }
  }

  if (normalized === 'OUTREACH_FROM_ADDRESS must use richard@startingmonday.app.') {
    return {
      title: 'Sender configuration error',
      detail: 'The outreach sender is misconfigured in the environment. No email was sent.',
    }
  }

  return {
    title: 'Email was not sent',
    detail: sendMode === 'test_to_self'
      ? 'The test email failed before delivery.'
      : 'The outreach email failed before delivery.',
    rawReason: normalized,
  }
}

function followUpIdempotencyKey(row: ProspectRow): string {
  return `${FOLLOW_UP_CAMPAIGN_STEP}:${row.email.toLowerCase()}`
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => {
    setTimeout(resolve, ms)
  })
}

async function sendFollowUpRequest(target: ProspectRow, mode: 'dry_run' | 'test_to_self' | 'live', batchId: string) {
  const res = await fetch('/api/outreach/send', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      fullName: target.fullName,
      company: target.company,
      roleBucket: target.roleBucket,
      emailTo: target.email,
      statusAfter: 'reached_out',
      mode,
      outreachChannel: target.outreachChannel,
      fitTier: target.fitTier,
      personaFocus: target.personaFocus,
      useLatestTemplateDraft: true,
      templateStep: 'followup_1',
      campaignStep: FOLLOW_UP_CAMPAIGN_STEP,
      idempotencyKey: followUpIdempotencyKey(target),
      batchId,
    }),
  })

  const { payload, fallbackError } = await readApiPayload(res)

  if (!res.ok) {
    const reason = typeof payload.error === 'string' && payload.error.trim().length > 0
      ? payload.error
      : fallbackError
    return {
      ok: false as const,
      duplicate: false,
      reason,
      transient: isTransientFollowUpError(reason),
      batchId: null,
    }
  }

  return {
    ok: true as const,
    duplicate: payload.duplicate === true,
    reason: '',
    transient: false,
    batchId: typeof payload.batchId === 'string' ? payload.batchId : null,
  }
}

async function sendFollowUpWithRetry(target: ProspectRow, mode: 'dry_run' | 'test_to_self' | 'live', batchId: string) {
  for (let attempt = 1; attempt <= FOLLOW_UP_MAX_ATTEMPTS; attempt += 1) {
    const result = await sendFollowUpRequest(target, mode, batchId)
    if (result.ok || !result.transient || attempt === FOLLOW_UP_MAX_ATTEMPTS) {
      return result
    }

    await sleep(FOLLOW_UP_RETRY_DELAY_MS)
  }

  return {
    ok: false as const,
    duplicate: false,
    reason: 'Unknown follow-up retry failure.',
    transient: false,
    batchId: null,
  }
}

async function pollOutreachBatchStatus(batchId: string): Promise<{ ok: true; status: string; summary: BatchStatusSummary } | { ok: false; reason: string }> {
  const startedAt = Date.now()
  let delayMs = FOLLOW_UP_POLL_INITIAL_DELAY_MS

  while (Date.now() - startedAt < FOLLOW_UP_POLL_TIMEOUT_MS) {
    const res = await fetch(`/api/outreach/send/batch-status?batchId=${encodeURIComponent(batchId)}`, {
      method: 'GET',
      cache: 'no-store',
    })
    const { payload, fallbackError } = await readApiPayload(res)
    if (!res.ok) {
      return {
        ok: false,
        reason: typeof payload.error === 'string' && payload.error.trim().length > 0 ? payload.error : fallbackError,
      }
    }

    const status = typeof payload.status === 'string' ? payload.status : 'queued'
    const summary = (payload.summary ?? {}) as BatchStatusSummary
    if (status === 'completed' || status === 'completed_with_failures') {
      return { ok: true, status, summary }
    }

    await sleep(delayMs)
    delayMs = Math.min(Math.floor(delayMs * 1.5), FOLLOW_UP_POLL_MAX_DELAY_MS)
  }

  return { ok: false, reason: 'Timed out waiting for batch completion.' }
}

function prefillForRow(row: ProspectRow): { subject: string; body: string } {
  void row
  return {
    subject: '',
    body: '',
  }
}

function statusBadge(status: string): string {
  if (status === 'reached_out') return 'bg-blue-50 text-blue-700'
  if (status === 'in_conversation') return 'bg-amber-50 text-amber-700'
  if (status === 'meeting_scheduled') return 'bg-green-50 text-green-700'
  if (status === 'closed') return 'bg-slate-200 text-slate-600'
  return 'bg-slate-100 text-slate-600'
}

function statusText(status: string): string {
  const hit = STATUS_OPTIONS.find(s => s.value === status)
  return hit?.label ?? 'Prospect'
}

export function OutreachHubClient({ rows, fromAddressLabel, buildVersion }: Props) {
  const [items, setItems] = useState(rows)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('all')
  const [confidenceFilter, setConfidenceFilter] = useState<'all' | 'high' | 'medium' | 'low'>('high')
  const [activeChannel, setActiveChannel] = useState<'executives' | 'search_firms' | 'coaches' | 'outplacement_firms'>('executives')
  const [activeCampaign, setActiveCampaign] = useState<'all' | 'coach_day1_60'>('all')
  const [selectedIndex, setSelectedIndex] = useState<number>(0)
  const [subject, setSubject] = useState('')
  const [messageText, setMessageText] = useState('')
  const [sendMode, setSendMode] = useState<'dry_run' | 'test_to_self' | 'live'>('dry_run')
  const [confirmLive, setConfirmLive] = useState(false)
  const [sending, setSending] = useState(false)
  const [templateLoading, setTemplateLoading] = useState(false)
  const [sendingFollowUps, setSendingFollowUps] = useState(false)
  const [suppressing, setSuppressing] = useState(false)
  const [saveBusyEmail, setSaveBusyEmail] = useState<string | null>(null)
  const [error, setError] = useState<ErrorDisplay | null>(null)
  const [success, setSuccess] = useState<string | null>(null)
  const [guardrailWarnings, setGuardrailWarnings] = useState<string[]>([])
  const [guardrailViolations, setGuardrailViolations] = useState<string[]>([])
  const [googleFollowUp3Url, setGoogleFollowUp3Url] = useState<string | null>(null)
  const [googleFollowUp7Url, setGoogleFollowUp7Url] = useState<string | null>(null)

  function insertCoachWorksheetLink() {
    setMessageText((current) => {
      const normalized = current.replace(/\r\n/g, '\n').trim()
      if (normalized.includes(COACH_WORKSHEET_URL)) return current

      const linkLine = `Here is the one-page coach prep worksheet: ${COACH_WORKSHEET_URL}`
      if (!normalized) return linkLine
      return `${normalized}\n\n${linkLine}`
    })
  }

  // Load current Supabase contact status for all rows on mount
  useEffect(() => {
    const emails = rows.map(r => r.email)
    if (emails.length === 0) return

    fetch('/api/outreach/current-status', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ emails }),
    })
      .then(res => res.json())
      .then(data => {
        const statusByEmail = data.statusByEmail ?? {}
        const merged = rows.map(r => {
          const dbStatus = statusByEmail[r.email]
          return {
            ...r,
            status: dbStatus?.outreach_status ?? r.status,
          }
        })
        setItems(merged)
      })
      .catch(err => console.error('Failed to fetch current statuses:', err))
  }, [rows])

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase()
    return items.filter((r) => {
      const matchesChannel = r.outreachChannel === activeChannel
      const matchesCampaign = activeCampaign === 'all' || r.campaignTag === activeCampaign
      const matchesStatus = statusFilter === 'all' || r.status === statusFilter
      const matchesConfidence = confidenceFilter === 'all' || r.emailConfidence === confidenceFilter
      const matchesQuery = !q
        || r.fullName.toLowerCase().includes(q)
        || r.company.toLowerCase().includes(q)
        || r.roleBucket.toLowerCase().includes(q)
        || r.email.toLowerCase().includes(q)
      return matchesChannel && matchesCampaign && matchesStatus && matchesConfidence && matchesQuery
    })
  }, [items, search, statusFilter, confidenceFilter, activeChannel, activeCampaign])

  const selected = filtered[selectedIndex] ?? filtered[0] ?? null
  const isCoachComposer = selected?.outreachChannel === 'coaches'
  const followUpTargets = useMemo(() => items.filter(r => r.status === 'reached_out' && !r.followUpSent && r.hasLiveOutreach), [items])

  async function hydrateTemplateForRow(row: ProspectRow) {
    setTemplateLoading(true)
    setSubject('')
    setMessageText('')
    try {
      const response = await fetch('/api/outreach/template', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          fullName: row.fullName,
          company: row.company,
          roleBucket: row.roleBucket,
          outreachChannel: row.outreachChannel,
          personaFocus: row.personaFocus,
          templateStep: 'first_touch',
        }),
      })

      const { payload } = await readApiPayload(response)
      if (!response.ok) {
        setError({
          title: 'Template refresh failed',
          detail: 'Could not load the latest server template for this row. Sending is blocked until template refresh succeeds.',
        })
        return
      }

      const nextSubject = typeof payload.subject === 'string' ? payload.subject : ''
      const nextBody = typeof payload.body === 'string' ? payload.body : ''
      if (nextSubject.trim() && nextBody.trim()) {
        setSubject(nextSubject)
        setMessageText(nextBody)
        setError(null)
      }
    } finally {
      setTemplateLoading(false)
    }
  }

  useEffect(() => {
    const row = filtered[selectedIndex] ?? filtered[0]
    if (!row) return
    void hydrateTemplateForRow(row)
    setGuardrailWarnings([])
    setSuccess(null)
  }, [filtered, selectedIndex])

  function resetComposerFor(index: number) {
    const next = filtered[index]
    if (!next) return
    setSelectedIndex(index)
    void hydrateTemplateForRow(next)
    setError(null)
    setGuardrailWarnings([])
    setSuccess(null)
    setGuardrailViolations([])
    setGoogleFollowUp3Url(null)
    setGoogleFollowUp7Url(null)
    setConfirmLive(false)
  }

  async function updateStatus(email: string, fullName: string, company: string, status: string) {
    setSaveBusyEmail(email)
    setError(null)
    setSuccess(null)

    const res = await fetch('/api/outreach/status', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, fullName, company, status }),
    })
    const { payload, fallbackError } = await readApiPayload(res)

    setSaveBusyEmail(null)

    if (!res.ok) {
      setError({
        title: 'Status update failed',
        detail: (payload.error as string) ?? fallbackError,
      })
      return
    }

    setItems(prev => prev.map((r) => (r.email === email ? { ...r, status } : r)))
    setSuccess(`Updated status for ${fullName}.`)
  }

  async function sendSelected() {
    if (!selected || sending) return

    const staleHits = detectLegacyTemplateCopy(subject, messageText)
    if (staleHits.length > 0) {
      setError(legacyCopyBlockedError(staleHits))
      setGuardrailWarnings([`Legacy markers detected: ${staleHits.join(', ')}`])
      setSuccess(null)
      return
    }

    setSending(true)
    setError(null)
    setSuccess(null)
    setGuardrailWarnings([])
    setGuardrailViolations([])

    const res = await fetch('/api/outreach/send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        fullName: selected.fullName,
        company: selected.company,
        roleBucket: selected.roleBucket,
        emailTo: selected.email,
        subject,
        messageText,
        statusAfter: 'reached_out',
        mode: sendMode,
        outreachChannel: selected.outreachChannel,
        fitTier: selected.fitTier,
        personaFocus: selected.personaFocus,
      }),
    })

    const { payload: data, fallbackError } = await readApiPayload(res)
    setSending(false)

    if (!res.ok) {
      const violations = toStringList(data.violations)
      const warnings = toStringList(data.warnings)
      setGuardrailViolations(violations)
      setGuardrailWarnings(warnings)
      const resolvedError = typeof data.error === 'string' && data.error.trim().length > 0
        ? data.error
        : fallbackError
      setError(formatOutreachErrorMessage(resolvedError, sendMode))
      return
    }

    const warnings = toStringList(data.warnings)
    setGuardrailWarnings(warnings)

    const maybeGoogle3 = typeof data.googleFollowUp3Url === 'string' ? data.googleFollowUp3Url : null
    const maybeGoogle7 = typeof data.googleFollowUp7Url === 'string' ? data.googleFollowUp7Url : null
    setGoogleFollowUp3Url(maybeGoogle3)
    setGoogleFollowUp7Url(maybeGoogle7)

    if (sendMode === 'live') {
      setSuccess(`Queued live send to ${selected.fullName} from ${fromAddressLabel}. Delivery updates will appear as webhooks arrive.`)
      setConfirmLive(false)
    } else if (sendMode === 'test_to_self') {
      setSuccess('Queued test email to your own inbox. Review rendering and tone before live send.')
    } else {
      setSuccess('Dry run complete. No email was sent.')
    }
  }

  async function suppressSelected() {
    if (!selected || suppressing) return

    setSuppressing(true)
    setError(null)
    setSuccess(null)

    const res = await fetch('/api/outreach/suppression', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        email: selected.email,
        reason: 'manual suppression from outreach hub',
        source: 'manual',
      }),
    })
    const { payload, fallbackError } = await readApiPayload(res)

    setSuppressing(false)

    if (!res.ok) {
      setError({
        title: 'Suppression update failed',
        detail: (payload.error as string) ?? fallbackError,
      })
      return
    }

    setItems(prev => prev.map((r) => (r.email === selected.email ? { ...r, status: 'closed' } : r)))
    setSuccess(`Suppressed ${selected.fullName}. Future sends are blocked until unsuppressed.`)
  }

  async function sendCrossChannelFollowUps() {
    if (sendingFollowUps) return
    if (followUpTargets.length === 0) {
      setError({
        title: 'No follow-up targets',
        detail: 'No contacts are currently marked Reached Out across channels.',
      })
      return
    }

    if (sendMode === 'live') {
      const confirmed = window.confirm(`Send follow-up emails to ${followUpTargets.length} reached-out contacts across all channels?`)
      if (!confirmed) return
    }

    setSendingFollowUps(true)
    setError(null)
    setSuccess(null)
    setGuardrailWarnings([])
    setGuardrailViolations([])

    let queuedCount = 0
    let preflightBlockedCount = 0
    let duplicateCount = 0
    const failures: string[] = []
    const sendQueue: ProspectRow[] = []
    const sharedBatchId = globalThis.crypto?.randomUUID?.() ?? `followup_${Date.now()}`
    let resolvedBatchId: string | null = null

    for (const target of followUpTargets) {
      const preflightRes = await fetch('/api/outreach/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          fullName: target.fullName,
          company: target.company,
          roleBucket: target.roleBucket,
          emailTo: target.email,
          statusAfter: 'followup_1_sent',
          mode: 'dry_run',
          outreachChannel: target.outreachChannel,
          fitTier: target.fitTier,
          personaFocus: target.personaFocus,
          useLatestTemplateDraft: true,
          templateStep: 'followup_1',
          campaignStep: FOLLOW_UP_CAMPAIGN_STEP,
          idempotencyKey: followUpIdempotencyKey(target),
        }),
      })

      const { payload: preflightPayload, fallbackError: preflightFallback } = await readApiPayload(preflightRes)
      if (!preflightRes.ok) {
        const reason = typeof preflightPayload.error === 'string' && preflightPayload.error.trim().length > 0
          ? preflightPayload.error
          : preflightFallback
        preflightBlockedCount += 1
        failures.push(`${target.fullName}: ${reason}`)
        continue
      }

      sendQueue.push(target)
    }

    if (sendMode === 'dry_run') {
      setSendingFollowUps(false)
      if (preflightBlockedCount > 0) {
        setError({
          title: 'Dry run found blocked follow-ups',
          detail: `${sendQueue.length} ready, ${preflightBlockedCount} blocked in preflight across all channels.`,
          rawReason: failures.slice(0, 4).join(' | '),
        })
      } else {
        setSuccess(`Dry run passed for ${sendQueue.length} follow-up emails across all channels.`)
      }
      return
    }

    for (let i = 0; i < sendQueue.length; i += FOLLOW_UP_BATCH_SIZE) {
      const batch = sendQueue.slice(i, i + FOLLOW_UP_BATCH_SIZE)

      const batchResults = await Promise.all(batch.map(async (target) => {
        const result = await sendFollowUpWithRetry(target, sendMode, sharedBatchId)
        if (!result.ok) {
          return {
            ok: false,
            duplicate: false,
            reason: `${target.fullName}: ${normalizeFollowUpFailureReason(result.reason)}`,
            batchId: null as string | null,
          }
        }

        return { ok: true, duplicate: result.duplicate, reason: '', batchId: result.batchId }
      }))

      for (const result of batchResults) {
        if (!result.ok) {
          failures.push(result.reason)
          continue
        }
        if (result.duplicate) {
          duplicateCount += 1
          continue
        }
        queuedCount += 1
        if (result.batchId) {
          resolvedBatchId = result.batchId
        }
      }

      if (i + FOLLOW_UP_BATCH_SIZE < sendQueue.length) {
        await sleep(FOLLOW_UP_BATCH_DELAY_MS)
      }
    }

    if (queuedCount === 0) {
      setSendingFollowUps(false)
      if (failures.length > 0) {
        setError({
          title: 'No follow-ups were queued',
          detail: `${duplicateCount} duplicates skipped and ${preflightBlockedCount} preflight blocks across ${followUpTargets.length} targets in ${sendMode} mode.`,
          rawReason: failures.slice(0, 4).join(' | '),
        })
        return
      }

      setSuccess(`No new follow-ups queued. ${duplicateCount} duplicate sends were skipped.`)
      return
    }

    if (!resolvedBatchId) {
      setSendingFollowUps(false)
      setError({
        title: 'Batch tracking failed',
        detail: 'Follow-up jobs were queued, but no batch id was returned for status tracking.',
      })
      return
    }

    setSuccess(`Queued ${queuedCount} follow-up emails. Waiting for delivery processing...`)
    const batchStatus = await pollOutreachBatchStatus(resolvedBatchId)
    setSendingFollowUps(false)

    if (!batchStatus.ok) {
      setError({
        title: 'Batch status unavailable',
        detail: `Queued ${queuedCount} follow-ups, but could not confirm completion.`,
        rawReason: batchStatus.reason,
      })
      return
    }

    const summary = batchStatus.summary
    if (summary.failedJobs > 0 || failures.length > 0) {
      const workerFailures = (summary.failedRecipients ?? []).map(item => `${item.recipientEmail}: ${item.message}`)
      setError({
        title: 'Some follow-ups failed',
        detail: `Queued ${queuedCount}; processed ${summary.completedJobs}/${summary.totalJobs}. Failed ${summary.failedJobs}, duplicates ${duplicateCount}, preflight blocks ${preflightBlockedCount}.`,
        rawReason: [...failures, ...workerFailures].slice(0, 4).join(' | '),
      })
      return
    }

    const sentEmails = new Set(sendQueue.map((row) => row.email))
    setItems(prev => prev.map((row) => (sentEmails.has(row.email) ? { ...row, followUpSent: true } : row)))

    const deliveredLike = summary.deliveredJobs + summary.acceptedJobs + summary.repliedJobs
    setSuccess(`Completed follow-up batch: ${deliveredLike} accepted/delivered/replied, ${summary.bouncedJobs} bounced, ${summary.complainedJobs} complained. ${duplicateCount > 0 ? `${duplicateCount} duplicates were skipped.` : ''}`.trim())
  }


  const staleComposerHits = useMemo(() => detectLegacyTemplateCopy(subject, messageText), [subject, messageText])
  const staleBlocked = staleComposerHits.length > 0
  const liveBlocked = sendMode === 'live' && !confirmLive

  return (
    <section className="bg-white border border-slate-200 rounded overflow-hidden">
      <div className="px-5 py-4 border-b border-slate-100">
        <h2 className="text-[16px] font-bold text-slate-900">Send Queue</h2>
        <p className="text-[12px] text-slate-500 mt-1">Defaults to high-confidence emails. Filter by confidence and status, review content, then send from {fromAddressLabel}.</p>

        <div className="mt-3 flex flex-wrap gap-2">
          {CHANNEL_OPTIONS.map((option) => (
            <button
              key={option.value}
              type="button"
              onClick={() => {
                setActiveChannel(option.value)
                setActiveCampaign('all')
                setSelectedIndex(0)
                setSearch('')
              }}
              className={[
                'text-[12px] font-semibold px-3 py-1.5 rounded border transition-colors',
                activeChannel === option.value
                  ? 'bg-slate-900 text-white border-slate-900'
                  : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400',
              ].join(' ')}
            >
              {option.label}
            </button>
          ))}
          <button
            type="button"
            onClick={() => {
              setActiveChannel('coaches')
              setActiveCampaign('coach_day1_60')
              setSelectedIndex(0)
              setSearch('')
            }}
            className={[
              'text-[12px] font-semibold px-3 py-1.5 rounded border transition-colors',
              activeChannel === 'coaches' && activeCampaign === 'coach_day1_60'
                ? 'bg-orange-600 text-white border-orange-600'
                : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400',
            ].join(' ')}
          >
            Day 1 Coach List (60)
          </button>
          <button
            type="button"
            onClick={sendCrossChannelFollowUps}
            disabled={sendingFollowUps || sending || suppressing}
            className="text-[12px] font-semibold px-3 py-1.5 rounded border border-slate-900 bg-slate-900 text-white hover:bg-slate-700 disabled:opacity-50"
            title="Send follow-up emails to all reached-out contacts across all channels"
          >
            {sendingFollowUps
              ? 'Sending Follow-ups...'
              : `Send First Follow-Ups (Eligible${followUpTargets.length > 0 ? `: ${followUpTargets.length}` : ''})`}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-[1.2fr_1fr] min-h-[640px]">
        <div className="border-r border-slate-100">
          <div className="px-4 py-3 border-b border-slate-100 flex flex-wrap gap-2">
            <input
              value={search}
              onChange={(e) => {
                setSearch(e.target.value)
                setSelectedIndex(0)
              }}
              placeholder="Search name, company, role, email"
              className="flex-1 min-w-[220px] border border-slate-200 rounded px-3 py-2 text-[13px] text-slate-900 focus:outline-none focus:border-slate-400"
            />
            <select
              aria-label="Filter prospects by status"
              title="Filter prospects by status"
              value={statusFilter}
              onChange={(e) => {
                setStatusFilter(e.target.value)
                setSelectedIndex(0)
              }}
              className="border border-slate-200 rounded px-3 py-2 text-[13px] text-slate-900 bg-white"
            >
              {STATUS_OPTIONS.map(option => (
                <option key={option.value} value={option.value}>{option.label}</option>
              ))}
            </select>
            <select
              aria-label="Filter prospects by email confidence"
              title="Filter prospects by email confidence"
              value={confidenceFilter}
              onChange={(e) => {
