function formatDate(dateStr: string): string {
  return new Date(dateStr + 'T12:00:00Z').toLocaleDateString('en-US', {
    weekday: 'long', month: 'long', day: 'numeric',
  })
}

function hasApprovedToken(notes: string | null | undefined): boolean {
  if (!notes) return false
  return notes.includes(APPROVED_TOKEN)
}

function setApprovedToken(notes: string | null | undefined, approved: boolean): string | null {
  const tokens = (notes ?? '')
    .split('|')
    .map(token => token.trim())
    .filter(Boolean)
    .filter(token => !token.startsWith('approval_status='))

  if (approved) tokens.unshift(APPROVED_TOKEN)
  return tokens.length > 0 ? tokens.join(' | ') : null
}

function getChicagoDateParts(date: Date): { year: string; month: string; day: string } {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Chicago',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date)

  const year = parts.find(part => part.type === 'year')?.value ?? '2026'
  const month = parts.find(part => part.type === 'month')?.value ?? '01'
  const day = parts.find(part => part.type === 'day')?.value ?? '01'
  return { year, month, day }
}

function buildCalendarReminderIcs(now: Date): string {
  const { year, month, day } = getChicagoDateParts(now)
  const dtStamp = now.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z'
  const dtStart = `${year}${month}${day}T081500`
  const dtEnd = `${year}${month}${day}T083000`

  return [
    'BEGIN:VCALENDAR',
    'VERSION:2.0',
    'PRODID:-//Starting Monday//Social Review Reminder//EN',
    'CALSCALE:GREGORIAN',
    'METHOD:PUBLISH',
    'BEGIN:VEVENT',
    'UID:social-review-upcoming-posts@startingmonday.app',
    `DTSTAMP:${dtStamp}`,
    `DTSTART;TZID=America/Chicago:${dtStart}`,
    `DTEND;TZID=America/Chicago:${dtEnd}`,
    'RRULE:FREQ=WEEKLY;BYDAY=MO,WE,FR',
    'SUMMARY:Review upcoming LinkedIn posts',
    'DESCRIPTION:Open https://startingmonday.app/dashboard/admin/social and review upcoming drafts before the daily post window.',
    'LOCATION:https://startingmonday.app/dashboard/admin/social',
    'END:VEVENT',
    'END:VCALENDAR',
  ].join('\r\n')
}

function buildGoogleCalendarReminderUrl(now: Date): string {
  const { year, month, day } = getChicagoDateParts(now)
  const dates = `${year}${month}${day}T081500/${year}${month}${day}T083000`
  const params = new URLSearchParams({
    text: 'Review upcoming LinkedIn posts',
    dates,
    ctz: 'America/Chicago',
    recur: 'RRULE:FREQ=WEEKLY;BYDAY=MO,WE,FR',
    details: 'Open https://startingmonday.app/dashboard/admin/social and review upcoming drafts before the daily post window.',
    location: 'https://startingmonday.app/dashboard/admin/social',
    add: 'richard@startingmonday.app',
  })
  return `${GOOGLE_CALENDAR_EVENT_BASE}?${params.toString()}`
}

function countMatches(text: string, pattern: RegExp): number {
  const matches = text.match(pattern)
  return matches ? matches.length : 0
}

function evaluateShortFormCouncil(text: string): ShortFormCouncilCheck {
  const trimmed = text.trim()
  const characterCount = trimmed.length
  const lines = trimmed.split('\n').map(line => line.trim()).filter(Boolean)
  const firstLine = lines[0] ?? ''

  const ctaHits = countMatches(trimmed, /(comment|reply|dm|message me|send me|if you want|if this is useful|open to)/gi)
  const humorHits = countMatches(trimmed, /(funny|joke|laugh|smile|recap theater|recap theatre|ironic|irony)/gi)
  const detailHits = countMatches(trimmed, /(\d|week|today|yesterday|client|call|session|pilot|quote|"|')/gi)
  const hedgeHits = countMatches(trimmed, /(usually|often|most|in our pilot|in week one|we are seeing|pattern)/gi)
  const overclaimHits = countMatches(trimmed, /(always|never|everyone|no one|guaranteed|proves)/gi)

  const under1200 = characterCount <= 1200
  const oneCta = ctaHits >= 1 && ctaHits <= 2
  const oneHumorLineMax = humorHits <= 1
  const realDetail = detailHits >= 2
  const honestClaim = overclaimHits === 0 || hedgeHits >= 1
  const oneCoreIdea = countMatches(trimmed, /(\n\n)/g) <= 7

  const hook = firstLine.length >= 28 && firstLine.length <= 140 ? 22 : 15
  const specificity = realDetail ? 17 : 11
  const credibility = honestClaim ? 17 : 10
  const wit = oneHumorLineMax ? (humorHits === 1 ? 14 : 10) : 6
  const compression = under1200 ? (characterCount <= 1100 ? 10 : 8) : 3
  const cta = oneCta ? 9 : 5

  const score = hook + specificity + credibility + wit + compression + cta

  const recommendation: ShortFormCouncilCheck['recommendation'] =
    score >= 84 ? 'publish' : score >= 72 ? 'revise' : 'rewrite-opening'

  const topFixes: string[] = []
  if (!under1200) topFixes.push('Trim to 1200 characters or less before publishing.')
  if (!realDetail) topFixes.push('Add one lived detail: a role, week marker, or direct quote.')
  if (!oneCta) topFixes.push('Keep exactly one clear CTA in the final two lines.')
  if (!honestClaim) topFixes.push('Replace absolute claims with precise, evidence-backed language.')
  if (!oneHumorLineMax) topFixes.push('Use one subtle smile line only; remove extra humor beats.')
  if (hook < 19) topFixes.push('Rewrite the first line to be more specific and operator-level.')

  if (topFixes.length === 0) {
    topFixes.push('Strong draft. Keep the opening and publish after a final read-aloud pass.')
  }

  return {
    score,
    characterCount,
    recommendation,
    categories: { hook, specificity, credibility, wit, compression, cta },
    checks: {
      under1200,
      oneCoreIdea,
      oneCta,
      oneHumorLineMax,
      realDetail,
      honestClaim,
    },
    topFixes: topFixes.slice(0, 3),
  }
}


export function SocialClient() {
  const [state, setState] = useState<TodayResponse | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [draftText, setDraftText] = useState('')
  const [notesText, setNotesText] = useState('')
  const [saving, setSaving] = useState(false)
  const [savingNotes, setSavingNotes] = useState(false)
  const [copied, setCopied] = useState(false)
  const [markingPosted, setMarkingPosted] = useState(false)
  const [posting, setPosting] = useState(false)
  const [regenerating, setRegenerating] = useState(false)
  const [togglingApproval, setTogglingApproval] = useState(false)
  const [handoffSubmitting, setHandoffSubmitting] = useState(false)
  const [handoffMessage, setHandoffMessage] = useState('')
  const [handoffTitle, setHandoffTitle] = useState('')
  const [handoffUrl, setHandoffUrl] = useState('')
  const [handoffSummary, setHandoffSummary] = useState('')
  const [handoffAudience, setHandoffAudience] = useState('')
  const [handoffVariants, setHandoffVariants] = useState(3)
  const [handoffPillar, setHandoffPillar] = useState<(typeof PILLAR_OPTIONS)[number]['value']>('market_intel')
  const [handoffHistory, setHandoffHistory] = useState<HandoffHistoryRun[]>([])
  const [handoffHistoryLoading, setHandoffHistoryLoading] = useState(true)
  const [calendarReminderSaved, setCalendarReminderSaved] = useState(false)
  const [googleCalendarOpened, setGoogleCalendarOpened] = useState(false)
  const [councilCheck, setCouncilCheck] = useState<ShortFormCouncilCheck | null>(null)
  const [councilChecking, setCouncilChecking] = useState(false)
  const [emotionalAngle, setEmotionalAngle] = useState<EmotionalAngle>('conviction')
  const [copiedTemplate, setCopiedTemplate] = useState<number | null>(null)
  const [connectionTexts, setConnectionTexts] = useState<string[]>(
    CONNECTION_TEMPLATES.map(t => t.text)
  )

  useEffect(() => { load() }, [])

  useEffect(() => {
    if (!state?.isPostDay) return
    if (!handoffSummary.trim()) {
      const summarySeed = state.post.draft_text.split('\n').filter(Boolean).slice(0, 2).join(' ')
      setHandoffSummary(summarySeed)
    }
  }, [state, handoffSummary])

  async function load() {
    setLoading(true)
    setError('')
    try {
      const res = await fetch('/api/admin/social/today')
      if (!res.ok) { setError(`Failed to load (${res.status})`); return }
      const data: TodayResponse = await res.json()
      setState(data)
      if (data.isPostDay) {
        setDraftText(data.post.draft_text)
        setNotesText(data.post.notes ?? '')
      }
      await loadHandoffHistory()
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Unknown error')
    } finally {
      setLoading(false)
    }
  }

  async function loadHandoffHistory() {
    setHandoffHistoryLoading(true)
    try {
      const res = await fetch('/api/admin/social/handoff-approved')
      if (!res.ok) return
      const data = await res.json() as { runs?: HandoffHistoryRun[] }
      setHandoffHistory(data.runs ?? [])
    } finally {
      setHandoffHistoryLoading(false)
    }
  }

  async function handleSave() {
    if (!state?.isPostDay || saving) return
    setSaving(true)
    try {
      const res = await fetch(`/api/admin/social/${state.post.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ draft_text: draftText }),
      })
      if (!res.ok) { setError('Save failed'); return }
      const data = await res.json() as { post?: SocialPost }
      const updatedPost = data.post
      if (!updatedPost) { setError('Save failed'); return }
      setState(prev => prev?.isPostDay ? { ...prev, post: updatedPost } : prev)
    } finally {
      setSaving(false)
    }
  }

  async function handleNotesSave() {
    if (!state?.isPostDay || savingNotes) return
    setSavingNotes(true)
    try {
      await fetch(`/api/admin/social/${state.post.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ notes: notesText }),
      })
      setState(prev => prev?.isPostDay ? { ...prev, post: { ...prev.post, notes: notesText || null } } : prev)
    } finally {
      setSavingNotes(false)
    }
  }

  async function handleCopy() {
    await navigator.clipboard.writeText(draftText)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
    if (state?.isPostDay && draftText !== state.post.draft_text) await handleSave()
  }

  async function handleMarkPosted() {
    if (!state?.isPostDay || markingPosted) return
    setMarkingPosted(true)
    try {
      if (draftText !== state.post.draft_text) await handleSave()
      const res = await fetch(`/api/admin/social/${state.post.id}/mark-posted`, { method: 'POST' })
      if (!res.ok) { setError('Failed to mark posted'); return }
      const data = await res.json() as { post?: SocialPost }
      const updatedPost = data.post
      if (!updatedPost) { setError('Failed to mark posted'); return }
      setState(prev => prev?.isPostDay ? { ...prev, post: updatedPost } : prev)
    } finally {
      setMarkingPosted(false)
    }
  }

  async function handlePost() {
    if (!state?.isPostDay || posting) return
    setPosting(true)
    setError('')
    try {
      if (draftText !== state.post.draft_text) await handleSave()
      const res = await fetch(`/api/admin/social/${state.post.id}/schedule`, { method: 'POST' })
      if (!res.ok) {
        const body = await res.json().catch(() => ({})) as { error?: string; detail?: string }
        setError(body.error ?? 'Failed to post to LinkedIn')
        return
      }
      const data = await res.json() as { post?: SocialPost }
      const updatedPost = data.post
      if (!updatedPost) { setError('Failed to post to LinkedIn'); return }
      setState(prev => prev?.isPostDay ? { ...prev, post: updatedPost } : prev)
    } finally {
      setPosting(false)
    }
  }

  async function handleCopyTemplate(index: number) {
    await navigator.clipboard.writeText(connectionTexts[index])
    setCopiedTemplate(index)
    setTimeout(() => setCopiedTemplate(null), 2000)
  }

  async function handleRegenerate() {
    if (!state?.isPostDay || regenerating) return
    setRegenerating(true)
    setError('')
    try {
      await fetch(`/api/admin/social/${state.post.id}`, { method: 'DELETE' }).catch(() => {})
      const res = await fetch(`/api/admin/social/today?regen=${Date.now()}`)
      if (!res.ok) { setError('Regeneration failed'); return }
      const data: TodayResponse = await res.json()
      setState(data)
      if (data.isPostDay) {
        setDraftText(data.post.draft_text)
        setNotesText(data.post.notes ?? '')
      }
    } finally {
      setRegenerating(false)
    }
  }

  async function handleToggleApproval() {
    if (!state?.isPostDay || togglingApproval) return
    setTogglingApproval(true)
    setError('')
    try {
      const nextApproved = !hasApprovedToken(state.post.notes)
      const nextNotes = setApprovedToken(state.post.notes, nextApproved)

      const res = await fetch(`/api/admin/social/${state.post.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ notes: nextNotes }),
      })

      if (!res.ok) {
        const data = await res.json().catch(() => ({})) as { error?: string }
        setError(data.error ?? 'Failed to update approval status')
        return
      }

      const data = await res.json() as { post?: SocialPost }
      const updated = data.post
      if (updated) {
        setState(prev => prev?.isPostDay ? { ...prev, post: updated } : prev)
        setNotesText(updated.notes ?? '')
      }
    } finally {
      setTogglingApproval(false)
    }
  }

  async function handleApprovedHandoff() {
    if (!state?.isPostDay || handoffSubmitting) return
    setHandoffSubmitting(true)
    setHandoffMessage('')
    setError('')

    try {
      const title = handoffTitle.trim() || `${formatDate(state.dateStr)} approved social article`
      const summary = handoffSummary.trim() || draftText.trim()
      if (!summary) {
        setError('Article summary is required for handoff')
        return
      }

      const variants = Math.max(1, Math.min(5, Math.floor(handoffVariants || 3)))
      const approvedNotes = setApprovedToken(state.post.notes, true)

      if (!hasApprovedToken(state.post.notes)) {
        const approvalRes = await fetch(`/api/admin/social/${state.post.id}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ notes: approvedNotes }),
        })
        if (approvalRes.ok) {
          const approvalData = await approvalRes.json() as { post?: SocialPost }
          const approvedPost = approvalData.post
          if (approvedPost) {
            setState(prev => prev?.isPostDay ? { ...prev, post: approvedPost } : prev)
            setNotesText(approvedPost.notes ?? '')
          }
        }
      }

      const res = await fetch('/api/admin/social/handoff-approved', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          approvalStatus: 'approved',
          pillar: handoffPillar,
          audience: handoffAudience.trim() || undefined,
          variantCount: variants,
          article: {
            title,
            url: handoffUrl.trim() || undefined,
            summary,
            keyTakeaways: summary
              .split(/[\n\.]/)
              .map(part => part.trim())
              .filter(Boolean)
              .slice(0, 2),
          },
        }),
      })

      const data = await res.json().catch(() => ({})) as {
        error?: string
        queued?: number
        posts?: Array<{ post_date: string }>
      }

      if (!res.ok) {
        setError(data.error ?? 'Approved handoff failed')
        return
      }

      const firstDate = data.posts?.[0]?.post_date
      setHandoffMessage(
        typeof data.queued === 'number'
          ? `Queued ${data.queued} approved posts${firstDate ? ` starting ${formatDate(firstDate)}` : ''}.`
          : 'Approved handoff queued successfully.'
      )
      await loadHandoffHistory()
    } finally {
      setHandoffSubmitting(false)
    }
  }

  function handleAddCalendarReminder() {
    const ics = buildCalendarReminderIcs(new Date())
    const blob = new Blob([ics], { type: 'text/calendar;charset=utf-8' })
    const url = URL.createObjectURL(blob)
    const anchor = document.createElement('a')
    anchor.href = url
    anchor.download = REVIEW_REMINDER_FILENAME
    anchor.click()
    URL.revokeObjectURL(url)
    setCalendarReminderSaved(true)
    window.setTimeout(() => setCalendarReminderSaved(false), 2200)
  }

  function handleAddGoogleCalendarReminder() {
    const url = buildGoogleCalendarReminderUrl(new Date())
    window.open(url, '_blank', 'noopener,noreferrer')
    setGoogleCalendarOpened(true)
    window.setTimeout(() => setGoogleCalendarOpened(false), 2200)
  }

  async function handleRunShortFormCouncilCheck() {
    if (!state?.isPostDay || councilChecking || !draftText.trim()) return
    setCouncilChecking(true)
    setError('')
    try {
      const res = await fetch(`/api/admin/social/${state.post.id}/council-check`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          draftText,
          emotionalAngle,
        }),
      })

      const data = await res.json().catch(() => ({})) as {
        error?: string
        result?: ShortFormCouncilCheck
        post?: SocialPost
      }

      if (!res.ok || !data.result) {
        setError(data.error ?? 'Failed to run council check')
        return
      }

      setCouncilCheck(data.result)
      const updatedPost = data.post
      if (updatedPost) {
        setState(prev => prev?.isPostDay ? { ...prev, post: updatedPost } : prev)
        setNotesText(updatedPost.notes ?? '')
      }
    } finally {
      setCouncilChecking(false)
    }
  }

  if (loading) {
    return (
      <div className="bg-white border border-slate-200 rounded p-8 flex items-center gap-2">
        <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block" />
        <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block [animation-delay:150ms]" />
        <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block [animation-delay:300ms]" />
      </div>
    )
  }

  if (error) {
    return (
      <div className="bg-white border border-slate-200 rounded p-6">
        <p className="text-[13px] text-red-600 mb-3">{error}</p>
        <button
          type="button"
          onClick={() => { setError(''); load() }}
          className="text-[12px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 cursor-pointer bg-transparent transition-colors"
        >
          Try again
        </button>
      </div>
    )
  }

  if (!state) return null

  if (!state.isPostDay) {
    return (
      <div className="bg-white border border-slate-200 rounded p-8 text-center">
        <p className="text-[14px] font-semibold text-slate-900 mb-2">No post scheduled today.</p>
        <p className="text-[13px] text-slate-500">Posts go out every weekday with audience rotation.</p>
        {state.nextPostDays.length > 0 && (
          <p className="text-[12px] text-slate-400 mt-3">
            Next: {state.nextPostDays.map(d => formatDate(d)).join(', ')}
          </p>
        )}
      </div>
    )
  }

  const { post, pillarLabel, dateStr } = state
  const isApproved = hasApprovedToken(post.notes)
  const isDirty = draftText !== post.draft_text
  const isNotesDirty = notesText !== (post.notes ?? '')
  const busy = saving || savingNotes || markingPosted || posting || regenerating || togglingApproval || handoffSubmitting

  return (
    <div className="flex flex-col gap-4">

      {/* Date + pillar header */}
      <div className="bg-white border border-slate-200 rounded px-6 py-5 flex items-center justify-between gap-4">
        <div>
          <p className="text-[13px] font-semibold text-slate-900">{formatDate(dateStr)}</p>
          <div className="flex flex-wrap items-center gap-2 mt-1">
            <span className="text-[11px] font-bold tracking-[0.08em] uppercase bg-orange-50 text-orange-600 px-2 py-0.5 rounded">
              {pillarLabel}
            </span>
            {state.audienceLabel && (
              <span className="text-[11px] font-bold tracking-[0.08em] uppercase bg-blue-50 text-blue-700 px-2 py-0.5 rounded">
                {state.audienceLabel}
              </span>
            )}
            {state.recommendedTimeCt && !post.is_posted && (
              <span className="text-[11px] font-semibold bg-slate-100 text-slate-600 px-2 py-0.5 rounded">
                Target {state.recommendedTimeCt}
              </span>
            )}
            {post.is_posted && (
              <span className="text-[11px] font-bold bg-green-50 text-green-700 px-2 py-0.5 rounded">
                Posted {post.posted_at ? new Date(post.posted_at).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }) : ''}
              </span>
            )}
            <button
              type="button"
              onClick={handleToggleApproval}
              disabled={busy || post.is_posted}
              className={`text-[11px] font-bold px-2 py-0.5 rounded border transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer ${
                isApproved
                  ? 'bg-emerald-50 text-emerald-700 border-emerald-200 hover:border-emerald-400'
                  : 'bg-slate-100 text-slate-600 border-slate-200 hover:border-slate-400'
              }`}
            >
              {togglingApproval ? 'Saving…' : isApproved ? 'Approved' : 'Unapproved'}
            </button>
          </div>
        </div>
        <button
          type="button"
          onClick={handleRegenerate}
          disabled={busy}
          className="shrink-0 text-[12px] font-semibold text-slate-500 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 hover:text-slate-700 bg-transparent cursor-pointer disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
        >
          {regenerating ? 'Generating…' : 'Regenerate'}
        </button>
      </div>

      {/* Draft editor */}
      <div className="bg-white border border-slate-200 rounded p-6">
        <div className="flex items-center justify-between mb-3">
          <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Post Draft</p>
          {isDirty && !saving && (
            <span className="text-[11px] text-amber-600 font-medium">Unsaved edits</span>
          )}
          {saving && (
            <span className="text-[11px] text-slate-400">Saving…</span>
          )}
        </div>
        <textarea
          value={draftText}
          onChange={e => setDraftText(e.target.value)}
          onBlur={isDirty ? handleSave : undefined}
          disabled={busy}
          rows={14}
          className="w-full text-[14px] text-slate-700 leading-relaxed border border-slate-200 rounded px-4 py-3 resize-none focus:outline-none focus:border-slate-400 font-[inherit] disabled:opacity-50"
          placeholder="Draft will appear here…"
        />
        <p className="mt-1.5 text-[11px] text-slate-300">{draftText.length} characters · Edits save on blur</p>
      </div>

      {/* Character count advisory */}
      {draftText.length > 3000 && (
        <div className="px-4 py-3 bg-amber-50 border border-amber-200 rounded text-[12px] text-amber-700">
          LinkedIn limits posts to 3,000 characters. This draft is {draftText.length} characters -- trim before posting.
        </div>
      )}

      {/* Short-form council helper */}
      <div id="content-checker" className="bg-white border border-slate-200 rounded p-6">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
          <div>
            <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Run Short-Form Council Check</p>
            <p className="text-[12px] text-slate-500 mt-1">Server-enforced council gate for posts under 1200 characters.</p>
          </div>
          <div className="flex items-center gap-2">
            <select
              value={emotionalAngle}
              onChange={e => setEmotionalAngle(e.target.value as EmotionalAngle)}
              className="text-[12px] text-slate-700 border border-slate-300 rounded px-2.5 py-2 bg-white focus:outline-none focus:border-slate-500"
              title="Primary emotional angle"
            >
              {ALLOWED_EMOTIONAL_ANGLES.map(angle => (
                <option key={angle} value={angle}>{angle.replace('_', ' ')}</option>
              ))}
            </select>
            <button
              type="button"
              onClick={handleRunShortFormCouncilCheck}
              disabled={!draftText.trim() || councilChecking}
              className="text-[12px] font-semibold text-slate-700 border border-slate-300 rounded px-4 py-2 hover:border-slate-500 hover:text-slate-900 disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer transition-colors bg-transparent"
            >
              {councilChecking ? 'Checking…' : 'Run Short-Form Council Check'}
            </button>
          </div>
        </div>

        {councilCheck && (
          <div className="mt-4 border-t border-slate-100 pt-4">
            <div className="flex flex-wrap items-center gap-2 mb-3">
              <span className="text-[12px] font-bold text-slate-900">Score {councilCheck.score}/100</span>
              <span className="text-[11px] font-semibold bg-slate-100 text-slate-600 px-2 py-0.5 rounded">{councilCheck.characterCount} chars</span>
              {councilCheck.emotionalAngle && (
                <span className="text-[11px] font-semibold bg-blue-50 text-blue-700 px-2 py-0.5 rounded">
                  Angle: {councilCheck.emotionalAngle.replace('_', ' ')}
                </span>
              )}
              <span className={`text-[11px] font-semibold px-2 py-0.5 rounded ${
                councilCheck.recommendation === 'publish'
                  ? 'bg-emerald-50 text-emerald-700'
                  : councilCheck.recommendation === 'revise'
                    ? 'bg-amber-50 text-amber-700'
                    : 'bg-red-50 text-red-700'
              }`}>
                {councilCheck.recommendation === 'publish' ? 'Publish' : councilCheck.recommendation === 'revise' ? 'Revise' : 'Rewrite opening'}
              </span>
              <span className={`text-[11px] font-semibold px-2 py-0.5 rounded ${councilCheck.councilPass ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-700'}`}>
                {councilCheck.councilPass ? 'Council pass' : 'Council fail'}
              </span>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2 mb-3">
              <p className="text-[11px] text-slate-600">Hook: <span className="font-semibold text-slate-800">{councilCheck.categories.hook}/25</span></p>
              <p className="text-[11px] text-slate-600">Specificity: <span className="font-semibold text-slate-800">{councilCheck.categories.specificity}/20</span></p>
              <p className="text-[11px] text-slate-600">Credibility: <span className="font-semibold text-slate-800">{councilCheck.categories.credibility}/20</span></p>
              <p className="text-[11px] text-slate-600">Wit: <span className="font-semibold text-slate-800">{councilCheck.categories.wit}/15</span></p>
              <p className="text-[11px] text-slate-600">Compression: <span className="font-semibold text-slate-800">{councilCheck.categories.compression}/10</span></p>
              <p className="text-[11px] text-slate-600">CTA: <span className="font-semibold text-slate-800">{councilCheck.categories.cta}/10</span></p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mb-3">
              <p className="text-[11px] text-slate-600">Under 1200: <span className="font-semibold text-slate-800">{councilCheck.checks.under1200 ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">One core idea: <span className="font-semibold text-slate-800">{councilCheck.checks.oneCoreIdea ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">One CTA: <span className="font-semibold text-slate-800">{councilCheck.checks.oneCta ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">One humor line max: <span className="font-semibold text-slate-800">{councilCheck.checks.oneHumorLineMax ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">Real detail present: <span className="font-semibold text-slate-800">{councilCheck.checks.realDetail ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">Honest claim: <span className="font-semibold text-slate-800">{councilCheck.checks.honestClaim ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">Angle selected: <span className="font-semibold text-slate-800">{councilCheck.checks.emotionalAnglePresent ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">Angle rotated: <span className="font-semibold text-slate-800">{councilCheck.checks.emotionalAngleRotation ? 'PASS' : 'FAIL'}</span></p>
            </div>

            <div>
              <p className="text-[11px] font-semibold text-slate-700 mb-1">Top fixes</p>
              <ul className="list-disc pl-5 text-[11px] text-slate-600 space-y-1">
                {councilCheck.topFixes.map(fix => (
                  <li key={fix}>{fix}</li>
                ))}
              </ul>
            </div>
          </div>
        )}
      </div>

      {/* Action buttons */}
      <div className="flex flex-col sm:flex-row gap-3">
        <button
          type="button"
          onClick={handlePost}
          disabled={busy || !draftText.trim() || post.is_posted}
          className="flex-1 bg-indigo-600 text-white text-[13px] font-semibold px-5 py-3 rounded cursor-pointer border-0 disabled:opacity-40 disabled:cursor-not-allowed transition-colors hover:bg-indigo-700"
        >
          {posting ? 'Posting…' : 'Post to LinkedIn'}
        </button>
        <button
          type="button"
          onClick={handleCopy}
          disabled={busy || !draftText.trim()}
          className="flex-1 bg-slate-900 text-white text-[13px] font-semibold px-5 py-3 rounded cursor-pointer border-0 disabled:opacity-40 disabled:cursor-not-allowed transition-colors hover:bg-slate-800"
        >
          {copied ? 'Copied!' : 'Copy to clipboard'}
        </button>
      </div>
      <div className="flex flex-col sm:flex-row gap-3">
        <a
          href={LINKEDIN_URL}
          target="_blank"
          rel="noopener noreferrer"
          className="flex-1 text-center text-[13px] font-semibold text-slate-700 border border-slate-200 rounded px-5 py-3 hover:border-slate-400 hover:text-slate-900 transition-colors"
        >
          Open LinkedIn
        </a>
        {!post.is_posted ? (
          <button
            type="button"
            onClick={handleMarkPosted}
            disabled={busy}
            className="flex-1 text-[13px] font-semibold text-green-700 border border-green-200 rounded px-5 py-3 hover:border-green-400 bg-green-50 cursor-pointer disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
          >
            {markingPosted ? 'Saving…' : 'Mark posted (manual)'}
          </button>
        ) : (
          <div className="flex-1 text-center text-[13px] font-semibold text-green-700 border border-green-200 rounded px-5 py-3 bg-green-50">
            Posted
          </div>
        )}
      </div>

      {/* Approved article handoff */}
      <div className="bg-white border border-slate-200 rounded p-6">
        <div className="flex items-start justify-between gap-4 mb-4">
          <div>
            <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Handoff approved article</p>
            <p className="text-[12px] text-slate-500 mt-1">
              One click queues approved variants into upcoming open social slots.
            </p>
            <div className="mt-2 flex items-center gap-2">
              <button
                type="button"
                onClick={handleAddCalendarReminder}
                className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-2.5 py-1 hover:border-slate-400 hover:text-slate-800 cursor-pointer transition-colors"
              >
                Add calendar reminder (.ics)
              </button>
              <button
                type="button"
                onClick={handleAddGoogleCalendarReminder}
                className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-2.5 py-1 hover:border-slate-400 hover:text-slate-800 cursor-pointer transition-colors"
              >
                Add to Google Calendar
              </button>
              {calendarReminderSaved && (
                <span className="text-[11px] text-emerald-700">Downloaded</span>
              )}
              {googleCalendarOpened && (
                <span className="text-[11px] text-emerald-700">Opened</span>
              )}
            </div>
          </div>
          <span className={`text-[11px] font-bold px-2 py-0.5 rounded ${isApproved ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>
            {isApproved ? 'Current draft approved' : 'Current draft not approved'}
          </span>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 mb-1">Article title</label>
            <input
              value={handoffTitle}
              onChange={e => setHandoffTitle(e.target.value)}
              placeholder="Context rebuild and executive transitions"
              className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 focus:outline-none focus:border-slate-400"
            />
          </div>
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 mb-1">Article URL (optional)</label>
            <input
              value={handoffUrl}
              onChange={e => setHandoffUrl(e.target.value)}
              placeholder="https://startingmonday.app/blog/..."
              className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 focus:outline-none focus:border-slate-400"
            />
          </div>
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 mb-1">Pillar</label>
            <select
              value={handoffPillar}
              onChange={e => setHandoffPillar(e.target.value as (typeof PILLAR_OPTIONS)[number]['value'])}
              className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 bg-white focus:outline-none focus:border-slate-400"
              title="Select pillar"
            >
              {PILLAR_OPTIONS.map(option => (
                <option key={option.value} value={option.value}>{option.label}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 mb-1">Audience (optional)</label>
            <input
              value={handoffAudience}
              onChange={e => setHandoffAudience(e.target.value)}
              placeholder="executive_coaches"
              className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 focus:outline-none focus:border-slate-400"
            />
          </div>
        </div>

        <div className="mt-3">
          <label className="block text-[11px] font-semibold text-slate-500 mb-1">Article summary</label>
          <textarea
            value={handoffSummary}
            onChange={e => setHandoffSummary(e.target.value)}
            rows={4}
            className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 resize-none focus:outline-none focus:border-slate-400"
            placeholder="Paste the approved article summary or leave the draft-derived default."
          />
        </div>

        <div className="mt-4 flex flex-col sm:flex-row gap-3 sm:items-end sm:justify-between">
          <label className="text-[11px] font-semibold text-slate-500">
            Variant count (1-5)
            <input
              type="number"
              min={1}
              max={5}
              value={handoffVariants}
              onChange={e => setHandoffVariants(Number(e.target.value || 3))}
              className="mt-1 block w-32 text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 focus:outline-none focus:border-slate-400"
            />
          </label>

          <button
            type="button"
            onClick={handleApprovedHandoff}
            disabled={busy || !handoffSummary.trim()}
            className="text-[13px] font-semibold text-white bg-emerald-600 hover:bg-emerald-700 rounded px-5 py-2.5 disabled:opacity-40 disabled:cursor-not-allowed border-0 cursor-pointer transition-colors"
          >
            {handoffSubmitting ? 'Queueing…' : 'Handoff approved article'}
          </button>
        </div>

        {handoffMessage && (
          <p className="mt-3 text-[12px] text-emerald-700 bg-emerald-50 border border-emerald-200 rounded px-3 py-2">{handoffMessage}</p>
        )}

        <div className="mt-4 border-t border-slate-100 pt-4">
          <div className="flex items-center justify-between gap-3 mb-2">
            <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Recent handoff runs</p>
            {handoffHistoryLoading && <span className="text-[11px] text-slate-400">Loading…</span>}
          </div>

          {!handoffHistoryLoading && handoffHistory.length === 0 && (
            <p className="text-[12px] text-slate-500">No approved handoff runs yet.</p>
          )}

          {handoffHistory.length > 0 && (
            <div className="flex flex-col gap-2">
              {handoffHistory.slice(0, 5).map(run => (
                <div key={run.batchId} className="border border-slate-200 rounded p-3 bg-slate-50">
                  <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-1">
                    <p className="text-[12px] font-semibold text-slate-800 truncate">
                      {run.articleTitle || 'Approved handoff'}
                    </p>
                    <p className="text-[11px] text-slate-500">
                      {new Date(run.createdAt).toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' })}
                    </p>
                  </div>
                  <p className="mt-1 text-[11px] text-slate-600">
                    Queued dates: {run.dates.map(date => formatDate(date)).join(', ')}
                  </p>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Connection outreach */}
      <div className="bg-white border border-slate-200 rounded p-6">
        <div className="flex items-center justify-between mb-4">
          <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">LinkedIn Connection Messages</p>
          <div className="flex gap-2">
            <a
              href={LINKEDIN_MESSAGING_URL}
              target="_blank"
              rel="noopener noreferrer"
              className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 hover:text-slate-800 transition-colors"
            >
              Open Messaging
            </a>
            <a
              href={LINKEDIN_MYNETWORK_URL}
              target="_blank"
              rel="noopener noreferrer"
              className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 hover:text-slate-800 transition-colors"
            >
              My Network
            </a>
          </div>
        </div>
        <div className="flex flex-col gap-4">
          {CONNECTION_TEMPLATES.map((template, i) => (
            <div key={template.label} className="border border-slate-100 rounded p-4 bg-slate-50">
              <div className="flex items-center justify-between mb-2">
                <span className="text-[11px] font-bold text-slate-500 uppercase tracking-[0.07em]">{template.label}</span>
                <button
                  type="button"
                  onClick={() => handleCopyTemplate(i)}
                  className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1 hover:border-slate-400 hover:text-slate-800 bg-white cursor-pointer transition-colors"
                >
                  {copiedTemplate === i ? 'Copied!' : 'Copy'}
                </button>
              </div>
              <textarea
                value={connectionTexts[i]}
                onChange={e => setConnectionTexts(prev => prev.map((t, j) => j === i ? e.target.value : t))}
                rows={3}
                title={template.label}
                placeholder="Edit connection message…"
                className="w-full text-[13px] text-slate-700 leading-relaxed border border-slate-200 rounded px-3 py-2 resize-none focus:outline-none focus:border-slate-400 font-[inherit] bg-white"
              />
              <p className="mt-1 text-[11px] text-slate-300">{connectionTexts[i].length} chars</p>
            </div>
          ))}
        </div>
      </div>

      {/* Notes */}
      <div className="bg-white border border-slate-200 rounded p-6">
        <div className="flex items-center justify-between mb-3">
          <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Notes (engagement, replies, reach)</p>
          {isNotesDirty && !savingNotes && (
            <span className="text-[11px] text-amber-600 font-medium">Unsaved</span>
          )}
          {savingNotes && (
            <span className="text-[11px] text-slate-400">Saving…</span>
          )}
        </div>
        <textarea
          value={notesText}
          onChange={e => setNotesText(e.target.value)}
          onBlur={isNotesDirty ? handleNotesSave : undefined}
          disabled={busy}
          rows={3}
          className="w-full text-[13px] text-slate-700 leading-relaxed border border-slate-200 rounded px-4 py-3 resize-none focus:outline-none focus:border-slate-400 font-[inherit] disabled:opacity-50"
          placeholder="Likes, comments, notable replies… saves on blur"
        />
      </div>

    </div>
  )
}

import Link from 'next/link'
import { redirect } from 'next/navigation'
import { createClient } from '@/lib/supabase/server'
import { createAdminClient } from '@/lib/supabase/admin'
import { todayInTz, greetingInTz, fullDateInTz } from '@/lib/date'
import { getActivationStatus } from '@/lib/activation'
import { resolveCareerMode } from '@/lib/career-mode'
import { LogoutButton } from './logout-button'
import { HelpQuickButton } from '@/components/HelpQuickButton'
import { CmdKButton } from '@/components/CmdKButton'
import { saveQuickProfile, saveWeeklyGoal, dismissStallNudge } from './profile/actions'
import { markPlaced } from './placed/actions'
import { OpportunityRadar } from './opportunity-radar'
import { ActivityChart, type WeekActivity } from '@/components/ActivityChart'
import { PipelineVelocity, type VelocityRow } from '@/components/PipelineVelocity'
import { DailyMomentumPlan, type DailyMomentumAction } from '@/components/DailyMomentumPlan'
import { getStaffMember, hasAdminHeaderAccess } from '@/lib/staff'
import { DashboardPipelineSection } from './dashboard-pipeline-section'
import { DashboardDisclosureSection } from './dashboard-disclosure-section'
import { DashboardStatusBanners } from './dashboard-status-banners'
import { DashboardProfileIntelligenceSection } from './dashboard-profile-intelligence-section'
import { DashboardWelcomeNudgeSection } from './dashboard-welcome-nudge-section'
import { DashboardAdvancedModulesSection } from './dashboard-advanced-modules-section'
import { DashboardTopShellSection } from './dashboard-top-shell-section'
import { DashboardPostPlacementView } from './dashboard-post-placement-view'
import { DashboardDecisionTimelineSection } from './dashboard-decision-timeline-section'
import { updateDecisionOwner } from './actions'
import { decisionMarkerForStage, extractDecisionOwnerFromNotes } from './dashboard-decision-timeline-utils'
import { bumpWeek, getWeekMonday, weekLabel } from './dashboard-week-utils'
import { canAccessFeature, getUserSubscription } from '@/lib/subscription'

// Full class strings - must not be constructed dynamically (Tailwind scanner needs to see them)
const STAGE: Record<string, { label: string; cls: string }> = {
  watching:     { label: 'Watching',     cls: 'bg-slate-100 text-slate-500' },
  researching:  { label: 'Researching',  cls: 'bg-blue-50 text-blue-700' },
  applied:      { label: 'In Process',   cls: 'bg-indigo-50 text-indigo-700' },
  interviewing: { label: 'Interviewing', cls: 'bg-amber-50 text-amber-700' },
  offer:        { label: 'Offer',        cls: 'bg-green-50 text-green-700' },
}

const PAGE_SIZE = 50

type ProfileRow = {
  full_name: string | null
  search_started_at: string | null
  briefing_timezone: string | null
  onboarding_completed_at: string | null
  target_titles: string[] | null
  resume_text: string | null
  positioning_summary: string | null
  briefing_time: string | null
  briefing_frequency: string | null
  current_title: string | null
  placed_at: string | null
  placement_company: string | null
  search_status: string | null
  weekly_goal: number | null
  stall_nudge_dismissed_at: string | null
  search_path: string | null
}

type UserRow = {
  subscription_status: string | null
  trial_ends_at: string | null
  subscription_tier: string | null
}

type SignalRow = {
  id: string
  signal_type: string
  signal_summary: string
  outreach_angle?: string | null
  signal_date: string
  company_id: string
  companies: { id: string; name: string } | null
}

type CompanyRow = {
  id: string
  name: string
  sector: string | null
  stage: string
  fit_score: number | null
  notes: string | null
  updated_at: string | null
}

export default async function DashboardPage({
  searchParams,
}: {
  searchParams: Promise<{ q?: string; stage?: string; page?: string; profile_saved?: string; focus?: string; preview?: string; timelinePage?: string; timelineSort?: string }>
}) {
  const { q, stage, page: pageParam, profile_saved, focus, preview, timelinePage: timelinePageParam, timelineSort: timelineSortParam } = await searchParams
  const page = Math.max(0, parseInt(pageParam ?? '0', 10) || 0)
  const timelinePage = Math.max(0, parseInt(timelinePageParam ?? '0', 10) || 0)
  const timelineSort = timelineSortParam === 'recent_desc' || timelineSortParam === 'name_asc'
    ? timelineSortParam
    : 'stalled_desc'
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) redirect('/login')

  const subscription = await getUserSubscription(user.id, supabase)
  if (canAccessFeature(subscription, 'coach_dashboard')) {
    redirect('/dashboard/coach')
  }

  const { data: profileRaw, error: profileError } = await supabase
    .from('user_profiles')
    .select('full_name, search_started_at, briefing_timezone, onboarding_completed_at, target_titles, resume_text, positioning_summary, briefing_time, briefing_frequency, current_title, placed_at, placement_company, search_status, weekly_goal, stall_nudge_dismissed_at, search_path')
    .eq('user_id', user.id)
    .single()
  const profile = profileRaw as ProfileRow | null

  if (profileError && profileError.code !== 'PGRST116') {
    console.error(JSON.stringify({ ts: new Date().toISOString(), event: 'dashboard_profile_error', code: profileError.code, message: profileError.message, userId: user.id }))
  } else if (!profile?.onboarding_completed_at) {
    redirect('/onboarding')
  }

  const careerMode = resolveCareerMode({ placedAt: profile?.placed_at, searchStatus: profile?.search_status })
  if (careerMode === 'post_search') {
    redirect('/dashboard/post-search')
  }

  const tz = profile?.briefing_timezone ?? 'UTC'
  const todayISO = todayInTz(tz)

  // Build filtered company query (server-side) with pagination
  let companyQuery = supabase
    .from('companies')
    .select('id, name, sector, stage, fit_score, notes, updated_at', { count: 'planned' })
    .eq('user_id', user.id)
    .is('archived_at', null)
    .order('fit_score', { ascending: false, nullsFirst: false })

  if (q) companyQuery = companyQuery.ilike('name', `%${q}%`)
  if (stage) companyQuery = companyQuery.eq('stage', stage)

  const start = page * PAGE_SIZE
  companyQuery = companyQuery.range(start, start + PAGE_SIZE - 1)

  // Stats query: total + active count (unfiltered)
  const statsQuery = supabase
    .from('companies')
    .select('id, stage, name, notes, updated_at')
    .eq('user_id', user.id)
    .is('archived_at', null)

  const since7d  = new Date(Date.now() -  7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]
  const since14d = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]
  const since70d = new Date(Date.now() - 70 * 24 * 60 * 60 * 1000).toISOString()
  const thisMonday = (() => {
    const d = new Date(); const day = d.getDay()
    d.setDate(d.getDate() + (day === 0 ? -6 : 1 - day)); d.setHours(0, 0, 0, 0)
    return d.toISOString()
  })()

  const adminClient = createAdminClient()
  const isPartnerPromise = Promise.resolve(
    adminClient
      .from('partners')
      .select('id', { count: 'exact', head: true })
      .eq('email', user.email ?? '')
      .eq('is_active', true)
  ).then(r => (r.count ?? 0) > 0).catch(() => false)

  const [{ data: rawCompanies, count: filteredCount }, { data: allCompanies }, { data: followUps }, { data: rawUserRow }, { data: rawSignals }, { data: rawPatternAlerts }, activation, { data: momentumData }, { data: contactRows }, { count: draftReadyCount }, { data: actCompanies }, { data: actContacts }, { data: actBriefs }, { data: actFollowUps }, { count: outreachThisWeek }, { count: prospectContactCount }, { data: briefedCompanyRows }] = await Promise.all([
    companyQuery,
    statsQuery,
    supabase
      .from('follow_ups')
      .select('id, due_date, action, companies(name)')
      .eq('user_id', user.id)
      .eq('status', 'pending')
      .lte('due_date', todayISO)
      .order('due_date', { ascending: true })
      .limit(20),
    supabase
      .from('users')
      .select('subscription_status, trial_ends_at, subscription_tier')
      .eq('id', user.id)
      .single(),
    supabase
      .from('company_signals')
      .select('id, signal_type, signal_summary, outreach_angle, signal_date, company_id, companies(id, name)')
      .eq('user_id', user.id)
      .neq('signal_type', 'pattern_alert')
      .gte('signal_date', since7d)
      .order('signal_date', { ascending: false })
      .limit(5),
    supabase
      .from('company_signals')
      .select('id, signal_type, signal_summary, outreach_angle, signal_date, company_id, companies(id, name)')
      .eq('user_id', user.id)
      .eq('signal_type', 'pattern_alert')
      .gte('signal_date', since14d)
      .order('signal_date', { ascending: false })
      .limit(3),
    getActivationStatus(user.id),
    // Separate query - columns added in migration 022; returns { data: null } gracefully if not yet applied
    supabase
      .from('user_profiles')
      .select('momentum_score, momentum_computed_at')
      .eq('user_id', user.id)
      .single(),
    supabase
      .from('contacts')
      .select('company_id')
      .eq('user_id', user.id)
      .eq('status', 'active')
      .not('company_id', 'is', null),
    supabase
      .from('company_signals')
      .select('id', { count: 'exact', head: true })
      .eq('user_id', user.id)
      .not('outreach_draft', 'is', null)
      .gte('signal_date', since14d),
    // Activity chart queries (last 10 weeks)
    supabase.from('companies').select('created_at').eq('user_id', user.id).is('archived_at', null).gte('created_at', since70d),
    supabase.from('contacts').select('created_at').eq('user_id', user.id).gte('created_at', since70d),
    supabase.from('briefs').select('created_at').eq('user_id', user.id).gte('created_at', since70d),
    supabase.from('follow_ups').select('created_at').eq('user_id', user.id).gte('created_at', since70d),
    supabase.from('briefs').select('id', { count: 'exact', head: true }).eq('user_id', user.id).eq('type', 'outreach').gte('created_at', thisMonday),
    supabase.from('contacts').select('id', { count: 'exact', head: true }).eq('user_id', user.id).eq('status', 'active').eq('outreach_status', 'prospect'),
    supabase.from('briefs').select('company_id').eq('user_id', user.id).eq('type', 'prep').not('company_id', 'is', null).limit(500),
  ])

  const companies = rawCompanies as CompanyRow[] | null
  const userRow   = rawUserRow as UserRow | null
  const signals   = (rawSignals ?? []) as unknown as SignalRow[]
  const patternAlerts = (rawPatternAlerts ?? []) as unknown as SignalRow[]

  // Build weekly activity chart data (last 10 weeks)
  const weekSlots: WeekActivity[] = []
  for (let i = 9; i >= 0; i--) {
    const d = new Date(Date.now() - i * 7 * 24 * 60 * 60 * 1000)
    weekSlots.push({ week: weekLabel(getWeekMonday(d)), companies: 0, contacts: 0, briefs: 0, followUps: 0 })
  }
  const weekMap = new Map(weekSlots.map((slot) => [slot.week, slot]))
  for (const r of actCompanies ?? []) bumpWeek(weekMap, r.created_at, 'companies')
  for (const r of actContacts ?? []) bumpWeek(weekMap, r.created_at, 'contacts')
  for (const r of actBriefs ?? []) bumpWeek(weekMap, r.created_at, 'briefs')
  for (const r of actFollowUps ?? []) bumpWeek(weekMap, r.created_at, 'followUps')

  const allActivityDates = [
    ...(actCompanies ?? []).map(r => r.created_at),
    ...(actContacts  ?? []).map(r => r.created_at),
    ...(actBriefs    ?? []).map(r => r.created_at),
    ...(actFollowUps ?? []).map(r => r.created_at),
  ]
  const lastActivityMs = allActivityDates.length > 0 ? Math.max(...allActivityDates.map(d => new Date(d).getTime())) : 0
  const daysSinceLastAction = lastActivityMs > 0 ? Math.floor((Date.now() - lastActivityMs) / 86400000) : null

  // Nurture path - derived from profile; showNurtureWelcome computed after totalCount and daysSinceOnboard
  const searchPath = profile?.search_path ?? null
  const isNurturePath = searchPath === 'nurture'

  // Stall detection - pattern-specific nudge shown after 14 days of low activity
  type StallNudge = { headline: string; body: string; action: string; href: string } | null
  let stallNudge: StallNudge = null
  const dismissedAt = profile?.stall_nudge_dismissed_at
  const dismissedDaysAgo = dismissedAt ? Math.floor((Date.now() - new Date(dismissedAt).getTime()) / 86400000) : Infinity
  const searchStartedAt = profile?.search_started_at ? new Date(profile.search_started_at) : null
  const daysSinceStart = searchStartedAt ? Math.floor((Date.now() - searchStartedAt.getTime()) / 86400000) : null
  const contactCount = (contactRows ?? []).length
  const totalCompanies = (allCompanies ?? []).length
  const hasAdvancedStage = (allCompanies ?? []).some(c => ['interviewing', 'applied', 'offer'].includes(c.stage))

  if (!profile?.placed_at && dismissedDaysAgo > 7 && daysSinceStart !== null && daysSinceStart >= 14) {
    if (totalCompanies > 0 && contactCount === 0) {
      stallNudge = {
        headline: 'Companies tracked. No contacts added.',
        body: 'Your target list is built. Adding the people you know at these companies is usually what holds the first outreach back. Even one contact changes the shape of the conversation.',
        action: 'Add a contact',
        href: '/dashboard/contacts',
      }
    } else if (contactCount > 0 && !hasAdvancedStage && daysSinceLastAction !== null && daysSinceLastAction >= 14) {
      const hasSummary = !!profile?.positioning_summary
      stallNudge = {
        headline: 'No activity in two weeks.',
        body: hasSummary
          ? 'You have contacts to work but nothing has moved. Run a strategy brief to see where the gap is.'
          : 'You have contacts to work but no positioning summary. That is usually what holds the first outreach back - you are not sure what to say yet.',
        action: hasSummary ? 'Run strategy brief' : 'Add your positioning',
        href: hasSummary ? '/dashboard/strategy' : '/dashboard/profile',
      }
    } else if (totalCompanies > 0 && !hasAdvancedStage && daysSinceLastAction !== null && daysSinceLastAction >= 21) {
      stallNudge = {
        headline: 'Nothing has moved in three weeks.',
        body: 'Every company is still at watching or researching. Either the target list needs narrowing, or the outreach has not started. Both are diagnosable.',
        action: 'Run a strategy brief',
        href: '/dashboard/strategy',
      }
    }
  }

  // Pipeline velocity rows (all companies, sorted by staleness)
  const velocityRows: VelocityRow[] = (companies ?? []).map(c => ({
    id: c.id,
    name: c.name,
    stage: c.stage,
    updated_at: c.updated_at ?? null,
  }))

  // isPartnerPromise was started before the main await above so it ran in parallel
  const isPartner = await isPartnerPromise
  const firstName = profile?.full_name?.split(' ')[0] ?? 'there'
  const allList = allCompanies ?? []
  const totalCount = allList.length
  const activeCount = allList.filter(c =>
    ['interviewing', 'applied', 'offer'].includes(c.stage)
  ).length
  const overdueCount   = (followUps ?? []).length
  const signalCount    = signals.length + patternAlerts.length

  const stalledCampaignRows = velocityRows
    .map((row) => {
      if (!row.updated_at) return null
      const daysStalled = Math.floor((Date.now() - new Date(row.updated_at).getTime()) / 86400000)
      if (daysStalled < 14) return null
      return { ...row, daysStalled }
    })
    .filter((row): row is VelocityRow & { daysStalled: number } => !!row)
    .sort((a, b) => b.daysStalled - a.daysStalled)

  const cadenceScore = Math.min(100, (outreachThisWeek ?? 0) * 20)
  const followThroughScore = Math.max(0, 100 - overdueCount * 15)
  const conversionScore = totalCount > 0 ? Math.min(100, Math.round((activeCount / totalCount) * 100)) : 0
  const campaignHealthScore = Math.round((cadenceScore * 0.4) + (followThroughScore * 0.35) + (conversionScore * 0.25))
  const campaignHealthBand = campaignHealthScore >= 75 ? 'Strong' : campaignHealthScore >= 50 ? 'Watch' : 'At risk'
  const topStalledCampaigns = stalledCampaignRows.slice(0, 5)

  const timelineOwnerLabel = profile?.full_name ?? user.email ?? 'Account owner'
  const decisionTimelineItemsAll = (allList ?? [])
    .map((company) => {
      const stageLabel = STAGE[company.stage]?.label ?? company.stage
      const updatedAtMs = company.updated_at ? new Date(company.updated_at).getTime() : null
      const daysSinceUpdate = updatedAtMs ? Math.floor((Date.now() - updatedAtMs) / 86400000) : null
      const stalled = (daysSinceUpdate ?? 0) >= 14
      const marker = decisionMarkerForStage(company.stage)
      const assignedOwner = extractDecisionOwnerFromNotes(company.notes) ?? timelineOwnerLabel

      return {
        id: company.id,
        name: company.name,
        stageLabel,
        nextDecisionMarker: marker.marker,
        decisionWindowLabel: marker.decisionWindowLabel,
        daysSinceUpdate,
        stalled,
        ownerLabel: assignedOwner,
        href: `/dashboard/companies/${company.id}`,
      }
    })

  const decisionTimelineItemsSorted = [...decisionTimelineItemsAll].sort((a, b) => {
    if (timelineSort === 'name_asc') return a.name.localeCompare(b.name)
    if (timelineSort === 'recent_desc') return (a.daysSinceUpdate ?? 0) - (b.daysSinceUpdate ?? 0)
    if (a.stalled !== b.stalled) return a.stalled ? -1 : 1
    return (b.daysSinceUpdate ?? 0) - (a.daysSinceUpdate ?? 0)
  })

  const timelinePageSize = 6
  const timelineTotalPages = Math.max(1, Math.ceil(decisionTimelineItemsSorted.length / timelinePageSize))
  const safeTimelinePage = Math.min(timelinePage, timelineTotalPages - 1)
  const decisionTimelineItems = decisionTimelineItemsSorted.slice(
    safeTimelinePage * timelinePageSize,
    safeTimelinePage * timelinePageSize + timelinePageSize,
  )

  // Warm paths: contacts at companies with recent signals
  const signalCompanyIds = [...new Set([...signals, ...patternAlerts].map(s => s.company_id).filter(Boolean))]
  type WarmPath = { contactId: string; contactName: string; contactTitle: string | null; companyId: string; companyName: string; signal: SignalRow }
  let warmPaths: WarmPath[] = []
  if (signalCompanyIds.length > 0) {
    const { data: warmContacts } = await supabase
      .from('contacts')
      .select('id, name, title, company_id')
      .eq('user_id', user.id)
      .eq('status', 'active')
      .in('company_id', signalCompanyIds)
      .limit(10)
    if (warmContacts && warmContacts.length > 0) {
      const seen = new Set<string>()
      for (const ct of warmContacts) {
        if (!ct.company_id) continue
        const sig = [...signals, ...patternAlerts].find(s => s.company_id === ct.company_id)
        if (!sig || !sig.companies) continue
        const key = `${ct.id}-${sig.id}`
        if (seen.has(key)) continue
        seen.add(key)
        warmPaths.push({
          contactId:   ct.id,
          contactName: ct.name,
          contactTitle: ct.title,
          companyId:   ct.company_id,
          companyName: sig.companies.name,
          signal:      sig,
        })
      }
      warmPaths = warmPaths.slice(0, 5)
    }
  }

  const contactCountMap = new Map<string, number>()
  for (const row of (contactRows ?? [])) {
    if (row.company_id) {
      contactCountMap.set(row.company_id, (contactCountMap.get(row.company_id) ?? 0) + 1)
    }
  }

  const briefedCompanyIds = new Set((briefedCompanyRows ?? []).map(b => b.company_id).filter(Boolean) as string[])
  const companiesWithoutContact = (allCompanies ?? []).filter(c => c.id && !contactCountMap.has(c.id))
  const companiesWithoutBrief   = (allCompanies ?? []).filter(c => c.id && !briefedCompanyIds.has(c.id))
  const numIntelGaps = [companiesWithoutContact.length > 0, (prospectContactCount ?? 0) > 0, companiesWithoutBrief.length > 0].filter(Boolean).length

  const filtered = companies ?? []
  const totalFiltered = filteredCount ?? 0
  const totalPages = Math.ceil(totalFiltered / PAGE_SIZE)
  const hasFilters = !!(q || stage)

  const greeting = greetingInTz(tz)
  const today = fullDateInTz(tz)

  const trialEndsAt = userRow?.trial_ends_at ? new Date(userRow.trial_ends_at) : null
  const isTrialing = userRow?.subscription_status === 'trialing'
  const isExecutive = userRow?.subscription_tier === 'executive'
  const isExecutivePreview = preview === 'executive-v2'
  const isExecutiveMode = isExecutive || isExecutivePreview
  const isCoach = userRow?.subscription_tier === 'coach'
  const staffMember = await getStaffMember(user.email ?? '')
  const isRothschildAdmin = hasAdminHeaderAccess(staffMember)
  const canUseOutreachHub = staffMember?.role === 'owner' || staffMember?.role === 'admin'
  const roleLensLabel = isRothschildAdmin
    ? 'Admin'
    : isPartner
      ? 'Partner'
      : isCoach
        ? 'Coach'
        : 'Executive'
  const trialDaysLeft = trialEndsAt
    ? Math.ceil((trialEndsAt.getTime() - Date.now()) / (1000 * 60 * 60 * 24))
    : 0

  const profileSections = [
    { label: 'Identity',    done: !!profile?.full_name,                                                anchor: 'section-identity' },
    { label: 'Targets',     done: ((profile?.target_titles as string[] | null)?.length ?? 0) > 0,     anchor: 'section-targets' },
    { label: 'Resume',      done: (profile?.resume_text?.length ?? 0) >= 200,                          anchor: 'section-resume' },
    { label: 'Positioning', done: (profile?.positioning_summary?.length ?? 0) >= 50,                   anchor: 'section-positioning' },
    { label: 'Briefing',    done: !!profile?.briefing_time,                                             anchor: 'section-briefing' },
  ]
  const profileScore = Math.round((profileSections.filter(s => s.done).length / 5) * 100)
  const nextProfileSection = profileSections.find(s => !s.done)
  const profileHref = nextProfileSection
    ? `/dashboard/profile#${nextProfileSection.anchor}`
    : '/dashboard/profile'

  const stats = [
    { value: totalCount,   label: 'Companies',   alert: false,            amber: false,              href: '#pipeline' },
    { value: activeCount,  label: 'Active',       alert: false,            amber: activeCount > 0,    href: '#pipeline' },
    { value: signalCount,  label: 'Signals',      alert: false,            amber: signalCount > 0,    href: '/dashboard/signals' },
    { value: overdueCount, label: 'Due Today',    alert: overdueCount > 0, amber: false,             href: '/dashboard/calendar' },
  ]

  const offerCompany = !profile?.placed_at
    ? allList.find(c => c.stage === 'offer') ?? null
    : null
  const offerCompanies = allList.filter(c => c.stage === 'offer')
  const interviewingCompany = allList.find(c => c.stage === 'interviewing') ?? null

  const daysSinceOnboard = profile?.onboarding_completed_at
    ? Math.floor((Date.now() - new Date(profile.onboarding_completed_at).getTime()) / 86400000)
    : null
  const showWeek3Prompt = daysSinceOnboard !== null && daysSinceOnboard >= 18 && daysSinceOnboard <= 28
  const showNurtureWelcome  = isNurturePath              && totalCount === 0 && daysSinceOnboard !== null && daysSinceOnboard <= 7
  const showCampaignWelcome = searchPath === 'campaign'  && totalCount === 0 && daysSinceOnboard !== null && daysSinceOnboard <= 7
  const showWatcherWelcome  = searchPath === 'watcher'   && totalCount === 0 && daysSinceOnboard !== null && daysSinceOnboard <= 7

  const momentumScore = typeof momentumData?.momentum_score === 'number'
    ? momentumData.momentum_score
    : null
  const momentumStatus: 'low' | 'medium' | 'strong' = momentumScore !== null
    ? (momentumScore >= 70 ? 'strong' : momentumScore >= 40 ? 'medium' : 'low')
    : ((signalCount + overdueCount + activeCount) >= 3 ? 'strong' : (signalCount + overdueCount + activeCount) > 0 ? 'medium' : 'low')

  const relationshipAction: DailyMomentumAction = warmPaths[0]
    ? {
        id: 'relationship-action',
        track: 'relationship',
        title: `Work ${warmPaths[0].contactName} at ${warmPaths[0].companyName}`,
        body: `${warmPaths[0].signal.signal_summary} gives you a concrete reason to re-engage. Use that signal while it is still fresh.`,
        effortMinutes: 15,
        href: `/dashboard/contacts/${warmPaths[0].contactId}/outreach`,
        cta: 'Open outreach',
      }
    : overdueCount > 0
      ? {
          id: 'relationship-action',
          track: 'relationship',
          title: 'Clear the next relationship follow-up',
          body: 'A due follow-up is the cleanest way to recover momentum. Close one loop before you add anything new.',
          effortMinutes: 15,
          href: '/dashboard/calendar',
          cta: 'Open calendar',
        }
      : {
          id: 'relationship-action',
          track: 'relationship',
          title: 'Pick one warm relationship to move',
          body: 'Open contacts, choose one person who can unblock a real conversation, and schedule the next step.',
          effortMinutes: 15,
          href: '/dashboard/contacts',
          cta: 'Open contacts',
        }

  const readinessAction: DailyMomentumAction = interviewingCompany
    ? {
        id: 'readiness-action',
        track: 'readiness',
        title: `Generate prep for ${interviewingCompany.name}`,
        body: 'If you already have a live conversation, readiness work outranks almost everything else.',
        effortMinutes: 25,
        href: `/dashboard/companies/${interviewingCompany.id}/prep`,
        cta: 'Run prep brief',
      }
    : profileScore < 100
      ? {
          id: 'readiness-action',
          track: 'readiness',
          title: 'Tighten the profile inputs driving your search',
          body: 'Briefing quality, prep quality, and positioning all degrade when the profile is incomplete.',
          effortMinutes: 20,
          href: profileHref,
          cta: 'Finish profile',
        }
      : {
          id: 'readiness-action',
          track: 'readiness',
          title: 'Run one readiness pass before more outreach',
          body: 'Use the strategy layer to sharpen what you will say before the next live conversation opens.',
          effortMinutes: 20,
          href: '/dashboard/strategy',
          cta: 'Open strategy',
        }

  const focusAction: DailyMomentumAction = signalCount > 0
    ? {
        id: 'focus-action',
        track: 'focus',
        title: 'Review the freshest market signals',
        body: 'New signal density is highest-leverage when you turn it into a sharper outreach angle the same day.',
        effortMinutes: 15,
        href: '/dashboard/signals',
        cta: 'Open signals',
      }
    : totalCount < 12
      ? {
          id: 'focus-action',
          track: 'focus',
          title: 'Add one more target company',
          body: 'A thin pipeline creates pressure. Add one target with a real reason it belongs in the search.',
          effortMinutes: 15,
          href: '/dashboard/companies/new',
          cta: 'Add company',
        }
      : {
          id: 'focus-action',
          track: 'focus',
          title: 'Convert today into a concrete next step',
          body: 'If the pipeline already exists, pick the next visible move instead of expanding scope.',
          effortMinutes: 10,
          href: overdueCount > 0 ? '/dashboard/calendar' : '/dashboard/briefing',
          cta: overdueCount > 0 ? 'View due today' : 'Open briefing',
        }

  const dailyMomentumActions: DailyMomentumAction[] = [relationshipAction, readinessAction, focusAction]

  const sponsorCoveragePercent = totalCount > 0 ? Math.round((contactCountMap.size / totalCount) * 100) : 0
  const signalToActionPercent = signalCount > 0 ? Math.min(100, Math.round(((draftReadyCount ?? 0) / signalCount) * 100)) : 0
  const followUpSlaPercent = overdueCount === 0 ? 100 : Math.max(0, 100 - overdueCount * 15)
  const decisionLagDays = offerCompanies.length > 0 ? (daysSinceLastAction ?? 0) : null

  const executiveStageLabel = offerCompanies.length > 0
    ? 'Offer and Decision'
    : (activeCount > 0 || !!interviewingCompany)
      ? 'Interviewing and Conversion'
      : (totalCount > 0 && contactCount > 0)
        ? 'Market Activation'
        : totalCount > 0
          ? 'Target and Narrative Design'
          : 'Trigger and Identity Reset'

  const threatRiskHigh = (daysSinceLastAction ?? 0) >= 14 || (totalCount === 0 && (daysSinceOnboard ?? 0) > 7)
  const perfectionRiskHigh = profileScore < 80 && totalCount === 0 && (daysSinceOnboard ?? 0) > 5
  const isolationRiskHigh = totalCount >= 3 && sponsorCoveragePercent < 50
  const decisionRiskHigh = offerCompanies.length > 0 && (daysSinceLastAction ?? 0) >= 7

  const riskItems: Array<{
    id: string
    label: string
    level: 'low' | 'medium' | 'high'
    detail: string
    href: string
    cta: string
  }> = [
    {
      id: 'threat-state',
      label: 'Threat and uncertainty state',
      level: threatRiskHigh ? 'high' : (signalCount > 0 ? 'low' : 'medium'),
      detail: threatRiskHigh
        ? 'Activity decay suggests rising uncertainty. Use one concrete move to restore control today.'
        : 'Signal and action flow is stable enough to keep confidence anchored in execution.',
      href: '/dashboard/briefing',
      cta: 'Open daily briefing',
    },
    {
      id: 'perfection-loop',
      label: 'Perfection loop risk',
      level: perfectionRiskHigh ? 'high' : (profileScore < 100 ? 'medium' : 'low'),
      detail: perfectionRiskHigh
        ? 'You may be polishing inputs without enough market activation. Ship one outreach action.'
        : 'Profile quality is improving. Keep edits tied to live outreach outcomes.',
      href: profileScore < 100 ? '/dashboard/profile' : '/dashboard/strategy',
      cta: profileScore < 100 ? 'Finish profile inputs' : 'Run strategy brief',
    },
    {
      id: 'isolation-risk',
      label: 'Sponsor map depth',
      level: isolationRiskHigh ? 'high' : (sponsorCoveragePercent < 70 ? 'medium' : 'low'),
      detail: isolationRiskHigh
        ? 'Coverage is low for an executive search. Relationship depth is likely the bottleneck now.'
        : 'Sponsor coverage is trending in the right direction. Keep adding depth at top targets.',
      href: '/dashboard/contacts',
      cta: 'Expand sponsor map',
    },
    {
      id: 'decision-drag',
      label: 'Decision drag risk',
      level: decisionRiskHigh ? 'high' : (offerCompanies.length > 0 ? 'medium' : 'low'),
      detail: offerCompanies.length > 0
        ? 'Offer context exists. Decision quality drops when timeline and no-go criteria stay implicit.'
        : 'No active offer context. Keep criteria explicit before final-round intensity rises.',
      href: offerCompanies.length > 0 ? '/dashboard/offers' : '/dashboard/strategy',
      cta: offerCompanies.length > 0 ? 'Open offer compare' : 'Capture criteria',
    },
  ]

  const executivePrimaryRisk = (() => {
    if (decisionRiskHigh) return { label: 'Decision drag', level: 'high' as const, href: '/dashboard/offers', cta: 'Resolve tradeoffs' }
    if (isolationRiskHigh) return { label: 'Sponsor depth gap', level: 'high' as const, href: '/dashboard/contacts', cta: 'Add sponsors' }
    if (threatRiskHigh) return { label: 'Momentum decay', level: 'high' as const, href: '/dashboard/briefing', cta: 'Re-anchor today' }
    if (perfectionRiskHigh) return { label: 'Perfection loop', level: 'medium' as const, href: '/dashboard/profile', cta: 'Ship and move' }
    return { label: 'Managed', level: 'low' as const, href: '/dashboard/briefing', cta: 'Keep cadence' }
  })()

  const executiveDecisionBrief = (() => {
    if (offerCompanies.length > 0) {
      return {
        changed: `${offerCompanies.length} offer ${offerCompanies.length === 1 ? 'is' : 'are'} in play and decision pressure is rising.`,
        whyNow: 'Late-stage ambiguity increases regret risk more than almost any other phase.',
        recommendedMove: 'Run the offer comparison and lock explicit no-go criteria before new conversations start.',
        downsideIfDelayed: 'Decision lag weakens negotiation leverage and increases reactive choices.',
        href: '/dashboard/offers',
        cta: 'Run offer comparison',
      }
    }

    if (signalCount > 0) {
      return {
        changed: `${signalCount} fresh market signal${signalCount === 1 ? '' : 's'} landed this week.`,
        whyNow: 'Signal freshness decays quickly unless converted to relationship action.',
        recommendedMove: 'Convert one high-relevance signal into a warm outreach draft today.',
        downsideIfDelayed: 'You lose timing edge and return to generic outreach.',
        href: '/dashboard/signals',
        cta: 'Convert strongest signal',
      }
    }

    if (overdueCount > 0) {
      return {
        changed: `${overdueCount} follow-up ${overdueCount === 1 ? 'is' : 'are'} overdue.`,
        whyNow: 'At executive level, delay is often interpreted as loss of conviction.',
        recommendedMove: 'Clear the next due relationship action before adding new scope.',
        downsideIfDelayed: 'Pipeline credibility drops and conversation velocity slows.',
        href: '/dashboard/calendar',
        cta: 'Clear overdue now',
      }
    }

    return {
      changed: 'No urgent blockers, but sponsor depth and cadence still determine outcomes.',
      whyNow: 'Quiet weeks are where high-quality systems get built.',
      recommendedMove: 'Add one sponsor at a priority company and schedule one next step.',
      downsideIfDelayed: 'Momentum looks stable but conversion quality erodes over time.',
      href: '/dashboard/contacts',
      cta: 'Strengthen sponsor map',
    }
  })()

  const offerCockpit = {
    show: offerCompanies.length > 0,
    offerCount: offerCompanies.length,
    offerCompanyName: offerCompany?.name ?? null,
    contextSignals: [
      { label: 'Role thesis clarity', ok: (profile?.positioning_summary?.length ?? 0) >= 80 },
      { label: 'Context constraints captured', ok: !!profile?.briefing_timezone },
      { label: 'Sponsor confirmation path', ok: sponsorCoveragePercent >= 50 },
    ],
  }

  const setupSteps = [
    { done: activation.a1_resume,    label: 'Upload your resume or import LinkedIn', sub: 'Drives every brief, every briefing, and every AI response you get.',                                                         href: '/dashboard/profile',        cta: 'Go to profile' },
    { done: activation.a2_company,   label: 'Add your first target company',         sub: 'Include the career page URL - we scan it within minutes and alert you to matching roles.',                                   href: '/dashboard/companies/new',  cta: 'Add a company' },
    { done: activation.a3_prep_brief,label: 'Generate your first prep brief',        sub: 'Open any target company and run the brief. Leadership signals, likely objections, best outreach angle.',                     href: '/dashboard',      cta: 'Go to companies' },
    { done: activation.a4_contact,   label: 'Add your first contact',                sub: 'Who do you know at target companies? Roles at this level fill through relationships, not applications.',                     href: '/dashboard/contacts',       cta: 'Add a contact' },
    { done: activation.a5_briefing,  label: 'Set up your daily briefing',            sub: 'Signals and due actions in your inbox before you start work.',                                                               href: '/dashboard/profile',        cta: 'Configure briefing' },
    { done: activation.a6_follow_up, label: 'Log your first follow-up reminder',     sub: 'The difference between an active search and a passive one is whether the next action is scheduled.',                        href: '/dashboard/contacts',       cta: 'Go to contacts' },
  ]

  // Post-placement: Career Intelligence mode
  if (profile?.placed_at) {
    const placedCompany = profile?.placement_company
    const isPaid = userRow?.subscription_status === 'active'
    const tier = userRow?.subscription_tier ?? 'free'
    return (
      <DashboardPostPlacementView
        greeting={greeting}
        firstName={firstName}
        today={today}
        placedCompany={placedCompany}
        isPaid={isPaid}
        tier={tier}
        totalCount={totalCount}
        allList={allList}
        canUseOutreachHub={canUseOutreachHub}
        isRothschildAdmin={isRothschildAdmin}
        profileNameOrEmail={profile?.full_name ?? user.email ?? ''}
      />
    )
  }

  return (
    <div className="min-h-screen bg-slate-100 font-sans">

      {/* Nav */}
      <header className="bg-slate-900">
        <div className="max-w-[1280px] mx-auto px-4 sm:px-6 h-12 sm:h-14 flex items-center gap-4 sm:gap-6">
          <span className="text-[13px] font-bold tracking-[0.16em] uppercase text-slate-400 shrink-0">
            <span className="text-white">Starting </span><span className="text-orange-500">Monday</span>
          </span>
          {/* Desktop nav */}
          <div className="hidden sm:flex items-center gap-4 flex-1">
