const CONFIDENCE_THRESHOLD = 60
const DELAY_MS = 600 // between companies to avoid hammering Google News
const SIGNAL_LOCK_KEY = 7329841025n
const USER_PAGE_SIZE = 500
const MAX_USER_PAGES_PER_RUN = Number(process.env.SIGNAL_JOB_MAX_PAGES_PER_RUN ?? 8)
const CHECKPOINT_JOB_NAME = 'signal-job'
const SIGNAL_RETRY_MODE = 'signal_company_retry'

async function fetchActiveUserPage(supabase, afterUserId = null) {
  let query = supabase
    .from('users')
    .select('id, email, subscription_tier')
    .in('subscription_status', ['active', 'trialing'])
    .order('id')
    .limit(USER_PAGE_SIZE)

  if (afterUserId) query = query.gt('id', afterUserId)

  const { data, error } = await query
  return { users: data ?? [], error }
}

function buildSignalMetadata(article, result, override = {}) {
  const sourceKind = override.sourceKind ?? inferSourceKindFromUrl(override.sourceUrl ?? article?.link ?? null)
  const focusTags = override.focusTags ?? inferFocusTags(override.signalType ?? result?.signal_type, result?.focus_tags ?? [])
  const evidenceSnippets = override.evidenceSnippets ?? extractEvidenceSnippets(article, result?.evidence_snippets ?? [])
  const partnerEntities = override.partnerEntities ?? extractPartnershipEntities(article, result?.partner_entities ?? [])

  return {
    confidence: typeof result?.confidence === 'number' ? result.confidence : null,
    sourceKind,
    focusTags,
    evidenceSnippets,
    partnerEntities,
    filingForm: override.filingForm ?? article?.filingForm ?? null,
    filingItems: override.filingItems ?? article?.filingItems ?? [],
  }
}

async function retrySignalCompanyById(supabase, payload) {
  const { companyId, userId } = payload ?? {}
  if (!companyId || !userId) throw new Error('invalid_signal_retry_payload')

  const [{ data: user, error: userErr }, { data: profile, error: profileErr }, { data: company, error: companyErr }] = await Promise.all([
    supabase
      .from('users')
      .select('id, email, subscription_tier')
      .eq('id', userId)
      .in('subscription_status', ['active', 'trialing'])
      .maybeSingle(),
    supabase
      .from('user_profiles')
      .select('user_id, role_type')
      .eq('user_id', userId)
      .maybeSingle(),
    supabase
      .from('companies')
      .select('id, name, user_id')
      .eq('id', companyId)
      .eq('user_id', userId)
      .is('archived_at', null)
      .maybeSingle(),
  ])

  if (userErr) throw new Error(`signal_retry_user_lookup_failed:${userErr.message}`)
  if (profileErr) throw new Error(`signal_retry_profile_lookup_failed:${profileErr.message}`)
  if (companyErr) throw new Error(`signal_retry_company_lookup_failed:${companyErr.message}`)
  if (!user || !company) {
    logger.warn('signal-job: retry target missing; skipping retry payload', {
      userId,
      companyId,
      hasUser: Boolean(user),
      hasCompany: Boolean(company),
    })
    return
  }

  const roleType = profile?.role_type ?? null
  const articles = await fetchCompanyNews(company.name)

  for (const article of articles) {
    const result = await classifySignal(company.name, article, roleType)
    const inferredPartners = extractPartnershipEntities(article, result.partner_entities ?? [])
    const inferredPartnership = inferredPartners.length > 0
    const isStrongSignal = (result.is_signal && (result.confidence ?? 0) >= CONFIDENCE_THRESHOLD) || inferredPartnership
    if (!isStrongSignal) continue

    const normalizedSignalType = inferredPartnership ? 'partnership' : result.signal_type
    const normalizedSummary = inferredPartnership
      ? `${company.name} appears to have a material partnership signal involving ${inferredPartners.join(', ')}.`
      : result.signal_summary
    if (!normalizedSignalType || !normalizedSummary) continue

    const signalDate = article.pubDate
      ? new Date(article.pubDate).toISOString().split('T')[0]
      : new Date().toISOString().split('T')[0]

    await writeSignal(supabase, {
      companyId: company.id,
      userId: user.id,
      signalType: normalizedSignalType,
      signalSummary: normalizedSummary,
      sourceUrl: article.link,
      signalDate,
      outreachAngle: result.outreach_angle ?? null,
      ...buildSignalMetadata(article, result, {
        signalType: normalizedSignalType,
        partnerEntities: inferredPartners,
        focusTags: inferredPartnership
          ? inferFocusTags('partnership', result.focus_tags ?? [])
          : undefined,
      }),
    })
  }
}

export async function runSignalRefreshForUser({ userId, companyId = null }) {
  if (!userId) throw new Error('missing_user_id')

  const supabase = getSupabase()

  if (companyId) {
    await retrySignalCompanyById(supabase, { companyId, userId })
    return { companiesProcessed: 1, companiesFailed: 0 }
  }

  const { data: companies, error } = await supabase
    .from('companies')
    .select('id')
    .eq('user_id', userId)
    .is('archived_at', null)

  if (error) {
    throw new Error(`signal_refresh_company_lookup_failed:${error.message}`)
  }

  let companiesProcessed = 0
  let companiesFailed = 0

  for (const company of companies ?? []) {
    try {
      await retrySignalCompanyById(supabase, { companyId: company.id, userId })
      companiesProcessed += 1
    } catch (err) {
      companiesFailed += 1
      logger.error('signal-job: user refresh company failed', {
        userId,
        companyId: company.id,
        error: err.message,
      })
    }
  }

  return { companiesProcessed, companiesFailed }
}

export async function runSignalJob() {
  const supabase = getSupabase()

  const { data: locked } = await supabase.rpc('try_advisory_lock', { p_key: SIGNAL_LOCK_KEY })
  if (!locked) {
    logger.warn('signal-job: another instance running — skipping')
    return
  }

  try {
    const cycleKey = new Date().toISOString().slice(0, 10)
    const checkpoint = await getJobCheckpoint(supabase, CHECKPOINT_JOB_NAME)
    const hasMatchingCycle = checkpoint?.context?.cycleKey === cycleKey
    let lastUserId = hasMatchingCycle
      ? (checkpoint?.cursor?.lastUserId ?? null)
      : null

    if (lastUserId) {
      logger.info('signal-job: resuming from checkpoint', { lastUserId, cycleKey })
    }

    let pagesProcessed = 0
    let completedCycle = false
    let usersProcessed = 0
    let companiesScanned = 0
    let signalsFound = 0

    while (pagesProcessed < MAX_USER_PAGES_PER_RUN) {
      const { users, error } = await fetchActiveUserPage(supabase, lastUserId)

      if (error) {
        logger.error('signal-job: failed to fetch users', { error: error.message, stack: error.stack })
        return
      }

      if (!users?.length) {
        if (!lastUserId) logger.info('signal-job: no active users')
        completedCycle = true
        break
      }

      pagesProcessed += 1
      usersProcessed += users.length

      const userIds = users.map(u => u.id)
      const { data: profiles } = await supabase
        .from('user_profiles')
        .select('user_id, role_type, full_name, current_title, positioning_summary, target_titles')
        .in('user_id', userIds)
      const roleTypeByUserId = Object.fromEntries((profiles ?? []).map(p => [p.user_id, p.role_type]))
      const profileByUserId  = Object.fromEntries((profiles ?? []).map(p => [p.user_id, p]))

      // Bulk-fetch companies for this user page to keep memory bounded.
      const { data: allCompanies } = await supabase
        .from('companies')
        .select('id, name, crunchbase_id, company_url, linkedin_url, sector, notes, role_watch_description, user_id, sec_cik_padded, is_public_company, activist_checked_at, insider_checked_at')
        .in('user_id', userIds)
        .is('archived_at', null)

      const companiesByUser = (allCompanies ?? []).reduce((acc, c) => {
        ;(acc[c.user_id] ??= []).push(c)
        return acc
      }, {})

      for (const user of users) {
      const roleType    = roleTypeByUserId[user.id] ?? null
      const userProfile = profileByUserId[user.id] ?? null
      const companies   = companiesByUser[user.id] ?? []

      if (!companies.length) continue

      for (const company of companies) {
        companiesScanned++
        try {
          // Google News — classify articles via Claude Haiku
          const articles = await fetchCompanyNews(company.name)
          for (const article of articles) {
            const result = await classifySignal(company.name, article, roleType)
            const inferredPartners = extractPartnershipEntities(article, result.partner_entities ?? [])
            const inferredPartnership = inferredPartners.length > 0
            const isStrongSignal = (result.is_signal && (result.confidence ?? 0) >= CONFIDENCE_THRESHOLD) || inferredPartnership
            if (!isStrongSignal) continue
            const normalizedSignalType = inferredPartnership ? 'partnership' : result.signal_type
            const normalizedSummary = inferredPartnership
              ? `${company.name} appears to have a material partnership signal involving ${inferredPartners.join(', ')}.`
              : result.signal_summary
            if (!normalizedSignalType || !normalizedSummary) continue

            const signalDate = article.pubDate
              ? new Date(article.pubDate).toISOString().split('T')[0]
              : new Date().toISOString().split('T')[0]

            const { skipped } = await writeSignal(supabase, {
              companyId:     company.id,
              userId:        user.id,
              signalType:    normalizedSignalType,
              signalSummary: normalizedSummary,
              sourceUrl:     article.link,
              signalDate,
              outreachAngle: result.outreach_angle ?? null,
              ...buildSignalMetadata(article, result, {
                signalType: normalizedSignalType,
                partnerEntities: inferredPartners,
                focusTags: inferredPartnership
                  ? inferFocusTags('partnership', result.focus_tags ?? [])
                  : undefined,
              }),
            })

            if (!skipped) {
              signalsFound++
              logger.info('signal-job: new signal', { company: company.name, type: normalizedSignalType })
            }
          }

          // Press room — scrape company's own newsroom for press releases
          if (company.company_url) {
            const pressArticles = await findPressRoomArticles(company.company_url)
            for (const article of pressArticles) {
              const result = await classifySignal(company.name, article, roleType)
              const inferredPartners = extractPartnershipEntities(article, result.partner_entities ?? [])
              const inferredPartnership = inferredPartners.length > 0
              const isStrongSignal = (result.is_signal && (result.confidence ?? 0) >= CONFIDENCE_THRESHOLD) || inferredPartnership
              if (!isStrongSignal) continue
              const normalizedSignalType = inferredPartnership ? 'partnership' : result.signal_type
              const normalizedSummary = inferredPartnership
                ? `${company.name} appears to have a material partnership signal involving ${inferredPartners.join(', ')}.`
                : result.signal_summary
              if (!normalizedSignalType || !normalizedSummary) continue

              const { skipped } = await writeSignal(supabase, {
                companyId:     company.id,
                userId:        user.id,
                signalType:    normalizedSignalType,
                signalSummary: normalizedSummary,
                sourceUrl:     article.link,
                signalDate:    new Date().toISOString().split('T')[0],
                outreachAngle: result.outreach_angle ?? null,
                ...buildSignalMetadata(article, result, {
                  signalType: normalizedSignalType,
                  partnerEntities: inferredPartners,
                  focusTags: inferredPartnership
                    ? inferFocusTags('partnership', result.focus_tags ?? [])
                    : undefined,
                }),
              })
              if (!skipped) {
                signalsFound++
                logger.info('signal-job: press room signal', { company: company.name, type: normalizedSignalType })
              }
            }
          }

          // SEC EDGAR 8-K filings — exec changes, acquisitions, bankruptcy, material events
          // Passing supabase+companyId also indexes all 8-K filings for trend detection below.
          const secRun = await startSecIngestionRun(supabase, {
            source: 'signal-job',
            companyId: company.id,
            companyName: company.name,
            companyCik: company.sec_cik_padded ?? null,
            metadata: {
              userId: user.id,
              roleType,
            },
          })

          const secResult = await fetchSecFilings(company.name, { supabase, companyId: company.id })
          let secSignalsEmitted = 0

          for (const article of secResult.articles) {
            const result = await classifySignal(company.name, article, roleType)
            if (!result.is_signal || (result.confidence ?? 0) < CONFIDENCE_THRESHOLD) continue
            if (!result.signal_type || !result.signal_summary) continue

            const signalDate = article.pubDate
              ? new Date(article.pubDate).toISOString().split('T')[0]
              : new Date().toISOString().split('T')[0]

            const { skipped } = await writeSignal(supabase, {
              companyId:     company.id,
              userId:        user.id,
              signalType:    result.signal_type,
              signalSummary: result.signal_summary,
              sourceUrl:     article.link,
              signalDate,
              outreachAngle: result.outreach_angle ?? null,
              ...buildSignalMetadata(article, result),
            })
            if (!skipped) {
              signalsFound++
              secSignalsEmitted++
              logger.info('signal-job: SEC filing signal', { company: company.name, type: result.signal_type })
            }
          }

          await finishSecIngestionRun(supabase, secRun.runId, {
            status: secResult.fetchError ? 'error' : 'success',
            filingsConsidered: secResult.indexStats.filingsConsidered,
            filingsIndexed: secResult.indexStats.filingsIndexed,
            secArticles: secResult.articles.length,
            signalsEmitted: secSignalsEmitted,
            latestFilingDate: secResult.indexStats.latestFilingDate,
            latestIngestedAt: secResult.indexStats.latestIngestedAt,
            errorMessage: secResult.fetchError,
            metadata: {
              userId: user.id,
              companyName: company.name,
            },
          })

          // SEC 8-K trend detection — cross-filing pattern analysis from indexed history
          const secTrend = await detectSecTrends(supabase, company.id, company.name, roleType)
          if (secTrend) {
            const weekSlot = Math.floor(Date.now() / (7 * 24 * 60 * 60 * 1000))
            const { skipped } = await writeSignal(supabase, {
              companyId:     company.id,
              userId:        user.id,
              signalType:    'filing_trend',
              signalSummary: secTrend.signal_summary,
              sourceUrl:     `sec-trend://${company.id}/${weekSlot}`,
              signalDate:    new Date().toISOString().split('T')[0],
              outreachAngle: secTrend.outreach_angle ?? null,
              sourceKind: 'sec_filing',
              focusTags: inferFocusTags('filing_trend'),
              evidenceSnippets: [secTrend.signal_summary],
            })
            if (!skipped) {
              signalsFound++
              logger.info('signal-job: SEC trend signal', { company: company.name })
            }
          }

          // DEF 14A proxy — board composition diff (public companies only, 90-day guard)
          if (company.sec_cik_padded) {
            const boardChanges = await fetchProxyBoardChanges(company.name, { supabase, companyId: company.id })
            for (const change of boardChanges) {
              const today = new Date().toISOString().split('T')[0]
              const { skipped } = await writeSignal(supabase, {
                companyId:     company.id,
                userId:        user.id,
                signalType:    'board_change',
                signalSummary: change.signal_summary,
                sourceUrl:     null,
                signalDate:    today,
                outreachAngle: change.outreach_angle,
                sourceKind: 'sec_filing',
                focusTags: inferFocusTags('board_change'),
                evidenceSnippets: [change.signal_summary],
              })
              if (!skipped) {
                signalsFound++
                logger.info('signal-job: board change', { company: company.name, type: change.changeType, director: change.directorName })
              }
            }
          }

          // SC 13D activist investor watcher (public companies only, 7-day throttle)
          if (company.sec_cik_padded) {
            const activistSignals = await fetchActivistFilings(company.name, {
              supabase,
              companyId:          company.id,
              activistCheckedAt:  company.activist_checked_at,
            })
            for (const sig of activistSignals) {
              const { skipped } = await writeSignal(supabase, {
                companyId:     company.id,
                userId:        user.id,
                signalType:    'activist_entry',
                signalSummary: sig.signal_summary,
                sourceUrl:     null,
                signalDate:    sig.filing_date,
                outreachAngle: sig.outreach_angle,
                sourceKind: 'sec_filing',
                focusTags: ['governance', 'leadership'],
                evidenceSnippets: [sig.signal_summary],
              })
              if (!skipped) {
                signalsFound++
                logger.info('signal-job: activist entry', { company: company.name, activist: sig.activist_name })
              }
            }
          }

          // Form 4 insider sales — material open-market share sales by named officers (7-day throttle)
          if (company.sec_cik_padded) {
            const insiderSignals = await fetchInsiderSales(company.name, {
              supabase,
              companyId:         company.id,
              insiderCheckedAt:  company.insider_checked_at,
            })
            for (const sig of insiderSignals) {
              const { skipped } = await writeSignal(supabase, {
                companyId:     company.id,
                userId:        user.id,
                signalType:    'insider_sale',
                signalSummary: sig.signal_summary,
                sourceUrl:     null,
                signalDate:    sig.signalDate,
                outreachAngle: sig.outreach_angle,
                sourceKind: 'sec_filing',
                focusTags: ['governance', 'leadership'],
                evidenceSnippets: [sig.signal_summary],
              })
              if (!skipped) {
                signalsFound++
                logger.info('signal-job: insider sale', { company: company.name })
              }
            }
          }

          // PR wire — prnewswire, businesswire, globenewswire via Google News RSS
          const prArticles = await fetchPrWire(company.name)
          for (const article of prArticles) {
            const result = await classifySignal(company.name, article, roleType)
            const inferredPartners = extractPartnershipEntities(article, result.partner_entities ?? [])
            const inferredPartnership = inferredPartners.length > 0
            const isStrongSignal = (result.is_signal && (result.confidence ?? 0) >= CONFIDENCE_THRESHOLD) || inferredPartnership
            if (!isStrongSignal) continue
            const normalizedSignalType = inferredPartnership ? 'partnership' : result.signal_type
            const normalizedSummary = inferredPartnership
              ? `${company.name} appears to have a material partnership signal involving ${inferredPartners.join(', ')}.`
              : result.signal_summary
            if (!normalizedSignalType || !normalizedSummary) continue

            const signalDate = article.pubDate
              ? new Date(article.pubDate).toISOString().split('T')[0]
              : new Date().toISOString().split('T')[0]

            const { skipped } = await writeSignal(supabase, {
              companyId:     company.id,
              userId:        user.id,
              signalType:    normalizedSignalType,
              signalSummary: normalizedSummary,
              sourceUrl:     article.link,
              signalDate,
              outreachAngle: result.outreach_angle ?? null,
              ...buildSignalMetadata(article, result, {
                signalType: normalizedSignalType,
                partnerEntities: inferredPartners,
                focusTags: inferredPartnership
                  ? inferFocusTags('partnership', result.focus_tags ?? [])
                  : undefined,
              }),
            })
            if (!skipped) {
              signalsFound++
              logger.info('signal-job: PR wire signal', { company: company.name, type: normalizedSignalType })
            }
          }

          // Business journals — Bizjournals.com network (private + mid-market coverage)
          const bizArticles = await fetchBizJournalMentions(company.name)
          for (const article of bizArticles) {
            const result = await classifySignal(company.name, article, roleType)
            const inferredPartners = extractPartnershipEntities(article, result.partner_entities ?? [])
            const inferredPartnership = inferredPartners.length > 0
            const isStrongSignal = (result.is_signal && (result.confidence ?? 0) >= CONFIDENCE_THRESHOLD) || inferredPartnership
            if (!isStrongSignal) continue
            const normalizedSignalType = inferredPartnership ? 'partnership' : result.signal_type
            const normalizedSummary = inferredPartnership
              ? `${company.name} appears to have a material partnership signal involving ${inferredPartners.join(', ')}.`
              : result.signal_summary
            if (!normalizedSignalType || !normalizedSummary) continue

            const signalDate = article.pubDate
              ? new Date(article.pubDate).toISOString().split('T')[0]
              : new Date().toISOString().split('T')[0]

            const { skipped } = await writeSignal(supabase, {
              companyId:     company.id,
              userId:        user.id,
              signalType:    normalizedSignalType,
              signalSummary: normalizedSummary,
              sourceUrl:     article.link,
              signalDate,
              outreachAngle: result.outreach_angle ?? null,
              ...buildSignalMetadata(article, result, {
                signalType: normalizedSignalType,
                partnerEntities: inferredPartners,
                focusTags: inferredPartnership
                  ? inferFocusTags('partnership', result.focus_tags ?? [])
                  : undefined,
              }),
            })
            if (!skipped) {
              signalsFound++
              logger.info('signal-job: bizjournal signal', { company: company.name, type: normalizedSignalType })
            }
          }

          // Tech trade press — CIO/CTO/CISO-focused publications
          const tradeArticles = await fetchTradePressArticles(company.name)
          for (const article of tradeArticles) {
            const result = await classifySignal(company.name, article, roleType)
            const inferredPartners = extractPartnershipEntities(article, result.partner_entities ?? [])
            const inferredPartnership = inferredPartners.length > 0
            const isStrongSignal = (result.is_signal && (result.confidence ?? 0) >= CONFIDENCE_THRESHOLD) || inferredPartnership
            if (!isStrongSignal) continue
            const normalizedSignalType = inferredPartnership ? 'partnership' : result.signal_type
            const normalizedSummary = inferredPartnership
              ? `${company.name} appears to have a material partnership signal involving ${inferredPartners.join(', ')}.`
              : result.signal_summary
            if (!normalizedSignalType || !normalizedSummary) continue

            const signalDate = article.pubDate
              ? new Date(article.pubDate).toISOString().split('T')[0]
              : new Date().toISOString().split('T')[0]

            const { skipped } = await writeSignal(supabase, {
              companyId:     company.id,
              userId:        user.id,
              signalType:    normalizedSignalType,
              signalSummary: normalizedSummary,
              sourceUrl:     article.link,
              signalDate,
              outreachAngle: result.outreach_angle ?? null,
              ...buildSignalMetadata(article, result, {
                signalType: normalizedSignalType,
                partnerEntities: inferredPartners,
                focusTags: inferredPartnership
                  ? inferFocusTags('partnership', result.focus_tags ?? [])
                  : undefined,
              }),
            })
            if (!skipped) {
              signalsFound++
              logger.info('signal-job: trade press signal', { company: company.name, type: normalizedSignalType })
            }
          }

          // Regulatory calendar — sector-level compliance pressure signals (90-day dedup)
          const regulatorySignals = await checkRegulatoryCalendar(company, { supabase, userId: user.id })
          for (const sig of regulatorySignals) {
            const { skipped } = await writeSignal(supabase, {
              companyId:     company.id,
              userId:        user.id,
              signalType:    'regulatory_change',
              signalSummary: sig.signal_summary,
              sourceUrl:     sig.sourceUrl,
              signalDate:    new Date().toISOString().split('T')[0],
              outreachAngle: sig.outreach_angle,
              sourceKind: 'regulatory_calendar',
              focusTags: inferFocusTags('regulatory_change'),
              evidenceSnippets: [sig.signal_summary],
            })
            if (!skipped) {
              signalsFound++
              logger.info('signal-job: regulatory signal', { company: company.name, event: sig.eventName })
            }
          }

          // PredictLeads — executive changes and company event signals
          if (company.company_url && process.env.PREDICTLEADS_API_KEY) {
            const plArticles = await fetchPredictLeadsSignals(company.company_url, company.name)
            for (const article of plArticles) {
              // PredictLeads signals are already typed — use the mapped type directly
              // and run classify only to generate the signal_summary and outreach_angle.
              const result = await classifySignal(company.name, article, roleType)
              if (!result.is_signal || (result.confidence ?? 0) < CONFIDENCE_THRESHOLD) continue
              if (!result.signal_summary) continue

              const signalDate = article.pubDate
                ? new Date(article.pubDate).toISOString().split('T')[0]
                : new Date().toISOString().split('T')[0]

              const { skipped } = await writeSignal(supabase, {
                companyId:     company.id,
                userId:        user.id,
                signalType:    article._predictleadsType,
                signalSummary: result.signal_summary,
                sourceUrl:     article.link,
                signalDate,
                outreachAngle: result.outreach_angle ?? null,
                ...buildSignalMetadata(article, result, { signalType: article._predictleadsType }),
              })
              if (!skipped) {
                signalsFound++
                logger.info('signal-job: predictleads signal', { company: company.name, type: article._predictleadsType })
              }
            }
          }

          // Crunchbase — structured funding rounds (no classification needed)
          if (company.crunchbase_id && process.env.CRUNCHBASE_API_KEY) {
            const rounds = await fetchCrunchbaseFunding(company.crunchbase_id)
            for (const round of rounds) {
              const { signal_summary, outreach_angle } = formatFundingSignal(company.name, round)
              const { skipped } = await writeSignal(supabase, {
                companyId:     company.id,
                userId:        user.id,
                signalType:    'funding',
                signalSummary: signal_summary,
                sourceUrl:     round.sourceUrl,
                signalDate:    round.announcedOn,
                outreachAngle: outreach_angle,
                sourceKind: inferSourceKindFromUrl(round.sourceUrl),
                focusTags: inferFocusTags('funding'),
                evidenceSnippets: [signal_summary],
              })
              if (!skipped) {
                signalsFound++
                logger.info('signal-job: crunchbase funding signal', { company: company.name, amount: round.amount })
              }
            }
          }
          // Proxycurl exec snapshot — detect departures and hires by diffing LinkedIn data
          if (process.env.PDL_API_KEY) {
            const today = new Date().toISOString().split('T')[0]
            const { data: existingSnapshot } = await supabase
              .from('exec_snapshots')
              .select('id')
              .eq('company_id', company.id)
              .eq('snapshot_date', today)
              .maybeSingle()

            if (!existingSnapshot) {
              const currentExecs = await fetchPdlExecs(company.name, company.company_url ?? null)
              if (currentExecs.length > 0) {
                const { departures, hires } = await diffExecSnapshot(supabase, company.id, user.id, currentExecs, today)

                for (const exec of departures) {
                  const outreachAngle = `The departure of ${exec.name} as ${exec.title} creates an opening for external executive talent. Reach out before the search is formalized.`
                  const { skipped, signalId } = await writeSignal(supabase, {
                    companyId:     company.id,
                    userId:        user.id,
                    signalType:    'exec_departure',
                    signalSummary: `${exec.name} (${exec.title}) departed ${company.name}.`,
                    sourceUrl:     exec.linkedin_url ? `${exec.linkedin_url}#departure` : null,
                    signalDate:    today,
                    outreachAngle,
                    sourceKind: 'executive_snapshot',
                    focusTags: inferFocusTags('exec_departure'),
                    evidenceSnippets: [`${exec.name} (${exec.title}) departed ${company.name}.`],
                  })
                  if (!skipped) {
                    signalsFound++
                    logger.info('signal-job: exec departure', { company: company.name, exec: exec.name })
                    if (user.subscription_tier === 'executive' && user.email) {
                      generateOutreachDraft({
                        companyName: company.name,
                        signalType: 'exec_departure',
                        signalSummary: `${exec.name} (${exec.title}) departed ${company.name}.`,
                        outreachAngle,
                        userProfile,
                        companyContext: {
                          sector: company.sector ?? null,
                          notes: company.notes ?? null,
                          roleWatchDescription: company.role_watch_description ?? null,
                        },
                      }).then(draft => {
                        if (draft && signalId) {
                          supabase.from('company_signals').update({ outreach_draft: draft }).eq('id', signalId).then(() => {})
                        }
                        sendSignalAlert({
                          to: user.email,
                          companyName: company.name,
                          patternName: 'Exec Departure',
                          summary: `${exec.name} (${exec.title}) has departed ${company.name}. No replacement announced yet.`,
                          outreachAngle,
                          outreachDraft: draft ?? null,
                        }).catch(err => logger.error('signal-job: exec departure alert failed', { error: err.message }))
                      }).catch(err => logger.error('signal-job: exec departure draft failed', { error: err.message }))
                    }
                  }
                }

                for (const exec of hires) {
                  const { skipped } = await writeSignal(supabase, {
                    companyId:     company.id,
                    userId:        user.id,
                    signalType:    'exec_hire',
                    signalSummary: `${exec.name} joined ${company.name} as ${exec.title}.`,
                    sourceUrl:     exec.linkedin_url ? `${exec.linkedin_url}#hire` : null,
                    signalDate:    today,
                    outreachAngle: `A new ${exec.title} at ${company.name} often builds new relationships early in tenure. This is a strong moment to introduce yourself.`,
                    sourceKind: 'executive_snapshot',
                    focusTags: inferFocusTags('exec_hire'),
                    evidenceSnippets: [`${exec.name} joined ${company.name} as ${exec.title}.`],
                  })
                  if (!skipped) {
                    signalsFound++
                    logger.info('signal-job: exec hire', { company: company.name, exec: exec.name })
                  }
                }
              }
            }
          }

          // Signal correlation — detect multi-signal patterns across the past 60 days
          const cutoff60 = new Date(Date.now() - 60 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]
          const { data: recentSignals } = await supabase
            .from('company_signals')
            .select('signal_type, signal_summary, signal_date')
            .eq('company_id', company.id)
            .eq('user_id', user.id)
            .gte('signal_date', cutoff60)
            .neq('signal_type', 'pattern_alert')
            .order('signal_date', { ascending: false })
            .limit(10)

          if ((recentSignals?.length ?? 0) >= 2) {
            const correlation = await correlateSignals(company.name, recentSignals, roleType)
            if (correlation.detected && correlation.pattern_name) {
              const weekSlot = Math.floor(Date.now() / (7 * 24 * 60 * 60 * 1000))
              const { skipped, signalId: patternSignalId } = await writeSignal(supabase, {
                companyId:     company.id,
                userId:        user.id,
                signalType:    'pattern_alert',
                signalSummary: `${correlation.pattern_name}: ${correlation.pattern_summary}`,
                sourceUrl:     `pattern://${correlation.pattern_name.toLowerCase().replace(/\s+/g, '_')}/${weekSlot}`,
                signalDate:    new Date().toISOString().split('T')[0],
                outreachAngle: correlation.outreach_angle ?? null,
                sourceKind: 'pattern_correlation',
                focusTags: ['leadership', 'operations'],
                evidenceSnippets: [correlation.pattern_summary],
              })
              if (!skipped) {
                signalsFound++
                logger.info('signal-job: pattern alert', { company: company.name, pattern: correlation.pattern_name })
                if (user.subscription_tier === 'executive' && user.email) {
                  generateOutreachDraft({
                    companyName: company.name,
                    signalType: 'pattern_alert',
                    signalSummary: correlation.pattern_summary,
                    outreachAngle: correlation.outreach_angle ?? null,
                    userProfile,
                    companyContext: {
                      sector: company.sector ?? null,
                      notes: company.notes ?? null,
                      roleWatchDescription: company.role_watch_description ?? null,
                    },
                  }).then(draft => {
                    if (draft && patternSignalId) {
                      supabase.from('company_signals').update({ outreach_draft: draft }).eq('id', patternSignalId).then(() => {})
                    }
                    sendSignalAlert({
                      to: user.email,
                      companyName: company.name,
                      patternName: correlation.pattern_name,
                      summary: correlation.pattern_summary,
                      outreachAngle: correlation.outreach_angle ?? null,
                      outreachDraft: draft ?? null,
                    }).catch(err => logger.error('signal-job: pattern alert email failed', { error: err.message }))
                  }).catch(err => logger.error('signal-job: pattern draft failed', { error: err.message }))
                }
              }
            }
          }
        } catch (err) {
          logger.error('signal-job: error', { company: company.name, error: err.message, stack: err.stack })

          await enqueueHeavyJob(supabase, {
            jobType: CHECKPOINT_JOB_NAME,
            payload: {
              mode: SIGNAL_RETRY_MODE,
              companyId: company.id,
              userId: user.id,
            },
            idempotencyKey: `${company.id}:${user.id}:${cycleKey}`,
            maxAttempts: 5,
          })
        }

        await new Promise(r => setTimeout(r, DELAY_MS))
      }
      }

      lastUserId = users[users.length - 1]?.id ?? lastUserId

      await saveJobCheckpoint(supabase, CHECKPOINT_JOB_NAME, {
        cursor: {
          lastUserId,
          pagesProcessed,
          usersProcessed,
          companiesScanned,
          signalsFound,
        },
        context: {
          cycleKey,
          updatedAt: new Date().toISOString(),
        },
      })

      if (users.length < USER_PAGE_SIZE) {
        completedCycle = true
        break
      }
    }

    if (completedCycle) {
      await clearJobCheckpoint(supabase, CHECKPOINT_JOB_NAME)
    } else {
      logger.warn('signal-job: page budget reached; resume will continue from checkpoint', {
        pagesProcessed,
        usersProcessed,
        lastUserId,
      })
    }

    const retryResult = await processHeavyJobs(supabase, {
      jobType: CHECKPOINT_JOB_NAME,
      limit: 10,
      handler: async (job) => {
        const payload = job?.payload ?? {}
        if (payload.mode !== SIGNAL_RETRY_MODE) {
          throw new Error('unsupported_signal_retry_payload')
        }
        await retrySignalCompanyById(supabase, payload)
      },
    })

    if ((retryResult.processed ?? 0) > 0) {
      logger.info('signal-job: retry queue processed', retryResult)
    }

    logger.info('signal-job: complete', { companiesScanned, signalsFound, usersProcessed, pagesProcessed })
  } finally {
    await supabase.rpc('advisory_unlock', { p_key: SIGNAL_LOCK_KEY })
  }
}

'use client'
import { useState, useRef } from 'react'

type Props = {
  resumeText: string
  initialJobDescription?: string
  companyName?: string
  companyId?: string
  defaultTargetTitle?: string
}

type Parsed = {
  tailored: string
  keywords: string
  changes: string
}

type QualityCheck = {
  atsScore: string
  atsNotes: string
  recruiterGrade: string
  recruiterNotes: string
  hiringManagerGrade: string
  hiringManagerNotes: string
  weakBullets: string
  verbalCover: string
  sixSecondGrade: string
  sixSecondNotes: string
}

type Section = 'all' | 'resume' | 'keywords' | 'changes' | 'quality'

function cleanResume(text: string): string {
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/^#{1,3} (.*)/gm, (_, body) => body.toUpperCase())
    .replace(/^-{3,}\s*$/gm, '')
    .replace(/_{3,}/g, '')
    .replace(/-/g, ',')
    .replace(/\n{3,}/g, '\n\n')
    .trim()
}

function parseOutput(raw: string): Parsed {
  const tailoredMatch = raw.match(/## TAILORED RESUME\s*([\s\S]*?)(?=## KEYWORD ANALYSIS|$)/i)
  const keywordsMatch = raw.match(/## KEYWORD ANALYSIS\s*([\s\S]*?)(?=## KEY CHANGES|$)/i)
  const changesMatch  = raw.match(/## KEY CHANGES\s*([\s\S]*)$/i)
  const tailored = tailoredMatch?.[1]?.trim() ?? (!keywordsMatch && !changesMatch ? raw.trim() : '')
  return {
    tailored,
    keywords: keywordsMatch?.[1]?.trim() ?? '',
    changes:  changesMatch?.[1]?.trim()  ?? '',
  }
}

function parseQualityCheck(raw: string): QualityCheck {
  const get = (header: string, nextHeader?: string) => {
    const pattern = nextHeader
      ? new RegExp(`## ${header}\\s*([\\s\\S]*?)(?=## ${nextHeader}|$)`)
      : new RegExp(`## ${header}\\s*([\\s\\S]*)$`)
    return raw.match(pattern)?.[1]?.trim() ?? ''
  }
  return {
    atsScore:            get('ATS SCORE',           'ATS NOTES').replace(/\D/g, ''),
    atsNotes:            get('ATS NOTES',            'RECRUITER GRADE'),
    recruiterGrade:      get('RECRUITER GRADE',      'RECRUITER NOTES').slice(0, 1).toUpperCase(),
    recruiterNotes:      get('RECRUITER NOTES',      'HIRING MANAGER GRADE'),
    hiringManagerGrade:  get('HIRING MANAGER GRADE', 'HIRING MANAGER NOTES').slice(0, 1).toUpperCase(),
    hiringManagerNotes:  get('HIRING MANAGER NOTES', 'WEAK BULLETS'),
    weakBullets:         get('WEAK BULLETS',         'VERBAL COVER'),
    verbalCover:         get('VERBAL COVER',         'SIX SECOND TEST'),
    sixSecondGrade:      get('SIX SECOND TEST',      'SIX SECOND NOTES').slice(0, 1).toUpperCase(),
    sixSecondNotes:      get('SIX SECOND NOTES'),
  }
}

function gradeColor(grade: string) {
  return grade === 'A' ? 'text-green-700 bg-green-50 border-green-200'
    : grade === 'B'    ? 'text-blue-700 bg-blue-50 border-blue-100'
    : grade === 'C'    ? 'text-amber-700 bg-amber-50 border-amber-200'
    : 'text-red-700 bg-red-50 border-red-200'
}

function atsColor(score: number) {
  return score >= 85 ? 'text-green-700'
    : score >= 70    ? 'text-blue-700'
    : score >= 55    ? 'text-amber-600'
    : 'text-red-700'
}

function BulletList({ text }: { text: string }) {
  const lines = text.split('\n').filter(Boolean)
  return (
    <div className="flex flex-col gap-1.5">
      {lines.map((line, i) => (
        <div key={i} className="flex items-start gap-2.5">
          <span className="text-slate-300 shrink-0 mt-0.5 text-[12px]">-</span>
          <p className="text-[13px] text-slate-700 leading-relaxed">{line.replace(/^[-*•]\s*/, '')}</p>
        </div>
      ))}
    </div>
  )
}

async function downloadDocx(text: string, companyName: string, suffix?: string) {
  const { Document, Packer, Paragraph, TextRun, HeadingLevel } = await import('docx')

  const lines = text.split('\n')
  const children = lines.map(line => {
    const trimmed = line.trim()
    if (!trimmed) return new Paragraph({ children: [new TextRun('')], spacing: { after: 100 } })
    if (trimmed === trimmed.toUpperCase() && trimmed.length > 3 && !/^\d/.test(trimmed)) {
      return new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [new TextRun({ text: trimmed, bold: true })],
        spacing: { before: 280, after: 120 },
      })
    }
    if (/^[-*•]/.test(trimmed)) {
      return new Paragraph({
        bullet: { level: 0 },
        children: [new TextRun({ text: trimmed.replace(/^[-*•]\s*/, ''), size: 22 })],
        spacing: { after: 60 },
      })
    }
    return new Paragraph({
      children: [new TextRun({ text: trimmed, size: 22 })],
      spacing: { after: 80 },
    })
  })

  const doc = new Document({ sections: [{ children }] })
  const blob = await Packer.toBlob(doc)
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  const base = companyName ? `Resume - ${companyName}` : 'Resume - Tailored'
  a.download = suffix ? `${base} (${suffix}).docx` : `${base}.docx`
  a.click()
  URL.revokeObjectURL(url)
}

const SECTION_TABS: { id: Section; label: string }[] = [
  { id: 'all',      label: 'Show All' },
  { id: 'resume',   label: 'Tailored Resume' },
  { id: 'keywords', label: 'Keywords' },
  { id: 'changes',  label: 'Key Changes' },
  { id: 'quality',  label: 'Quality Check' },
]

export function ResumeTailor({ resumeText, initialJobDescription = '', companyName = '', defaultTargetTitle = '' }: Props) {
  const [jd, setJd]                   = useState(initialJobDescription)
  const [targetTitle, setTargetTitle] = useState(defaultTargetTitle)
  const [output, setOutput]           = useState('')
  const [streaming, setStreaming]     = useState(false)
  const [done, setDone]               = useState(false)
  const [error, setError]             = useState('')
  const [copied, setCopied]           = useState(false)

  const [checkRaw, setCheckRaw]               = useState('')
  const [checkStreaming, setCheckStreaming]   = useState(false)
  const [checkDone, setCheckDone]             = useState(false)
  const [checkError, setCheckError]           = useState('')

  const [activeSection, setActiveSection]     = useState<Section>('all')

  const [strengthenRaw, setStrengthenRaw]     = useState('')
  const [strengthening, setStrengthening]     = useState(false)
  const [strengthenDone, setStrengthenDone]   = useState(false)
  const [strengthenError, setStrengthenError] = useState('')
  const [strengthenCopied, setStrengthenCopied] = useState(false)

  const abortRef = useRef<AbortController | null>(null)
  const bufRef   = useRef('')

  const parsedRaw = done ? parseOutput(output) : null
  const parsed = parsedRaw ? { ...parsedRaw, tailored: cleanResume(parsedRaw.tailored) } : null
  const quality = checkDone ? parseQualityCheck(checkRaw) : null
  const strengthenedResume = strengthenDone ? cleanResume(strengthenRaw) : ''

  function show(section: Exclude<Section, 'all'>) {
    return activeSection === 'all' || activeSection === section
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (streaming) return
    bufRef.current = ''
    setStreaming(true)
    setDone(false)
    setOutput('')
    setError('')
    setCopied(false)
    setCheckRaw('')
    setCheckDone(false)
    setCheckError('')
    setActiveSection('all')
    setStrengthenRaw('')
    setStrengthenDone(false)
    setStrengthenError('')
    abortRef.current = new AbortController()

    try {
      const res = await fetch('/api/tailor', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ resumeText, jobDescription: jd, companyName, targetTitle }),
        signal: abortRef.current.signal,
      })

      if (!res.ok) {
        const json = await res.json().catch(() => ({}))
        setError(json.error ?? 'Something went wrong.')
        setStreaming(false)
        return
      }

      const reader = res.body!.getReader()
      const decoder = new TextDecoder()
      let isDone = false
      while (!isDone) {
        const { value, done: d } = await reader.read()
        isDone = d
        if (value) bufRef.current += decoder.decode(value, { stream: !isDone })
      }
      setOutput(bufRef.current)
      setDone(true)
    } catch (err) {
      if ((err as Error).name !== 'AbortError') setError('Connection lost. Try again.')
    } finally {
      setStreaming(false)
    }
  }

  async function handleQualityCheck() {
    if (checkStreaming) return
    if (!parsed?.tailored) {
      setCheckError('Could not find the tailored resume. Try tailoring again.')
      return
    }
    setCheckStreaming(true)
    setCheckDone(false)
    setCheckRaw('')
    setCheckError('')

    try {
      const res = await fetch('/api/tailor/check', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ tailoredResume: parsed.tailored, jobDescription: jd, companyName }),
      })

      if (!res.ok) {
        const json = await res.json().catch(() => ({}))
        setCheckError(json.error ?? 'Quality check failed.')
        setCheckStreaming(false)
        return
      }

      const reader = res.body!.getReader()
      const decoder = new TextDecoder()
      let isDone = false
      while (!isDone) {
        const { value, done: d } = await reader.read()
        isDone = d
        if (value) setCheckRaw(prev => prev + decoder.decode(value, { stream: !isDone }))
      }
      setCheckDone(true)
    } catch {
      setCheckError('Connection lost. Try again.')
    } finally {
      setCheckStreaming(false)
    }
  }

  async function handleStrengthen() {
    if (strengthening || !parsed?.tailored || !quality?.weakBullets) return
    setStrengthening(true)
    setStrengthenDone(false)
    setStrengthenRaw('')
    setStrengthenError('')

    try {
      const res = await fetch('/api/tailor/strengthen', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          tailoredResume: parsed.tailored,
          weakBullets: quality.weakBullets,
          jobDescription: jd,
          companyName,
        }),
      })

      if (!res.ok) {
        const json = await res.json().catch(() => ({}))
        setStrengthenError(json.error ?? 'Strengthen failed.')
        setStrengthening(false)
        return
      }

      const reader = res.body!.getReader()
      const decoder = new TextDecoder()
      let isDone = false
      while (!isDone) {
        const { value, done: d } = await reader.read()
        isDone = d
        if (value) setStrengthenRaw(prev => prev + decoder.decode(value, { stream: !isDone }))
      }
      setStrengthenDone(true)
    } catch {
      setStrengthenError('Connection lost. Try again.')
    } finally {
      setStrengthening(false)
    }
  }

  function handleCopy() {
    if (!parsed?.tailored) return
    navigator.clipboard.writeText(parsed.tailored)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  function handleStrengthenCopy() {
    if (!strengthenedResume) return
    navigator.clipboard.writeText(strengthenedResume)
    setStrengthenCopied(true)
    setTimeout(() => setStrengthenCopied(false), 2000)
  }

  const canSubmit = jd.trim().length >= 100 && !streaming

  return (
    <div className="flex flex-col gap-6">

      {/* Input form */}
      <div className="bg-white border border-slate-200 rounded overflow-hidden">
        <div className="px-6 py-[18px] border-b border-slate-200">
          <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Job Description</span>
        </div>
        <form onSubmit={handleSubmit}>
          <div className="px-6 pt-5 pb-3">
            <label className="block text-[11px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-1.5">
              Target title <span className="text-slate-300 font-normal">(optional)</span>
            </label>
            <input
              type="text"
              value={targetTitle}
              onChange={e => setTargetTitle(e.target.value)}
              disabled={streaming}
              placeholder="VP of Engineering"
              className="w-full border border-slate-200 rounded px-3 py-2.5 text-[14px] text-slate-900 placeholder:text-slate-300 focus:outline-none focus:border-slate-400 disabled:opacity-60"
            />
          </div>
          <div className="px-6 pb-3">
            <label className="block text-[11px] font-bold tracking-[0.08em] uppercase text-slate-500 mb-1.5">
              Job description <span className="text-red-500">*</span>
            </label>
            <textarea
              value={jd}
              onChange={e => setJd(e.target.value)}
              disabled={streaming}
              placeholder="Paste the full job description here..."
              rows={10}
              className="w-full border border-slate-200 rounded px-3 py-2.5 text-[14px] text-slate-800 placeholder:text-slate-300 resize-none focus:outline-none focus:border-slate-400 leading-relaxed disabled:opacity-60"
            />
          </div>
          <div className="px-6 pb-5 flex items-center justify-between gap-4">
            <span className="text-[12px] text-slate-400">
              {jd.length > 0 ? `${jd.length.toLocaleString()} characters` : 'Min. 100 characters'}
            </span>
            <button
              type="submit"
              disabled={!canSubmit}
              className="text-[13px] font-semibold text-white bg-slate-900 hover:bg-slate-700 px-5 py-2.5 rounded transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer"
            >
              {streaming ? 'Tailoring...' : 'Tailor my resume'}
            </button>
          </div>
        </form>
      </div>

      {/* Error */}
      {error && (
        <div className="bg-red-50 border border-red-200 rounded px-5 py-3">
          <p className="text-[13px] text-red-700">{error}</p>
        </div>
      )}

      {/* Loading state while streaming */}
      {streaming && !done && (
        <div className="bg-white border border-slate-200 rounded p-8">
          <p className="text-[13px] text-slate-400 animate-pulse">Tailoring your resume...</p>
        </div>
      )}

      {/* Section tab bar */}
      {done && parsed && (
        <div className="flex gap-2 flex-wrap">
          {SECTION_TABS.map(tab => (
            <button
              key={tab.id}
              type="button"
              onClick={() => setActiveSection(tab.id)}
              className={`text-[12px] font-semibold px-3 py-1.5 rounded transition-colors cursor-pointer border ${
                activeSection === tab.id
                  ? 'bg-slate-900 text-white border-slate-900'
                  : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      )}

      {/* Parsed output */}
      {done && parsed && (
        <>
          {/* Tailored resume */}
          {parsed.tailored && show('resume') && (
            <div className="bg-white border border-slate-200 rounded overflow-hidden">
              <div className="px-6 py-[18px] border-b border-slate-200 flex items-center justify-between gap-4">
                <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Tailored Resume</span>
                <div className="flex items-center gap-3">
                  <button
                    type="button"
                    onClick={handleCopy}
                    className="text-[12px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 transition-colors cursor-pointer bg-transparent"
                  >
                    {copied ? 'Copied!' : 'Copy text'}
                  </button>
                  <button
                    type="button"
                    onClick={() => downloadDocx(parsed.tailored, companyName)}
                    className="text-[12px] font-semibold text-white bg-slate-900 hover:bg-slate-700 rounded px-3 py-1.5 transition-colors cursor-pointer border-0"
                  >
                    Download .docx
                  </button>
                </div>
              </div>
              <div className="px-6 py-6">
                <pre className="text-[13px] text-slate-800 leading-relaxed whitespace-pre-wrap font-sans">{parsed.tailored}</pre>
              </div>
            </div>
          )}

          {/* Strengthened resume (shown in resume tab too) */}
          {(strengthenDone || strengthening) && show('resume') && !(activeSection === 'quality') && (
            <div className="bg-white border border-emerald-200 rounded overflow-hidden">
              <div className="px-6 py-[18px] border-b border-emerald-200 flex items-center justify-between gap-4">
                <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-emerald-600">Strengthened Resume</span>
                {strengthenDone && (
                  <div className="flex items-center gap-3">
                    <button
                      type="button"
                      onClick={handleStrengthenCopy}
                      className="text-[12px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 transition-colors cursor-pointer bg-transparent"
                    >
                      {strengthenCopied ? 'Copied!' : 'Copy text'}
                    </button>
                    <button
                      type="button"
                      onClick={() => downloadDocx(strengthenedResume, companyName, 'Strengthened')}
                      className="text-[12px] font-semibold text-white bg-slate-900 hover:bg-slate-700 rounded px-3 py-1.5 transition-colors cursor-pointer border-0"
                    >
                      Download .docx
                    </button>
                  </div>
                )}
              </div>
              <div className="px-6 py-6">
                {strengthening && <p className="text-[13px] text-slate-400 animate-pulse">Strengthening bullets...</p>}
                {strengthenDone && <pre className="text-[13px] text-slate-800 leading-relaxed whitespace-pre-wrap font-sans">{strengthenedResume}</pre>}
              </div>
            </div>
          )}

          {/* Keyword analysis */}
          {parsed.keywords && show('keywords') && (
            <div className="bg-white border border-slate-200 rounded overflow-hidden">
              <div className="px-6 py-[18px] border-b border-slate-200">
                <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Keyword Analysis</span>
              </div>
              <div className="px-6 py-5">
                {parsed.keywords.split('\n').filter(Boolean).map((line, i) => {
                  const isPresent = line.toLowerCase().startsWith('present:')
                  const isMissing = line.toLowerCase().startsWith('missing:')
                  const label = isPresent ? 'Present' : isMissing ? 'Missing' : null
                  const content = line.replace(/^(present|missing):\s*/i, '').trim()
                  if (!label) return <p key={i} className="text-[13px] text-slate-600 leading-relaxed">{line}</p>
                  return (
                    <div key={i} className="flex items-start gap-3 mb-3 last:mb-0">
                      <span className={`text-[11px] font-bold tracking-[0.06em] uppercase px-2 py-0.5 rounded shrink-0 mt-0.5 ${isPresent ? 'bg-green-50 text-green-700' : 'bg-amber-50 text-amber-700'}`}>
                        {label}
                      </span>
                      <p className="text-[13px] text-slate-700 leading-relaxed">{content}</p>
                    </div>
                  )
                })}
              </div>
            </div>
          )}

          {/* Key changes */}
          {parsed.changes && show('changes') && (
            <div className="bg-white border border-slate-200 rounded overflow-hidden">
              <div className="px-6 py-[18px] border-b border-slate-200">
                <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Key Changes</span>
              </div>
              <div className="px-6 py-5">
                <BulletList text={parsed.changes} />
              </div>
            </div>
          )}

          {/* Quality check section - all quality-related cards */}
          {show('quality') && (
            <>
              {/* Quality check trigger */}
              {!checkDone && !checkStreaming && (
                <div className="bg-slate-50 border border-slate-200 rounded p-6 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                  <div>
                    <p className="text-[14px] font-semibold text-slate-900 mb-1">Run quality check</p>
                    <p className="text-[13px] text-slate-500 leading-relaxed">
                      Score this resume from three angles: ATS match, recruiter first impression, and hiring manager fit. Flags weak bullets and gaps to cover verbally.
                    </p>
                  </div>
                  <button
                    type="button"
                    onClick={handleQualityCheck}
                    className="shrink-0 text-[13px] font-semibold text-white bg-slate-900 hover:bg-slate-700 px-5 py-2.5 rounded transition-colors cursor-pointer border-0"
                  >
                    Run quality check
                  </button>
                </div>
              )}

              {/* Quality check streaming */}
              {checkStreaming && !checkDone && (
                <div className="bg-white border border-slate-200 rounded overflow-hidden">
                  <div className="px-6 py-[18px] border-b border-slate-200 flex items-center justify-between">
                    <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Quality Check</span>
                    <span className="text-[11px] text-slate-400 animate-pulse">Scoring...</span>
                  </div>
                  <div className="px-6 py-6">
                    <pre className="text-[13px] text-slate-600 leading-relaxed whitespace-pre-wrap font-sans">{checkRaw}</pre>
                  </div>
                </div>
              )}

              {/* Quality check error */}
              {checkError && (
                <div className="bg-red-50 border border-red-200 rounded px-5 py-3">
                  <p className="text-[13px] text-red-700">{checkError}</p>
                </div>
              )}

              {/* Quality check results */}
              {checkDone && quality && (
                <>
                  {/* Score summary row */}
                  <div className="bg-white border border-slate-200 rounded overflow-hidden">
                    <div className="px-6 py-[18px] border-b border-slate-200">
                      <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Quality Check</span>
                    </div>
                    <div className="grid grid-cols-2 sm:grid-cols-4 divide-x divide-y sm:divide-y-0 divide-slate-100">
                      <div className="px-6 py-5 text-center">
                        <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-2">ATS Match</p>
                        <p className={`text-[36px] font-bold leading-none ${atsColor(parseInt(quality.atsScore || '0'))}`}>
                          {quality.atsScore || '?'}
                        </p>
                        <p className="text-[10px] text-slate-400 mt-1">out of 100</p>
                      </div>
                      <div className="px-6 py-5 text-center">
                        <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-2">Recruiter</p>
                        {quality.recruiterGrade && (
                          <span className={`inline-block text-[28px] font-bold leading-none px-3 py-1 rounded border ${gradeColor(quality.recruiterGrade)}`}>
                            {quality.recruiterGrade}
                          </span>
                        )}
                      </div>
                      <div className="px-6 py-5 text-center">
                        <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-2">Hiring Mgr</p>
                        {quality.hiringManagerGrade && (
                          <span className={`inline-block text-[28px] font-bold leading-none px-3 py-1 rounded border ${gradeColor(quality.hiringManagerGrade)}`}>
                            {quality.hiringManagerGrade}
                          </span>
                        )}
                      </div>
                      <div className="px-6 py-5 text-center">
                        <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-2">6-Second Test</p>
                        {quality.sixSecondGrade && (
                          <span className={`inline-block text-[28px] font-bold leading-none px-3 py-1 rounded border ${gradeColor(quality.sixSecondGrade)}`}>
                            {quality.sixSecondGrade}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>

                  {/* ATS detail */}
                  {quality.atsNotes && (
                    <div className="bg-white border border-slate-200 rounded overflow-hidden">
                      <div className="px-6 py-[18px] border-b border-slate-200">
                        <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">ATS Keywords</span>
                      </div>
                      <div className="px-6 py-5">
                        {quality.atsNotes.split('\n').filter(Boolean).map((line, i) => {
                          const isPresent = line.toLowerCase().startsWith('present:')
                          const isMissing = line.toLowerCase().startsWith('missing:')
                          const label = isPresent ? 'Present' : isMissing ? 'Missing' : null
                          const content = line.replace(/^(present|missing):\s*/i, '').trim()
                          if (!label) return <p key={i} className="text-[13px] text-slate-600">{line}</p>
                          return (
                            <div key={i} className="flex items-start gap-3 mb-3 last:mb-0">
                              <span className={`text-[11px] font-bold tracking-[0.06em] uppercase px-2 py-0.5 rounded shrink-0 mt-0.5 ${isPresent ? 'bg-green-50 text-green-700' : 'bg-amber-50 text-amber-700'}`}>
                                {label}
                              </span>
                              <p className="text-[13px] text-slate-700 leading-relaxed">{content}</p>
                            </div>
                          )
                        })}
                      </div>
                    </div>
                  )}

                  {/* Recruiter + HM notes side by side */}
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    {quality.recruiterNotes && (
                      <div className="bg-white border border-slate-200 rounded overflow-hidden">
                        <div className="px-6 py-[18px] border-b border-slate-200 flex items-center gap-3">
                          <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Recruiter View</span>
                          {quality.recruiterGrade && (
                            <span className={`text-[11px] font-bold px-1.5 py-0.5 rounded border ${gradeColor(quality.recruiterGrade)}`}>
                              {quality.recruiterGrade}
                            </span>
                          )}
                        </div>
                        <div className="px-6 py-5">
                          <BulletList text={quality.recruiterNotes} />
                        </div>
                      </div>
                    )}
                    {quality.hiringManagerNotes && (
                      <div className="bg-white border border-slate-200 rounded overflow-hidden">
                        <div className="px-6 py-[18px] border-b border-slate-200 flex items-center gap-3">
                          <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Hiring Manager View</span>
                          {quality.hiringManagerGrade && (
                            <span className={`text-[11px] font-bold px-1.5 py-0.5 rounded border ${gradeColor(quality.hiringManagerGrade)}`}>
                              {quality.hiringManagerGrade}
                            </span>
                          )}
                        </div>
                        <div className="px-6 py-5">
                          <BulletList text={quality.hiringManagerNotes} />
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Weak bullets */}
                  {quality.weakBullets && quality.weakBullets.trim().length > 10 && (
                    <div className="bg-white border border-slate-200 rounded overflow-hidden">
                      <div className="px-6 py-[18px] border-b border-slate-200 flex items-center justify-between gap-4">
                        <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">Bullets to Strengthen</span>
                        {!strengthenDone && (
                          <button
                            type="button"
                            onClick={handleStrengthen}
                            disabled={strengthening}
                            className="text-[12px] font-semibold text-white bg-slate-900 hover:bg-slate-700 px-3 py-1.5 rounded transition-colors cursor-pointer border-0 disabled:opacity-40"
                          >
                            {strengthening ? 'Rewriting...' : 'Strengthen resume'}
                          </button>
                        )}
                        {strengthenDone && (
                          <span className="text-[11px] font-semibold text-emerald-600">Resume strengthened</span>
                        )}
                      </div>
                      <div className="px-6 py-5 flex flex-col gap-4">
                        {quality.weakBullets.split(/\n\s*\n/).filter(b => b.trim()).map((block, i) => {
                          const bulletLine = block.match(/BULLET:\s*(.+)/i)?.[1]?.trim()
                          const fixLine    = block.match(/FIX:\s*(.+)/i)?.[1]?.trim()
                          if (!bulletLine && !fixLine) return null
                          return (
                            <div key={i} className="border border-slate-100 rounded p-4">
                              {bulletLine && (
                                <p className="text-[13px] text-slate-500 italic mb-2">&ldquo;{bulletLine}...&rdquo;</p>
                              )}
                              {fixLine && (
                                <p className="text-[13px] text-slate-900 leading-relaxed">{fixLine}</p>
                              )}
                            </div>
                          )
                        })}
                      </div>
                    </div>
                  )}

                  {/* Strengthen error */}
                  {strengthenError && (
                    <div className="bg-red-50 border border-red-200 rounded px-5 py-3">
                      <p className="text-[13px] text-red-700">{strengthenError}</p>
                    </div>
                  )}

                  {/* Strengthened resume (shown in quality tab) */}
                  {(strengthenDone || strengthening) && (
                    <div className="bg-white border border-emerald-200 rounded overflow-hidden">
                      <div className="px-6 py-[18px] border-b border-emerald-200 flex items-center justify-between gap-4">
                        <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-emerald-600">Strengthened Resume</span>
                        {strengthenDone && (
                          <div className="flex items-center gap-3">
                            <button
                              type="button"
                              onClick={handleStrengthenCopy}
                              className="text-[12px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 transition-colors cursor-pointer bg-transparent"
                            >
                              {strengthenCopied ? 'Copied!' : 'Copy text'}
                            </button>
                            <button
                              type="button"
                              onClick={() => downloadDocx(strengthenedResume, companyName, 'Strengthened')}
                              className="text-[12px] font-semibold text-white bg-slate-900 hover:bg-slate-700 rounded px-3 py-1.5 transition-colors cursor-pointer border-0"
                            >
                              Download .docx
                            </button>
                          </div>
                        )}
                      </div>
                      <div className="px-6 py-6">
                        {strengthening && <p className="text-[13px] text-slate-400 animate-pulse">Rewriting weak bullets...</p>}
                        {strengthenDone && <pre className="text-[13px] text-slate-800 leading-relaxed whitespace-pre-wrap font-sans">{strengthenedResume}</pre>}
                      </div>
                    </div>
                  )}

                  {/* Verbal cover */}
                  {quality.verbalCover && (
                    <div className="bg-amber-50 border border-amber-200 rounded overflow-hidden">
                      <div className="px-6 py-[18px] border-b border-amber-200">
                        <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-amber-700">Cover Verbally in the Room</span>
                      </div>
                      <div className="px-6 py-5">
                        <p className="text-[12px] text-amber-700 mb-3">These gaps cannot be fixed on paper. Address them proactively in the interview.</p>
                        <BulletList text={quality.verbalCover} />
                      </div>
                    </div>
                  )}

                  {/* 6-second test */}
                  {quality.sixSecondNotes && (
                    <div className="bg-white border border-slate-200 rounded overflow-hidden">
                      <div className="px-6 py-[18px] border-b border-slate-200 flex items-center gap-3">
                        <span className="text-[10px] font-bold tracking-[0.14em] uppercase text-slate-400">6-Second Recruiter Test</span>
                        {quality.sixSecondGrade && (
                          <span className={`text-[11px] font-bold px-1.5 py-0.5 rounded border ${gradeColor(quality.sixSecondGrade)}`}>
                            {quality.sixSecondGrade}
                          </span>
                        )}
                      </div>
                      <div className="px-6 py-5">
                        <p className="text-[13px] text-slate-700 leading-relaxed">{quality.sixSecondNotes}</p>
                      </div>
                    </div>
                  )}

                  {/* Re-run / retailor */}
                  <div className="flex items-center justify-between">
                    <button
                      type="button"
                      onClick={() => { setCheckDone(false); setCheckRaw('') }}
                      className="text-[12px] text-slate-400 hover:text-slate-700 transition-colors cursor-pointer bg-transparent border-0"
                    >
                      Re-run quality check
                    </button>
                    <button
                      type="button"
                      onClick={() => {
                        setDone(false)
                        setOutput('')
                        setCheckDone(false)
                        setCheckRaw('')
                        setStrengthenDone(false)
                        setStrengthenRaw('')
                        setActiveSection('all')
                      }}
                      className="text-[12px] text-slate-400 hover:text-slate-700 transition-colors cursor-pointer bg-transparent border-0"
                    >
                      Update JD and retailor
                    </button>
                  </div>
                </>
              )}
            </>
          )}

          {/* Retailor (shown in non-quality sections when check not yet run) */}
          {!checkDone && show('resume') && activeSection !== 'quality' && (
            <div className="flex justify-center">
              <button
                type="button"
                onClick={() => {
                  setDone(false)
                  setOutput('')
                  setStrengthenDone(false)
                  setStrengthenRaw('')
                  setActiveSection('all')
                }}
                className="text-[12px] text-slate-400 hover:text-slate-700 transition-colors cursor-pointer bg-transparent border-0"
              >
                Update job description and retailor
              </button>
            </div>
          )}
        </>
      )}
    </div>
  )
}

/**
 * Production Synthetic Tests (R2.1 + R2.2)
 *
 * Implements Synthetic-01 through Synthetic-09 from:
 *   docs/sre/synthetic-tests-and-deploy-gates.md
 *
 * These tests are designed to run against the live production environment
 * using a dedicated synthetic test account. They validate the full P0
 * request path — not just page rendering.
 *
 * Synthetic account requirements:
 *   PLAYWRIGHT_TEST_EMAIL     — active account with completed onboarding
 *   PLAYWRIGHT_TEST_PASSWORD  — password for the account
 *   PLAYWRIGHT_SYNTH_PAID_EMAIL / PLAYWRIGHT_SYNTH_PAID_PASSWORD (optional)
 *     — paid-seat account for Synthetic-07 (billing portal)
 *
 * Budget (per spec):
 *   Synthetic-01: <= 3000ms
 *   Synthetic-02: <= 2000ms
 *   Synthetic-03: <= 4000ms
 *   Synthetic-04: <= 2000ms
 *   Synthetic-05: <= 6000ms first-byte
 *   Synthetic-06: <= 10000ms
 *   Synthetic-07: <= 3000ms
 *   Synthetic-08: <= 2000ms
 *   Synthetic-09: <= 5000ms per route
 */

import { test, expect, type APIRequestContext, type Page } from '@playwright/test'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

async function hasAuthSession(page: Page): Promise<boolean> {
  await page.goto('/dashboard')
  return !/\/login(?:$|[/?#])/.test(page.url())
}

async function trySignIn(page: Page): Promise<boolean> {
  const email = process.env.PLAYWRIGHT_TEST_EMAIL
  const password = process.env.PLAYWRIGHT_TEST_PASSWORD
  if (!email || !password) return false

  await page.goto('/login', { waitUntil: 'load' })
  await page.locator('#email').fill(email)
  await page.locator('#password').fill(password)
  await page.getByRole('button', { name: /^Sign in$/i }).click()

  await page
    .waitForURL(url => !/\/login(?:$|[/?#])/.test(url.pathname), { timeout: 10000 })
    .catch(() => null)

  return hasAuthSession(page)
}

async function requireAuthSessionOrSkip(page: Page) {
  const authenticated = (await hasAuthSession(page)) || (await trySignIn(page))
  test.skip(
    !authenticated,
    'Skipping synthetic: auth session unavailable (dashboard redirected to login). Check PLAYWRIGHT_TEST_EMAIL / PLAYWRIGHT_TEST_PASSWORD.'
  )
}

async function skipIfApiAuthUnavailable(request: APIRequestContext, baseURL: string) {
  const healthRes = await request.get(`${baseURL}/api/health`, { failOnStatusCode: false })
  test.skip(healthRes.status() !== 200, `Skipping synthetic: health check returned ${healthRes.status()}`)
}

