              <input
                value={tailoredRole}
                onChange={(e) => setTailoredRole(e.target.value)}
                className="w-full border border-slate-200 rounded px-3 py-2.5 text-[14px] text-slate-900"
                placeholder="Enterprise CIO (Next Role)"
                required
